import React, { useState, useEffect, useRef, useCallback } from 'react';
import InputBox from '../UIComponents/InputBox';
import { icons } from '../../Constants/svg';
import { postWindowMessage } from '../../utils/messageSender';
import './CustomerInfo.css';

const Field = ({ label, children, full = false }) => (
    <label className={`cq-customer-field ${full ? 'cq-field-full' : ''}`}>
        <span className="cq-customer-label">{label}</span>
        {children}
    </label>
);

const CompanyField = ({ value, onChange, disabled }) => {
    const [companies, setCompanies] = useState([]);
    const [companiesLoading, setCompaniesLoading] = useState(false);
    const [showCompanyDropdown, setShowCompanyDropdown] = useState(false);
    const [companiesPage, setCompaniesPage] = useState(1);
    const [hasMoreCompanies, setHasMoreCompanies] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [searchTimeout, setSearchTimeout] = useState(null);

    // Internal form state for Create/Edit
    const [showCompanyForm, setShowCompanyForm] = useState(false);
    const [companyForm, setCompanyForm] = useState({
        name: '',
        domain: '',
        industry: ''
    });
    const [isEditing, setIsEditing] = useState(false);
    const [companySaving, setCompanySaving] = useState(false);
    const [companyError, setCompanyError] = useState('');
    const lastCompanyDraft = useRef(null);

    // When value changes externally (e.g. initial load), ensure internal state matches if needed
    // However, `value` here is the *selected* company object or name.
    // We mainly use it to know if we are in "Selected" state.

    const fetchCompanies = (query = '', page = 1) => {
        setCompaniesLoading(true);
        setCompaniesPage(page);
        postWindowMessage('COMPANIES_GET', {
            name: query,
            page,
            page_size: 10
        });
    };

    const handleCompanySearch = (e) => {
        const query = e.target.value;
        setSearchQuery(query);

        // If user clears input, notify parent (clearing selection)
        if (!query && value) {
            onChange(null);
        }

        if (searchTimeout) clearTimeout(searchTimeout);

        const newTimeout = setTimeout(() => {
            fetchCompanies(query, 1);
        }, 300);

        setSearchTimeout(newTimeout);
        setShowCompanyDropdown(true);
    };

    const handleCompanyInputFocus = () => {
        if (!showCompanyDropdown && companies.length === 0) {
            fetchCompanies('', 1);
        }
        setShowCompanyDropdown(true);
    };

    const handleCompanySelect = (company) => {
        onChange(company);
        setSearchQuery('');
        setShowCompanyDropdown(false);
    };

    const loadMoreCompanies = () => {
        if (!companiesLoading && hasMoreCompanies) {
            fetchCompanies(searchQuery, companiesPage + 1);
        }
    };

    // --- Message Handling ---
    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;
            const { actionType, data } = payload || {};

            if (type === 'COMPANIES_UPDATE') {
                if (actionType === 'COMPANIES_RETRIEVED' && data) {
                    const { results, next } = data;
                    if (companiesPage === 1) {
                        setCompanies(results || []);
                    } else {
                        setCompanies(prev => [...prev, ...(results || [])]);
                    }
                    setHasMoreCompanies(!!next);
                    setCompaniesLoading(false);
                } else if ((actionType === 'COMPANY_CREATED' || actionType === 'COMPANY_UPDATED') && data) {
                    // Success
                    const draft = lastCompanyDraft.current || {};
                    const updatedCompany = { id: data.company_id, ...draft };

                    // Update selected value
                    onChange(updatedCompany);

                    // Reset UI
                    setCompanySaving(false);
                    setShowCompanyForm(false);
                    setCompanyError('');
                    lastCompanyDraft.current = null;
                    setIsEditing(false);

                } else if (actionType === 'COMPANY_ERROR' && data) {
                    setCompanySaving(false);
                    setCompanyError(data.error || 'Failed to save company');
                }
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [companiesPage, onChange]);

    // --- Create/Edit/Delete Logic ---

    const startCreate = () => {
        setCompanyForm({ name: searchQuery, domain: '', industry: '' });
        setIsEditing(false);
        setShowCompanyForm(true);
        setShowCompanyDropdown(false);
    };

    const startEdit = () => {
        if (!value) return;
        setCompanyForm({
            name: value.name || '',
            domain: value.domain || '',
            industry: value.industry || ''
        });
        setIsEditing(true);
        setShowCompanyForm(true);
    };

    const handleSaveCompany = () => {
        const name = companyForm.name.trim();
        if (!name) return;

        setCompanySaving(true);
        setCompanyError('');
        lastCompanyDraft.current = { ...companyForm, name };

        if (isEditing && value?.id) {
            postWindowMessage('COMPANY_UPDATE', {
                company_id: value.id,
                ...companyForm,
                name
            });
        } else {
            postWindowMessage('COMPANY_CREATE', {
                ...companyForm,
                name
            });
        }
    };

    const handleCancelForm = () => {
        setShowCompanyForm(false);
        setCompanyError('');
        setCompanySaving(false);
    };

    const handleRemove = () => {
        onChange(null);
        setShowCompanyForm(false);
    };

    // Close dropdown on outside click
    const containerRef = useRef(null);
    useEffect(() => {
        const handleClickOutside = (e) => {
            if (containerRef.current && !containerRef.current.contains(e.target)) {
                setShowCompanyDropdown(false);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, []);

    return (
        <div className="company-search-container" ref={containerRef} style={{ position: 'relative' }}>

            {/* Search Input or Display */}
            <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <div style={{ flex: 1 }}>
                    <InputBox
                        placeholder="Type to search companies..."
                        value={value ? value.name : searchQuery}
                        onChange={value ? undefined : handleCompanySearch}
                        onFocus={value ? undefined : handleCompanyInputFocus}
                        disabled={disabled || !!value}
                    />
                </div>

                {value && (
                    <>
                        <button type="button" className="cq-icon-btn" onClick={startEdit} title="Edit company">
                            {icons.EDIT}
                        </button>
                        <button type="button" className="cq-icon-btn cq-icon-btn--danger" onClick={handleRemove} title="Remove company">
                            {icons.CROSS_CIRCLED}
                        </button>
                    </>
                )}
            </div>

            {/* Dropdown */}
            {showCompanyDropdown && !value && (
                <div className="cq-company-dropdown">
                    {companiesLoading && companiesPage === 1 && (
                        <div className="cq-company-dropdown-loading">Loading...</div>
                    )}

                    {companies.length > 0 && companies.map((c, i) => (
                        <div key={i} className="cq-company-dropdown-item" onClick={() => handleCompanySelect(c)}>
                            {c.name}
                        </div>
                    ))}

                    {hasMoreCompanies && (
                        <div onClick={loadMoreCompanies} className="cq-company-dropdown-item cq-company-dropdown-load-more">
                            {companiesLoading ? 'Loading...' : 'Load more'}
                        </div>
                    )}

                    {!companiesLoading && searchQuery && (
                        <div
                            onClick={startCreate}
                            className="cq-company-dropdown-item"
                            style={{ color: 'var(--color-accent-solid)', fontWeight: 500 }}
                        >
                            Create company "{searchQuery}"
                        </div>
                    )}

                    {(!companiesLoading && !searchQuery && companies.length === 0) && (
                        <div className="cq-company-dropdown-loading">
                            No companies available
                        </div>
                    )}
                </div>
            )}

            {/* Create/Edit Form */}
            {showCompanyForm && (
                <div className="cq-company-card" style={{ marginTop: '12px' }}>
                    <div className="cq-company-heading">{isEditing ? 'Update Company' : 'Create Company'}</div>

                    <div className="cq-grid-responsive">
                        <Field label={<>Name<span style={{ color: '#ef4444' }}> *</span></>} full>
                            <InputBox
                                value={companyForm.name}
                                onChange={(e) => setCompanyForm(p => ({ ...p, name: e.target.value }))}
                            />
                            {companyError && <div className="cq-error-text">{companyError}</div>}
                        </Field>
                        <Field label="Domain" full>
                            <InputBox
                                value={companyForm.domain}
                                onChange={(e) => setCompanyForm(p => ({ ...p, domain: e.target.value }))}
                            />
                        </Field>
                        <Field label="Industry" full>
                            <InputBox
                                value={companyForm.industry}
                                onChange={(e) => setCompanyForm(p => ({ ...p, industry: e.target.value }))}
                            />
                        </Field>
                    </div>

                    <div style={{ marginTop: '12px', display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
                        <button
                            type="button"
                            onClick={handleSaveCompany}
                            disabled={companySaving || !companyForm.name.trim()}
                            style={{
                                padding: '6px 16px',
                                fontSize: '14px',
                                backgroundColor: companySaving ? '#9ca3af' : ((companyForm.name && companyForm.name.trim()) ? '#10b981' : '#9ca3af'),
                                color: 'white',
                                border: 'none',
                                borderRadius: '4px',
                                cursor: companySaving ? 'not-allowed' : ((companyForm.name && companyForm.name.trim()) ? 'pointer' : 'not-allowed')
                            }}
                        >
                            {companySaving ? 'Saving...' : (isEditing ? 'Update' : 'Create')}
                        </button>
                        <button
                            type="button"
                            onClick={handleCancelForm}
                            className="cq-btn-secondary"
                            style={{ padding: '6px 16px', fontSize: '14px' }}
                        >
                            Cancel
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CompanyField;
