import React, { useState, useEffect, useRef } from 'react';
import ArtifactIconCard from '../../UIComponents/ArtifactIconCard';
import ClickToEditInput from '../../UIComponents/ClickToEditInput';
import { icons } from '../../../Constants/svg';
import { useToast } from '../../UIComponents/Toast/ToastManager';
import { searchWPPContacts } from '../../../utils/WppFunctions';
import './LeadPeople.css';



import { postWindowMessage } from '../../../utils/messageSender';

import ConfirmationModal from '../../UIComponents/ConfirmationModal';

const LeadPeople = ({ leadId }) => {
    const [contacts, setContacts] = useState([]);
    const { addToast } = useToast();

    // Search State
    const [searchQuery, setSearchQuery] = useState('');
    const [suggestions, setSuggestions] = useState([]);
    const [showSuggestions, setShowSuggestions] = useState(false);
    const wrapperRef = useRef(null);

    // Delete Confirmation State
    const [deleteModalOpen, setDeleteModalOpen] = useState(false);
    const [contactToDelete, setContactToDelete] = useState(null);

    const fetchContacts = () => {
        postWindowMessage('LEAD_LINKED_ENTITIES_LIST', { leadId, page: 1 });
    };

    useEffect(() => {
        if (leadId) {
            fetchContacts();
        }
    }, [leadId]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'LEAD_LINKED_ENTITIES_LIST_SUCCESS') {
                const results = payload.results || [];
                const mappedContacts = results.map(item => ({
                    linkId: item.id || item.link_id || item.pk || item.entity_id,
                    id: item.customer.chat_id || item.customer.id,
                    name: (item.customer.first_name || '') + ' ' + (item.customer.last_name || ''),
                    phone: item.customer.phone || item.customer.email,
                    relationship: item.short_info || '',
                    isPrimary: item.is_primary,
                    isIndividual: true,
                    isGroup: false
                }));
                setContacts(mappedContacts);
            } else if (type === 'LEAD_LINKED_ENTITIES_LIST_ERROR') {
                console.error('Error fetching linked entities:', payload.error);
                addToast({ message: 'Failed to fetch stakeholders', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_LINKED_ENTITIES_CREATE_SUCCESS') {
                addToast({ message: 'Stakeholder added', type: 'success', duration: 3000 });
                fetchContacts();
            } else if (type === 'LEAD_LINKED_ENTITIES_CREATE_ERROR') {
                console.error('Error creating linked entity:', payload.error);
                addToast({ message: 'Failed to add stakeholder', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_LINKED_ENTITIES_DELETE_SUCCESS') {
                addToast({ message: 'Stakeholder removed', type: 'success', duration: 3000 });
                fetchContacts();
            } else if (type === 'LEAD_LINKED_ENTITIES_DELETE_ERROR') {
                console.error('Error deleting linked entity:', payload.error);
                addToast({ message: 'Failed to remove stakeholder', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_LINKED_ENTITIES_UPDATE_SUCCESS') {
                addToast({ message: 'Stakeholder updated', type: 'success', duration: 3000 });
                fetchContacts();
            } else if (type === 'LEAD_LINKED_ENTITIES_UPDATE_ERROR') {
                console.error('Error updating linked entity:', payload.error);
                addToast({ message: 'Failed to update stakeholder', type: 'error', duration: 3000 });
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [addToast]);

    const handleSearchChange = async (e) => {
        const val = e.target.value;
        setSearchQuery(val);

        if (val.length > 1) {
            const results = await searchWPPContacts(val);
            setSuggestions(results);
            setShowSuggestions(true);
        } else {
            setSuggestions([]);
            setShowSuggestions(false);
        }
    };

    const handleSelectSuggestion = (suggestion) => {
        // Prevent adding duplicates by ID
        if (contacts.find(c => c.id === suggestion.id)) {
            addToast({ message: 'Contact already added', type: 'info', duration: 3000 });
            setSearchQuery('');
            setShowSuggestions(false);
            return;
        }

        // Split name for API payload
        const nameParts = (suggestion.name || '').split(' ');
        const firstName = nameParts[0] || '';
        const lastName = nameParts.slice(1).join(' ') || '';

        const payload = {
            lead_id: leadId,
            customer: {
                chat_id: suggestion.id,
                chat_lid: suggestion.lid || '',
                first_name: firstName,
                last_name: lastName,
                phone: suggestion.number
            },
            is_primary: false
        };

        postWindowMessage('LEAD_LINKED_ENTITIES_CREATE', payload);

        setSearchQuery('');
        setSuggestions([]);
        setShowSuggestions(false);
    };

    const handleRelationshipSave = (contactId, newRelationship) => {
        const contact = contacts.find(c => c.id === contactId);
        if (!contact) return;

        postWindowMessage('LEAD_LINKED_ENTITIES_UPDATE', {
            leadId,
            entityId: contact.id,
            data: { short_info: newRelationship }
        });

        setContacts(prev => prev.map(c =>
            c.id === contactId ? { ...c, relationship: newRelationship } : c
        ));
    };

    const handleMakePrimary = (contactId) => {
        const contact = contacts.find(c => c.id === contactId);
        if (!contact) return;

        postWindowMessage('LEAD_LINKED_ENTITIES_UPDATE', {
            leadId,
            entityId: contact.id,
            data: { is_primary: true }
        });

        setContacts(prev => prev.map(c => ({
            ...c,
            isPrimary: c.id === contactId
        })));
    };

    const handleDeleteContact = (contactId) => {
        const contact = contacts.find(c => c.id === contactId);
        if (!contact) return;

        setContactToDelete(contact);
        setDeleteModalOpen(true);
    };

    const confirmDeleteContact = () => {
        if (!contactToDelete || !contactToDelete.id) {
            setDeleteModalOpen(false);
            setContactToDelete(null);
            return;
        }

        postWindowMessage('LEAD_LINKED_ENTITIES_DELETE', {
            leadId,
            entityId: contactToDelete.id
        });

        setDeleteModalOpen(false);
        setContactToDelete(null);
    };

    return (
        <div className="cq-lead-people">
            <div className="cq-people-action-section" ref={wrapperRef} style={{ position: 'relative' }}>
                <div className="cq-search-input-wrapper">
                    <input
                        type="text"
                        placeholder="Search WhatsApp contacts..."
                        className="cq-people-search-input"
                        value={searchQuery}
                        onChange={handleSearchChange}
                        onFocus={() => searchQuery.length > 1 && setShowSuggestions(true)}
                    />
                </div>

                {/* Suggestions Dropdown */}
                {showSuggestions && suggestions.length > 0 && (
                    <div className="cq-suggestions-dropdown">
                        {suggestions.map((suggestion) => (
                            <div
                                key={suggestion.id}
                                className="cq-suggestion-item"
                                onClick={() => handleSelectSuggestion(suggestion)}
                            >
                                <div className="cq-suggestion-name">{suggestion.name}</div>
                                <div className="cq-suggestion-meta">
                                    <span className="cq-suggestion-type">
                                        {suggestion.isGroup ? 'Group' : 'User'}
                                    </span>
                                    {!suggestion.isGroup && (
                                        <span className="cq-suggestion-number">
                                            {suggestion.number}
                                        </span>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
                {showSuggestions && suggestions.length === 0 && searchQuery.length > 1 && (
                    <div className="cq-suggestions-dropdown">
                        <div className="cq-suggestion-item" style={{ cursor: 'default', color: 'var(--text-secondary)' }}>
                            No contacts found
                        </div>
                    </div>
                )}
            </div>

            <div className="cq-contacts-list">
                <div className="cq-section-header">Stakeholders ({contacts.length})</div>

                {contacts.length === 0 && (
                    <div className="cq-no-contacts">No stakeholders added yet.</div>
                )}

                {contacts.map((contact, index) => (
                    <div key={contact.id} className="cq-contact-item-wrapper">
                        <ArtifactIconCard
                            index={index}
                            title={
                                <div className="cq-contact-title-row">
                                    <span className="cq-contact-name">{contact.name}</span>
                                    {contact.isPrimary && (
                                        <span className="cq-primary-badge">Primary</span>
                                    )}
                                </div>
                            }
                            style={{ padding: '8px 12px', marginBottom: '8px' }}
                            descriptionNode={
                                <div className="cq-contact-details">
                                    {!contact.isGroup && contact.phone && (
                                        <div className="cq-contact-phone">
                                            <span className="cq-phone-icon">{icons.PHONE}</span>
                                            {contact.phone}
                                        </div>
                                    )}
                                    {contact.isGroup && (
                                        <div className="cq-contact-phone">
                                            <span className="cq-phone-icon">{icons.PROFILE}</span>
                                            Group Chat
                                        </div>
                                    )}
                                </div>
                            }
                            actions={[
                                contact.isIndividual ? {
                                    icon: icons.CHECK,
                                    tooltip: 'Make it primary',
                                    onClick: () => handleMakePrimary(contact.id),
                                    disabled: false,
                                } : null,
                                !contact.isPrimary ? {
                                    icon: icons.DELETE,
                                    tooltip: 'Remove contact',
                                    onClick: () => handleDeleteContact(contact.id),
                                } : null
                            ].filter(Boolean).map(action => {
                                if (action.tooltip === 'Make it primary') {
                                    return {
                                        ...action,
                                        icon: (
                                            <span style={{
                                                color: contact.isPrimary ? '#2563eb' : 'var(--text-secondary, #9ca3af)',
                                                display: 'flex',
                                                opacity: contact.isPrimary ? 1 : 0.6
                                            }}>
                                                {icons.CHECK}
                                            </span>
                                        )
                                    };
                                }
                                return action;
                            })}
                        >
                            <div className="cq-contact-relationship-row">
                                <span className="cq-relationship-label">Role:</span>
                                <ClickToEditInput
                                    value={contact.relationship}
                                    onSave={(val) => handleRelationshipSave(contact.id, val)}
                                    placeholder="Add role"
                                    className="cq-relationship-input"
                                    textStyle={{ fontSize: '13px' }}
                                />
                            </div>
                        </ArtifactIconCard>
                    </div>
                ))}
            </div>

            <ConfirmationModal
                isOpen={deleteModalOpen}
                onClose={() => {
                    setDeleteModalOpen(false);
                    setContactToDelete(null);
                }}
                onConfirm={confirmDeleteContact}
                title="Remove Stakeholder?"
                message={`Are you sure you want to remove ${contactToDelete?.name || 'this contact'} from this lead?`}
                confirmLabel="Remove"
                cancelLabel="Cancel"
                confirmButtonStyle="danger"
            />
        </div>
    );
};

export default LeadPeople;
