import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import './Dashboard.css';
import '../../UIComponents/Icon.css';

const TooltipWrapper = ({ children, content }) => {
    const [hover, setHover] = useState(false);
    const [coords, setCoords] = useState({ top: 0, left: 0 });

    const handleMouseEnter = (e) => {
        const rect = e.currentTarget.getBoundingClientRect();
        setCoords({
            top: rect.top - 10, // 10px above the element
            left: rect.left + rect.width / 2
        });
        setHover(true);
    };

    return (
        <div
            style={{ position: 'relative', display: 'inline-flex' }}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={() => setHover(false)}
        >
            {children}
            {hover && createPortal(
                <div
                    className="cq-icon-tooltip"
                    style={{
                        position: 'fixed',
                        top: coords.top,
                        left: coords.left,
                        transform: 'translate(-50%, -100%)',
                        zIndex: 999999, // Ensure it's on top of everything
                        pointerEvents: 'none', // Allow clicking through if needed, though usually tooltips block nothing
                        whiteSpace: 'nowrap',
                        margin: 0
                    }}
                >
                    {content}
                </div>,
                document.body
            )}
        </div>
    );
};

export default TooltipWrapper;
