import React, { useState, useEffect, useRef } from 'react';
import InputBox from '../UIComponents/InputBox';
import Select from '../UIComponents/Select';
import ContactCard from './ContactCard';
import { postWindowMessage } from '../../utils/messageSender';
import { PRIORITY_OPTIONS, CURRENCY_OPTIONS, DEFAULT_PIPELINE } from '../../Constants/constant';
import { uuidv4, mapPipelineToUI } from '../../utils/utils';
import './LeadCreation.css';

const mapStageToApi = (s) => ({
    stage_type: s.type,
    label: s.name,
    position: s.order,
    meta: {
        color: s.color,
        probability: s.probability
    }
});

const defaultPipelinePayload = (isVirtual = false) => {
    const name = DEFAULT_PIPELINE.name || 'Default Pipeline';
    const tempStages = DEFAULT_PIPELINE.stages.map((s, i) => {
        const stage = mapStageToApi({ ...s, order: i });
        if (isVirtual) {
            return { ...stage, id: `TEMP_STAGE_${i}`, is_temp: true };
        }
        return stage;
    });
    return {
        id: isVirtual ? uuidv4() : undefined,
        name,
        stages: tempStages,
        is_temp: isVirtual
    };
};



const LeadCreation = ({
    onCancel,
    contact,
    onContactUpdate,
    chatId,
    customerId,
    hasLeads,
    forceExpanded,
    isLoadingContact,
    isAnalyzing,
    pipelines: initialPipelines = []
}) => {


    const [pipelines, setPipelines] = useState(initialPipelines);
    const [loadingPipelines, setLoadingPipelines] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [pendingLeadCreation, setPendingLeadCreation] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [isExiting, setIsExiting] = useState(false);

    // Ref to track if we are currently attempting to create the default pipeline due to it missing
    const creatingDefaultPipelineRef = React.useRef(false);

    // Sync local pipelines state with prop if it changes and we're not in the middle of a virtual creation
    useEffect(() => {
        if (initialPipelines.length > 0) {
            setPipelines(initialPipelines);
            setLoadingPipelines(false);
        } else if (!loadingPipelines && pipelines.length === 0 && !creatingDefaultPipelineRef.current) {
            // Generate Virtual Pipeline if none exist and we're not loading or creating
            const virtualPipeline = defaultPipelinePayload(true);

            setPipelines([virtualPipeline]);

            // Auto-select for parent if not already selected
            if (!contact.pipelineId) {
                onContactUpdate({
                    pipelineId: virtualPipeline.id,
                    stageId: virtualPipeline.stages[0].id
                });
            }
        }
    }, [initialPipelines, pipelines.length, loadingPipelines]);

    useEffect(() => {
        if (isAnalyzing) {
            setShowLoader(true);
            setIsExiting(false);
        } else if (showLoader) {
            // Start exit animation
            setIsExiting(true);
            const timer = setTimeout(() => {
                setShowLoader(false);
                setIsExiting(false);
            }, 300); // Match CSS transition duration
            return () => clearTimeout(timer);
        }
    }, [isAnalyzing, showLoader]);

    // Watch for customerId update to complete pending lead creation
    // Watch for customerId update to complete pending lead creation
    useEffect(() => {
        // Only auto-submit if we are NOT waiting for a pipeline creation
        if (pendingLeadCreation && customerId && !creatingDefaultPipelineRef.current) {
            submitLead(customerId);
            setPendingLeadCreation(false);
        }
    }, [customerId, pendingLeadCreation]);

    // Keep a ref of contact to access latest state in event listeners
    const contactRef = useRef(contact);
    const customerIdRef = useRef(customerId);
    const pendingLeadCreationRef = useRef(pendingLeadCreation);

    useEffect(() => {
        contactRef.current = contact;
    }, [contact]);

    useEffect(() => {
        customerIdRef.current = customerId;
    }, [customerId]);

    useEffect(() => {
        pendingLeadCreationRef.current = pendingLeadCreation;
    }, [pendingLeadCreation]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            // Use ref for latest state
            const currentContact = contactRef.current;
            const currentCustomerId = customerIdRef.current;
            const isPending = pendingLeadCreationRef.current;

            if (type === 'PIPELINES_LIST') {
                const data = payload;
                const pipelineList = Array.isArray(data) ? data : (data.pipelines || data.results || []);
                setPipelines(pipelineList);


                // Check if we were waiting for the pipeline to be created to submit a lead
                // And now it might be available in the list
                if (isPending) {
                    const defaultPipeline = pipelineList.find(p => p.name === 'Default');


                    if (defaultPipeline && defaultPipeline.stages && defaultPipeline.stages.length > 0) {
                        const sortedStages = (defaultPipeline.stages || []).sort((a, b) => a.position - b.position);

                        const tempStageIndex = String(currentContact.stageId).startsWith('TEMP_STAGE_')
                            ? parseInt(currentContact.stageId.replace('TEMP_STAGE_', ''))
                            : 0;

                        const realStageId = sortedStages[tempStageIndex] ? sortedStages[tempStageIndex].id : sortedStages[0].id;
                        const realPipelineId = defaultPipeline.id;

                        // Update contact with REAL IDs
                        onContactUpdate({
                            pipelineId: realPipelineId,
                            stageId: realStageId
                        });


                        if (currentCustomerId) {
                            submitLead(currentCustomerId, {
                                pipelineId: realPipelineId,
                                stageId: realStageId
                            });
                            setPendingLeadCreation(false);
                            creatingDefaultPipelineRef.current = false;
                        } else {
                            // Customer missing, trigger create customer
                            const withPlus = (val) => {
                                if (!val) return val;
                                return String(val).startsWith('+') ? String(val) : `+${val}`;
                            };
                            const companyId = currentContact.company?.id;
                            const custPayload = {
                                chat_id: chatId,
                                first_name: currentContact.firstName,
                                last_name: currentContact.lastName,
                                email: currentContact.email,
                                phone: withPlus(currentContact.phone),
                                source: currentContact.source || '',
                                address: currentContact.address,
                                city: currentContact.city,
                                state: currentContact.state,
                                zip_code: currentContact.zip,
                                country: currentContact.country,
                                ...(companyId ? { company_id: companyId, relationship_type: currentContact.designation } : {})
                            };
                            postWindowMessage('CUSTOMER_CREATE', custPayload);
                            // Keep pendingLeadCreation = true
                        }
                        setLoadingPipelines(false);
                        return; // Done
                    }
                }

                // Auto-select pipeline logic
                const currentPipelineId = currentContact.pipelineId;
                const pipelineExists = pipelineList.find(p => p.id === currentPipelineId);

                if (!currentPipelineId || !pipelineExists) {
                    // 1. Try to find 'Default' or any existing pipeline
                    const existingPipeline = pipelineList.find(p => p.name === 'Default') || pipelineList[0];

                    if (existingPipeline) {
                        setLoadingPipelines(false);
                        // Found logic: Select it and its first stage
                        const sortedStages = (existingPipeline.stages || []).sort((a, b) => a.position - b.position);
                        const firstStageId = sortedStages.length > 0 ? sortedStages[0].id : '';

                        onContactUpdate({
                            pipelineId: existingPipeline.id,
                            stageId: firstStageId
                        });
                    } else if (!creatingDefaultPipelineRef.current) {
                        // Not found logic: Use VIRTUAL pipeline (ONLY if no pipelines exist)
                        // Not found logic: Use VIRTUAL pipeline (ONLY if no pipelines exist)
                        const virtualPipeline = defaultPipelinePayload(true);

                        setPipelines(prev => [...prev, virtualPipeline]);

                        onContactUpdate({
                            pipelineId: virtualPipeline.id,
                            stageId: virtualPipeline.stages[0].id
                        });

                        setLoadingPipelines(false);
                    } else {
                        // Creating (real one triggered by submit), keep loading
                        setLoadingPipelines(true);
                    }
                } else {
                    setLoadingPipelines(false);
                }
            } else if (type === 'PIPELINE_CREATED_SUCCESS') {
                const rawPipeline = payload.data || payload; // Handle nested data

                if (rawPipeline && rawPipeline.id) {
                    const mappedPipeline = mapPipelineToUI(rawPipeline);

                    // Update local state immediately with MAPPED pipeline
                    setPipelines(prev => [...prev.filter(p => !p.is_temp), mappedPipeline]);

                    if (pendingLeadCreationRef.current) {
                        const sortedStages = mappedPipeline.stages;
                        const realPipelineId = mappedPipeline.id;

                        // Calculate real stage based on temp stage index (if applicable)
                        const currentContact = contactRef.current;
                        const tempStageIndex = String(currentContact.stageId).startsWith('TEMP_STAGE_')
                            ? parseInt(currentContact.stageId.replace('TEMP_STAGE_', ''))
                            : 0;

                        // Use calculated index or fallback to 0
                        const realStageId = sortedStages[tempStageIndex] ? sortedStages[tempStageIndex].id : (sortedStages[0] ? sortedStages[0].id : '');

                        // Update contact in parent
                        onContactUpdate({
                            pipelineId: realPipelineId,
                            stageId: realStageId
                        });

                        const currentCustomerId = customerIdRef.current;

                        if (currentCustomerId) {
                            submitLead(currentCustomerId, {
                                pipelineId: realPipelineId,
                                stageId: realStageId
                            });
                            setPendingLeadCreation(false);
                        } else {
                            // Customer missing, trigger create customer logic
                            // Customer missing, trigger create customer logic
                            const currentContact = contactRef.current;
                            const custPayload = constructCustomerPayload(currentContact);
                            postWindowMessage('CUSTOMER_CREATE', custPayload);
                            // Keep pendingLeadCreation = true so when customer is created, the useEffect will trigger submitLead
                        }
                    }
                    creatingDefaultPipelineRef.current = false;
                    setLoadingPipelines(false);
                }
            } else if (type === 'PIPELINE_CREATED_ERROR') {
                creatingDefaultPipelineRef.current = false;
                setLoadingPipelines(false);
            } else if (type === 'PIPELINES_LIST_ERROR') {
                setLoadingPipelines(false);
            } else if (type === 'LEAD_CREATE_SUCCESS') {
                setIsSubmitting(false);
                if (onCancel) onCancel();
            } else if (type === 'LEAD_CREATE_ERROR') {
                setIsSubmitting(false);
                // TODO: Show error to user
            }
        };

        window.addEventListener('message', handleMessage);

        return () => window.removeEventListener('message', handleMessage);
    }, []);


    const handleChange = (key) => (e) => {
        onContactUpdate({ [key]: e.target.value });
    };

    const constructCustomerPayload = (contactData) => {
        const withPlus = (val) => {
            if (!val) return val;
            return String(val).startsWith('+') ? String(val) : `+${val}`;
        };
        const companyId = contactData.company?.id;
        return {
            chat_id: chatId,
            first_name: contactData.firstName,
            last_name: contactData.lastName,
            email: contactData.email,
            phone: withPlus(contactData.phone),
            source: contactData.source || '',
            address: contactData.address,
            city: contactData.city,
            state: contactData.state,
            zip_code: contactData.zip,
            country: contactData.country,
            ...(companyId ? { company_id: companyId, relationship_type: contactData.designation } : {})
        };
    };



    const handleSelectChange = (key) => (value) => {
        if (key === 'pipelineId') {
            const selectedPipeline = pipelines.find(p => p.id === value);
            let defaultStageId = '';
            // Auto-select first stage
            if (selectedPipeline && selectedPipeline.stages && selectedPipeline.stages.length > 0) {
                defaultStageId = selectedPipeline.stages[0].id;
            }
            onContactUpdate({ [key]: value, stageId: defaultStageId });
        } else {
            onContactUpdate({ [key]: value });
        }
    };

    const submitLead = (finalCustomerId, overrides = {}) => {
        const currentContact = contactRef.current; // ALWAYS use Ref for fresh data
        const payload = {
            pipeline_id: overrides.pipelineId || currentContact.pipelineId,
            stage_id: overrides.stageId || currentContact.stageId,
            title: currentContact.title,
            expected_value: Number(currentContact.expectedValue),
            priority: currentContact.priority || 'HOT',
            expected_closing_date: currentContact.closingDate ? new Date(currentContact.closingDate).toISOString() : null,
            source: currentContact.source,
            currency_type: currentContact.currency || 'INR',
            contact_id: Number(finalCustomerId)
        };

        postWindowMessage('LEAD_CREATE', payload);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (isSubmitting) return;

        if (!contact.pipelineId || !contact.stageId) {
            // TODO: Add proper validation UI
            return;
        }

        if (contact.closingDate) {
            const selectedDate = new Date(contact.closingDate);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            if (selectedDate <= today) {
                // TODO: Add proper validation UI. For now, we return.
                return;
            }
        }

        setIsSubmitting(true);

        if (contact.pipelineId) {
            const selectedPipe = pipelines.find(p => p.id === contact.pipelineId);

            if (selectedPipe && selectedPipe.is_temp) {
                setIsSubmitting(true);
                setPendingLeadCreation(true); // Flag to handle subsequent logic
                creatingDefaultPipelineRef.current = true;

                // Create Real Pipeline
                const createPayload = defaultPipelinePayload();
                postWindowMessage('CREATE_PIPELINE', createPayload);
                return;
            }
        }

        if (!customerId) {
            // Need to create customer first
            setPendingLeadCreation(true);
            setIsSubmitting(true);

            const payload = constructCustomerPayload(contact);

            postWindowMessage('CUSTOMER_CREATE', payload);
        } else {
            setIsSubmitting(true);
            submitLead(customerId);
        }
    };

    const selectedPipeline = pipelines.find(p => p.id === contact.pipelineId);
    const stageOptions = selectedPipeline ? (selectedPipeline.stages || []).map(s => ({ label: s.name || s.label, value: s.id })) : [];
    const pipelineOptions = pipelines.map(p => ({ label: p.name, value: p.id }));
    const priorityOptions = PRIORITY_OPTIONS;
    const currencyOptions = CURRENCY_OPTIONS;

    return (
        <div className="cq-lead-creation">
            <div className="cq-lead-header">Create New Lead</div>

            <form onSubmit={handleSubmit} className="cq-lead-form">

                {/* Contact Card Section */}
                <ContactCard
                    contact={contact}
                    onContactUpdate={onContactUpdate}
                    chatId={chatId}
                    customerId={customerId}
                    forceExpanded={forceExpanded}
                    isLoadingContact={isLoadingContact}
                />

                {/* Lead Details Section */}
                <div className="cq-lead-details-section">
                    {showLoader && (
                        <div className={`cq-analyzing-container ${isExiting ? 'slide-up' : ''}`}>
                            <div className="wave-text infinite">
                                {"Analyzing chat to suggest details...".split('').map((char, index) => (
                                    <span key={index} style={{ '--i': index }}>
                                        {char === ' ' ? '\u00A0' : char}
                                    </span>
                                ))}
                            </div>
                        </div>
                    )}
                    <div className="cq-lead-row">
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Pipeline</span>
                            <Select
                                options={pipelineOptions}
                                value={contact.pipelineId}
                                onChange={handleSelectChange('pipelineId')}
                                placeholder={loadingPipelines ? "Loading pipelines..." : "Select Pipeline"}
                            />
                        </label>
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Stage</span>
                            <Select
                                options={stageOptions}
                                value={contact.stageId}
                                onChange={handleSelectChange('stageId')}
                                placeholder="Select Stage"
                            />
                        </label>
                    </div>
                    <label className="cq-lead-field">
                        <span className="cq-lead-label">Lead Title</span>
                        <InputBox
                            value={contact.title}
                            onChange={handleChange('title')}
                            placeholder="Enter lead title"
                        />
                    </label>

                    <div className="cq-lead-row">
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Priority</span>
                            <Select
                                options={priorityOptions}
                                value={contact.priority}
                                onChange={handleSelectChange('priority')}
                                placeholder="Select Priority"
                            />
                        </label>
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Expected Closing Date</span>
                            <InputBox
                                value={contact.closingDate}
                                onChange={handleChange('closingDate')}
                                type="date"
                                min={new Date(new Date().setDate(new Date().getDate() + 1)).toISOString().split('T')[0]}
                            />
                        </label>
                    </div>

                    <div className="cq-lead-row">
                        <label className="cq-lead-field" style={{ gridColumn: 'span 2' }}>
                            <span className="cq-lead-label">Expected Value</span>
                            <div className="cq-combined-input">
                                <div style={{ width: '100px' }}>
                                    <Select
                                        options={currencyOptions}
                                        value={contact.currency}
                                        onChange={handleSelectChange('currency')}
                                        placeholder="CUR"
                                    />
                                </div>
                                <InputBox
                                    value={contact.expectedValue}
                                    onChange={handleChange('expectedValue')}
                                    placeholder="0.00"
                                    type="number"
                                />
                            </div>
                        </label>
                    </div>



                    <label className="cq-lead-field">
                        <span className="cq-lead-label">Lead Source</span>
                        <InputBox
                            value={contact.source}
                            onChange={handleChange('source')}
                            placeholder="e.g. Website, Referral"
                        />
                    </label>
                </div>

                <div className="cq-lead-actions">
                    {hasLeads && (
                        <button type="button" className="cq-btn-secondary" onClick={onCancel} disabled={isSubmitting}>
                            Cancel
                        </button>
                    )}
                    <button
                        type="submit"
                        className="cq-btn-primary"
                        disabled={isSubmitting || !contact.pipelineId || !contact.stageId || !contact.title}
                    >
                        {isSubmitting ? 'Creating...' : 'Create Lead'}
                    </button>
                </div>
            </form >
        </div >
    );
};

export default LeadCreation;
