import React, { useState, useEffect, useImperativeHandle, forwardRef, useRef } from 'react';
import NoteForm from '../../../UIComponents/Forms/NoteForm';
import { postWindowMessage } from '../../../../utils/messageSender';
import { icons } from '../../../../Constants/svg';
import './LeadActivity.css';

import ActivityNote from './ActivityNote';
import ActivityTask from './ActivityTask';
import ActivityLead from './ActivityLead';
import ActivityContact from './ActivityContact';

const LeadActivity = forwardRef(({ leadId, refreshTrigger }, ref) => {
    const [activities, setActivities] = useState([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);
    const observerTarget = useRef(null);
    const requestedPageRef = useRef(1);

    // Reset when lead changes or refresh is triggered
    useEffect(() => {
        setActivities([]);
        setPage(1);
        setHasMore(true);
        setLoading(true);
        requestedPageRef.current = 1;
        postWindowMessage('LEAD_ACTIVITY_LIST', { leadId, page: 1 });
    }, [leadId, refreshTrigger]);

    // Fetch more when page changes (but not for initial load which is handled above)
    useEffect(() => {
        if (page > 1) {
            setLoading(true);
            requestedPageRef.current = page;
            postWindowMessage('LEAD_ACTIVITY_LIST', { leadId, page });
        }
    }, [page, leadId]);

    // Intersection Observer for Infinite Scroll
    useEffect(() => {
        const observer = new IntersectionObserver(
            entries => {
                if (entries[0].isIntersecting && hasMore && !loading) {
                    setPage(prev => prev + 1);
                }
            },
            { threshold: 1.0 }
        );

        if (observerTarget.current) {
            observer.observe(observerTarget.current);
        }

        return () => {
            if (observerTarget.current) {
                observer.unobserve(observerTarget.current);
            }
        };
    }, [hasMore, loading]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'LEAD_ACTIVITY_LIST_SUCCESS') {
                const results = payload.results || [];
                // Use payload page if available, otherwise fallback to our tracked request page
                const currentPage = payload.page || requestedPageRef.current;

                setActivities(prev => {
                    if (currentPage === 1) return results;
                    // Filter out any potential duplicates by ID just in case
                    const existingIds = new Set(prev.map(a => a.id));
                    const newUnique = results.filter(a => !existingIds.has(a.id));
                    return [...prev, ...newUnique];
                });

                setLoading(false);
                setHasMore(!!payload.next);
            } else if (type === 'LEAD_ACTIVITY_LIST_ERROR') {
                console.error('Error fetching activities:', payload.error);
                setLoading(false);
            } else if (type === 'LEAD_NOTE_CREATE_SUCCESS') {
                // Refresh list on new note
                setPage(1);
                setLoading(true);
                requestedPageRef.current = 1;
                postWindowMessage('LEAD_ACTIVITY_LIST', { leadId, page: 1 });
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, []);

    useImperativeHandle(ref, () => ({
        refresh: () => {
            setPage(1);
            setLoading(true);
            requestedPageRef.current = 1;
            postWindowMessage('LEAD_ACTIVITY_LIST', { leadId, page: 1 });
        },
        addSystemActivity: (content) => {
            setPage(1);
            setLoading(true);
            requestedPageRef.current = 1;
            postWindowMessage('LEAD_ACTIVITY_LIST', { leadId, page: 1 });
        }
    }));

    const handleSaveNote = async (noteText) => {
        postWindowMessage('LEAD_NOTE_CREATE', {
            lead_id: leadId,
            content: noteText
        });
    };

    const formatTime = (isoString) => {
        if (!isoString) return '';
        const date = new Date(isoString);
        const now = new Date();

        if (date.toDateString() === now.toDateString()) {
            return 'Today, ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }
        return date.toLocaleDateString() + ', ' + date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    };

    const renderActivityItem = (activity) => {
        if (activity.activity_type.includes('note')) {
            return <ActivityNote key={activity.id} activity={activity} formatTime={formatTime} />;
        }
        if (activity.activity_type.startsWith('task_')) {
            return <ActivityTask key={activity.id} activity={activity} formatTime={formatTime} />;
        }
        if (activity.activity_type.startsWith('linked_entity_') || activity.activity_type.startsWith('contact_')) {
            return <ActivityContact key={activity.id} activity={activity} formatTime={formatTime} />;
        }
        // Default fallthrough for 'lead_updated' or others
        return <ActivityLead key={activity.id} activity={activity} formatTime={formatTime} />;
    };

    return (
        <div className="cq-activity-feed">
            <NoteForm
                onSave={handleSaveNote}
                placeholder="Write a quick note..."
                saveLabel="Save Note"
            />

            <div className="cq-feed-list">
                {activities.map(activity => renderActivityItem(activity))}

                {activities.length === 0 && !loading && (
                    <div style={{ padding: '20px', textAlign: 'center', color: '#6b7280' }}>No activity yet.</div>
                )}

                {/* Loading Indicator / Observer Target */}
                <div ref={observerTarget} style={{ padding: '10px', textAlign: 'center', minHeight: '20px' }}>
                    {loading && <span style={{ color: '#6b7280', fontSize: '13px' }}>Loading...</span>}
                </div>
            </div>
        </div>
    );
});

export default LeadActivity;
