import React, { useState, useEffect } from 'react';
import './Dashboard.css';
import { icons } from '../../../Constants/svg';
import TooltipWrapper from './TooltipWrapper';
import { showToast } from '../../UIComponents/Toast/ToastManager';
import { isDarkMode } from '../../../utils/utils';

const KanbanTab = ({ pipelineId, pipeline, onLeadClick }) => {
    const isDark = isDarkMode();
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true); // Global loading for initial fetch
    const [error, setError] = useState(null);
    const [stagePagination, setStagePagination] = useState({}); // { [stageId]: { page: 1, hasMore: false, loading: false } }

    const pipelineStages = pipeline?.stages || [];

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'LEAD_UPDATE_ERROR') {
                console.error("Failed to update lead:", payload.error);
                showToast({ message: 'Failed to update lead', type: 'error', duration: 3000 });
                fetchLeads();
            } else if (type === 'DASHBOARD_LEADS_GET_SUCCESS') {
                const { results, stage_id, page, next } = payload;
                if (results && stage_id) {
                    setLeads(prevLeads => {
                        if (page === 1) {
                            // Replace leads for this stage
                            const otherLeads = prevLeads.filter(l => l.stage_id !== stage_id);
                            return [...otherLeads, ...results];
                        } else {
                            // Append leads (filter out duplicates if any, just in case)
                            const existingIds = new Set(prevLeads.map(l => l.id));
                            const newLeads = results.filter(l => !existingIds.has(l.id));
                            return [...prevLeads, ...newLeads];
                        }
                    });

                    setStagePagination(prev => ({
                        ...prev,
                        [stage_id]: {
                            page: page,
                            hasMore: !!next,
                            loading: false
                        }
                    }));
                }

                // If this was an initial load (page 1), we can start showing things
                if (page === 1) setLoading(false);
            } else if (type === 'DASHBOARD_LEADS_GET_ERROR') {
                console.error("Error fetching dashboard leads:", payload.error);
                const { stage_id } = payload;
                if (stage_id) {
                    setStagePagination(prev => ({
                        ...prev,
                        [stage_id]: { ...prev[stage_id], loading: false }
                    }));
                }
                setLoading(false);
            } else if (type === 'LEAD_CREATE_SUCCESS') {
                const newLead = payload;
                const newLeadPipeId = newLead.pipeline_id || newLead.pipelineId;
                if (newLead && String(newLeadPipeId) === String(pipelineId)) {
                    setLeads(prev => {
                        if (prev.some(l => String(l.id) === String(newLead.id))) return prev;
                        return [newLead, ...prev];
                    });
                }
            } else if (type === 'LEAD_DELETE_SUCCESS') {
                const deletedLeadId = payload.id || payload.lead_id;
                if (deletedLeadId) {
                    setLeads(prev => prev.filter(l => String(l.id) !== String(deletedLeadId)));
                }
            }
        };

        window.addEventListener('message', handleMessage);

        const fetchLeads = () => {
            if (!pipelineId || !pipeline?.stages) {
                setLeads([]);
                setLoading(false);
                setError(null);
                return;
            }
            setLoading(true); // Global loading on init
            setError(null);

            // Initialize pagination state for all stages
            const initialPagination = {};
            pipeline.stages.forEach(stage => {
                initialPagination[stage.id] = { page: 1, hasMore: false, loading: true };
            });
            setStagePagination(initialPagination);

            pipeline.stages.forEach(stage => {
                window.postMessage({
                    type: 'DASHBOARD_LEADS_GET',
                    payload: {
                        pipeline_id: pipelineId,
                        stage_id: stage.id,
                        page: 1,
                        page_size: 5 // Fetch only 5 records per stage
                    }
                }, '*');
            });
        };

        fetchLeads();

        return () => window.removeEventListener('message', handleMessage);
    }, [pipelineId]);

    const handleDragStart = (e, leadId) => {
        e.dataTransfer.setData("leadId", leadId);
    };

    const handleDragOver = (e) => {
        e.preventDefault(); // Necessary for drop to work
    };

    const handleDrop = (e, targetStageId) => {
        e.preventDefault();
        const leadId = e.dataTransfer.getData("leadId");

        const leadToMove = leads.find(l => l.id === leadId);
        if (!leadToMove || leadToMove.stage_id === targetStageId) return;

        // Optimistic update
        setLeads(prev => prev.map(lead => {
            if (lead.id === leadId) {
                return { ...lead, stage_id: targetStageId };
            }
            return lead;
        }));

        window.postMessage({
            type: 'LEAD_UPDATE',
            payload: {
                lead_id: leadId,
                updates: { stage_id: targetStageId }
            }
        }, '*');

        showToast({ message: 'Lead moved successfully', type: 'success', duration: 3000 });
    };

    // Calculate stage totals
    const getStageTotal = (stageId) => {
        return leads
            .filter(l => l.stage_id === stageId)
            // Ensure value is a number
            .reduce((sum, l) => sum + (parseFloat(l.expected_value || l.estimated_value) || 0), 0);
    };

    const formatCurrency = (val) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumSignificantDigits: 3 }).format(val);

    const isSlippingAway = (lead) => {
        if (!lead.last_activity) return false;
        const sevenDaysAgo = new Date();
        sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
        return new Date(lead.last_activity) < sevenDaysAgo;
    };

    const hasTaskDue = (lead) => {
        return lead.has_overdue_task || false;
    };

    const getBaseColor = (stage) => {
        return stage.color || (stage.meta && stage.meta.color) || '#d1d5db';
    };

    const handleLoadMore = (stageId) => {
        const currentPagination = stagePagination[stageId];
        if (!currentPagination || currentPagination.loading || !currentPagination.hasMore) return;

        const nextPage = (currentPagination.page || 1) + 1;

        setStagePagination(prev => ({
            ...prev,
            [stageId]: { ...prev[stageId], loading: true }
        }));

        window.postMessage({
            type: 'DASHBOARD_LEADS_GET',
            payload: {
                pipeline_id: pipelineId,
                stage_id: stageId,
                page: nextPage,
                page_size: 5
            }
        }, '*');
    };

    if (loading) {
        return <div className="cq-kanban-loader">Loading leads...</div>;
    }

    if (error) {
        return <div className="cq-kanban-error">{error}</div>;
    }

    if (!pipelineStages || pipelineStages.length === 0) {
        return <div className="cq-kanban-empty">No stages defined for this pipeline.</div>;
    }

    return (
        <div className="cq-kanban-container">
            <div className="cq-kanban-board">
                {pipelineStages.map(stage => {
                    const baseColor = getBaseColor(stage);
                    const headerBg = `color-mix(in srgb, ${baseColor} 25%, ${isDark ? 'black' : 'white'})`;
                    const bodyBg = `color-mix(in srgb, ${baseColor} 10%, ${isDark ? 'black' : 'white'})`;
                    const borderColor = baseColor;
                    const pagination = stagePagination[stage.id] || { hasMore: false, loading: false };

                    return (
                        <div
                            key={stage.id}
                            className="cq-kanban-column"
                            onDragOver={handleDragOver}
                            onDrop={(e) => handleDrop(e, stage.id)}
                            style={{
                                borderTop: `4px solid ${borderColor}`,
                                backgroundColor: bodyBg
                            }}
                        >
                            <div className="cq-kanban-header" style={{ backgroundColor: headerBg }}>
                                <span className="cq-stage-name">{stage.name || stage.label}</span>
                                <span className="cq-stage-total">{formatCurrency(getStageTotal(stage.id))}</span>
                            </div>
                            <div className="cq-kanban-body">
                                {leads.filter(l => l.stage_id === stage.id).map(lead => (
                                    <div
                                        key={lead.id}
                                        className={`cq-kanban-card ${isSlippingAway(lead) ? 'cq-card-slipping' : ''}`}
                                        draggable
                                        onDragStart={(e) => handleDragStart(e, lead.id)}
                                        onClick={() => onLeadClick && onLeadClick(lead)}
                                    >
                                        <div className="cq-card-title">{lead.title || 'Unnamed Lead'}</div>
                                        <div className="cq-card-company">{lead.company_name || lead.company || ''}</div>
                                        <div className="cq-card-footer">
                                            <span className="cq-card-value">{formatCurrency(lead.expected_value || lead.estimated_value || 0)}</span>
                                            <div className="cq-card-icons">
                                                {isSlippingAway(lead) && (
                                                    <TooltipWrapper content="Slipping Away: No activity for 7+ days">
                                                        <span className="cq-tag-dot red"></span>
                                                    </TooltipWrapper>
                                                )}
                                                {hasTaskDue(lead) && (
                                                    <TooltipWrapper content="Task Due: Action required">
                                                        <span className="cq-tag-icon yellow">⚠️</span>
                                                    </TooltipWrapper>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                                {pagination.hasMore && (
                                    <div className="cq-kanban-load-more">
                                        <button
                                            className="cq-btn-load-more"
                                            onClick={() => handleLoadMore(stage.id)}
                                            disabled={pagination.loading}
                                        >
                                            {pagination.loading ? 'Loading...' : 'Load More'}
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );


};

export default KanbanTab;
