import React, { useEffect, useState } from 'react';
import { icons } from '../../../../Constants/svg';

const Scorecard = ({ stats, loading, currency, exchangeRates }) => {
    // currency and exchangeRates are passed from parent, but we can default if missing
    const localCurrency = (currency || 'USD').toUpperCase();
    const rates = exchangeRates || {};

    const targetRate = rates[localCurrency.toLowerCase()] || 1;

    const convertedValue = (stats?.pipeline_value?.values || []).reduce((acc, item) => {
        const val = item?.total || 0;
        const sourceCurrency = (item?.currency || 'USD').toLowerCase();
        // Calculate cross-rate: (USD -> Target) / (USD -> Source)
        const sourceRate = rates[sourceCurrency] || 1;
        const conversionFactor = targetRate / sourceRate;
        return acc + (val * conversionFactor);
    }, 0);

    const conversionRate = stats?.conversion_rate?.percentage || 0;
    const newLeadsCount = stats?.new_leads?.count || 0;
    const tasksDueToday = stats?.tasks_due_today?.count || 0;

    const formatCurrency = (val) => {
        try {
            return new Intl.NumberFormat(window.navigator.language, {
                style: 'currency',
                currency: localCurrency,
                maximumSignificantDigits: 3
            }).format(val || 0);
        } catch (e) {
            return `${localCurrency} 0`;
        }
    };

    return (
        <div className="cq-dashboard-grid">
            <div className="cq-metric-card">
                <div className="cq-metric-header">
                    <span className="cq-metric-label">Forecast Value</span>
                    <div className="cq-metric-icon" style={{ fontSize: '14px', fontWeight: 'bold' }}>
                        {localCurrency === 'INR' ? '₹' : (localCurrency === 'USD' ? '$' : localCurrency)}
                    </div>
                </div>
                <div className="cq-metric-value">{loading ? '...' : formatCurrency(convertedValue)}</div>
                <div className="cq-metric-trend"><span className="cq-trend-neutral">Weighted Pipeline</span></div>
            </div>

            <div className="cq-metric-card">
                <div className="cq-metric-header">
                    <span className="cq-metric-label">Conversion Rate</span>
                    <div className="cq-metric-icon">%</div>
                </div>
                <div className="cq-metric-value">{loading ? '...' : conversionRate}%</div>
                <div className="cq-metric-trend"><span className="cq-trend-neutral">Period Average</span></div>
            </div>

            <div className="cq-metric-card">
                <div className="cq-metric-header">
                    <span className="cq-metric-label">New Leads</span>
                    <div className="cq-metric-icon">{icons.PLUS_IN_SQUARE}</div>
                </div>
                <div className="cq-metric-value">{loading ? '...' : newLeadsCount}</div>
                <div className="cq-metric-trend"><span className="cq-trend-up">In selected range</span></div>
            </div>

            <div className="cq-metric-card">
                <div className="cq-metric-header">
                    <span className="cq-metric-label">Tasks Due Today</span>
                    <div className="cq-metric-icon">{icons.TODO}</div>
                </div>
                <div className="cq-metric-value">{loading ? '...' : tasksDueToday}</div>
                <div className="cq-metric-trend"><span className="cq-trend-down" style={{ color: '#ef4444' }}>Action required</span></div>
            </div>
        </div>
    );
};

export default Scorecard;
