import React, { useEffect, useState } from 'react';

export function isUserTextAvailable() {
  const inputBox = document.querySelector('footer._ak1i .lexical-rich-text-input [contenteditable="true"]');
  if (!inputBox) return false;
  const typedText = inputBox.textContent?.trim();
  return Boolean(typedText && typedText.length > 0);
}


function parseStaticMessages() {
  const staticMessages = localStorage.getItem('CQ_STATIC_MESSAGES');
  if (!staticMessages) return {};

  try {
    return JSON.parse(staticMessages);
  } catch (error) {
    console.error('Failed to parse static messages:', error);
    return {};
  }
}

export const getStaticMessage = (key) => {
  const staticMessages = parseStaticMessages();
  if (!staticMessages || !key) return '';

  const message = staticMessages[key];
  if (!message) {
    console.warn(`Static message for key "${key}" not found.`);
    return '';
  }

  return message;
}


export function getTrialDaysLeft(expiryDateStr) {
  const now = new Date();
  const expiryDate = new Date(expiryDateStr);

  // Calculate time difference in milliseconds
  const diffTime = expiryDate - now;

  // Convert to full days (rounding up if partial day left)
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Ensure it's never negative
  return Math.max(diffDays, 0);
}

export const renderHtml = (htmlString) => {
  return <div dangerouslySetInnerHTML={{ __html: htmlString }} style={{ wordWrap: 'break-word', marginBottom: '10px', lineHeight: '1.4em', color: '#1f2937' }} />;
};

export const stripHtml = (htmlString) => {
  if (!htmlString) return '';
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlString, 'text/html');
  return doc.body.textContent || '';
};

export function isDarkMode() {
  const getIsDark = () => document.body.classList.contains('dark');
  const [isDarkMode, setIsDarkMode] = useState(getIsDark());

  useEffect(() => {
    const observer = new MutationObserver(() => {
      setIsDarkMode(getIsDark());
    });

    observer.observe(document.body, {
      attributes: true,
      attributeFilter: ['class'],
    });

    return () => observer.disconnect();
  }, []);

  return isDarkMode;
}

export function uuidv4() {
  return "10000000-1000-4000-8000-100000000000".replace(/[018]/g, c =>
    (+c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> (+c / 4)).toString(16)
  );
}

export const mapPipelineToUI = (p) => ({
  ...p,
  isDefault: p.is_default, // map snake_case to camelCase
  stages: (p.stages || []).sort((a, b) => a.position - b.position).map(stage => ({
    id: stage.id,
    name: stage.label,
    type: stage.stage_type,
    color: stage.meta?.color || '#94a3b8',
    probability: stage.meta?.probability || 0,
    order: stage.position,
    is_active: stage.is_active
  }))
});