import React, { useState, useRef, useEffect, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import './Tooltip.css';

const Tooltip = ({ text, children, position = 'top', delay = 200 }) => {
    const [isVisible, setIsVisible] = useState(false);
    const [coords, setCoords] = useState({ top: 0, left: 0 });
    const triggerRef = useRef(null);
    const tooltipRef = useRef(null);
    const timeoutRef = useRef(null);

    const updatePosition = () => {
        if (triggerRef.current && isVisible) {
            const rect = triggerRef.current.getBoundingClientRect();
            let top = 0;
            let left = 0;

            // Fixed positioning logic (relative to viewport)
            if (position === 'top') {
                top = rect.top - 8;
                left = rect.left + rect.width / 2;
            } else if (position === 'bottom') {
                top = rect.bottom + 8;
                left = rect.left + rect.width / 2;
            }

            setCoords({ top, left });
        }
    };

    useLayoutEffect(() => {
        if (isVisible) {
            updatePosition();
            window.addEventListener('scroll', updatePosition, true);
            window.addEventListener('resize', updatePosition);
        }
        return () => {
            window.removeEventListener('scroll', updatePosition, true);
            window.removeEventListener('resize', updatePosition);
        };
    }, [isVisible, position]);

    const showTooltip = () => {
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        timeoutRef.current = setTimeout(() => {
            setIsVisible(true);
        }, delay);
    };

    const hideTooltip = () => {
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        setIsVisible(false);
    };

    useEffect(() => {
        return () => {
            if (timeoutRef.current) clearTimeout(timeoutRef.current);
        };
    }, []);

    if (!text) return children;

    const tooltipElement = isVisible && createPortal(
        <div
            ref={tooltipRef}
            className={`cq-tooltip cq-tooltip-${position}`}
            style={{
                top: coords.top,
                left: coords.left,
                position: 'fixed',
                transform: position === 'top' ? 'translate(-50%, -100%)' : 'translate(-50%, 0)',
                zIndex: 2147483647 // Max z-index
            }}
        >
            {text}
        </div>,
        document.body
    );

    return (
        <div
            ref={triggerRef}
            className="cq-tooltip-wrapper"
            onMouseEnter={showTooltip}
            onMouseLeave={hideTooltip}
        >
            {children}
            {tooltipElement}
        </div>
    );
};

export default Tooltip;
