import React, { useState, useEffect } from 'react';
import Modal from '../../UIComponents/Modal/Modal';
import ClickToEditInput from '../../UIComponents/ClickToEditInput'; // We'll use standard inputs instead of ClickToEdit for form
import InputBox from '../../UIComponents/InputBox';

// Reuse button styles from generic areas or define local
const buttonStyle = {
    padding: '8px 16px',
    borderRadius: '6px',
    fontSize: '14px',
    fontWeight: '500',
    cursor: 'pointer',
    border: 'none',
    transition: 'background 0.2s',
};

const primaryBtnStyle = {
    ...buttonStyle,
    background: '#2563eb',
    color: 'white',
};

const secondaryBtnStyle = {
    ...buttonStyle,
    background: 'transparent',
    color: '#6b7280',
    border: '1px solid #d1d5db'
};

const WonLostModal = ({
    isOpen,
    onClose,
    type, // 'won' or 'lost'
    leadValue, // Initial value if exists
    onSave
}) => {
    const [value, setValue] = useState(leadValue || '');
    const [reason, setReason] = useState('');

    useEffect(() => {
        if (isOpen) {
            setValue(leadValue || '');
            setReason('');
        }
    }, [isOpen, leadValue]);

    const handleSave = () => {
        if (type === 'won') {
            onSave({ value });
        } else {
            onSave({ reason });
        }
        onClose();
    };

    const isWon = type === 'won';
    const title = isWon ? "Deal Won! 🎉" : "Mark as Lost";

    const footer = (
        <>
            <button style={secondaryBtnStyle} onClick={onClose}>Cancel</button>
            <button style={primaryBtnStyle} onClick={handleSave}>
                {isWon ? 'Save Value' : 'Mark Lost'}
            </button>
        </>
    );

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={title}
            footer={footer}
            width="400px"
        >
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {isWon ? (
                    <div>
                        <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500' }}>
                            Final Deal Value ({/* Currency symbol could be passed prop */ '$'})
                        </label>
                        <InputBox
                            type="number"
                            value={value}
                            onChange={(e) => setValue(e.target.value)}
                            placeholder="Enter final value"
                            autoFocus
                        />
                        <p style={{ fontSize: '12px', color: '#6b7280', marginTop: '4px' }}>
                            Update the final revenue amount for this deal.
                        </p>
                    </div>
                ) : (
                    <div>
                        <label style={{ display: 'block', marginBottom: '8px', fontWeight: '500' }}>
                            Reason for Loss
                        </label>
                        <textarea
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            placeholder="Why was this deal lost? e.g. Price too high, Competitor..."
                            style={{
                                width: '100%',
                                minHeight: '100px',
                                padding: '10px',
                                borderRadius: '8px',
                                border: '1px solid #d1d5db',
                                fontFamily: 'inherit',
                                fontSize: '14px',
                                outline: 'none',
                                resize: 'vertical'
                            }}
                            autoFocus
                        />
                    </div>
                )}
            </div>
        </Modal>
    );
};

export default WonLostModal;
