// Centralized popover management to prevent duplicates
class PopoverManager {
  constructor() {
    this.activePopovers = new Set();
  }

  // Check if a popover is already active
  isPopoverActive(popoverId) {
    return this.activePopovers.has(popoverId);
  }

  // Check if any popover is currently active
  hasActivePopover() {
    return this.activePopovers.size > 0;
  }

  // Register a new popover
  registerPopover(popoverId) {
    this.activePopovers.add(popoverId);
  }

  // Remove a popover when closed
  unregisterPopover(popoverId) {
    this.activePopovers.delete(popoverId);
  }

  // Force close all popovers
  closeAllPopovers() {
    this.activePopovers.clear();
  }

  // Close specific popover by ID
  closePopover(popoverId) {
    this.unregisterPopover(popoverId);
  }
}

// Create singleton instance
const popoverManager = new PopoverManager();

export default popoverManager;