import React, { useState, useMemo } from 'react';
import ContactCard from './ContactCard';
import LeadCard from './LeadCard';
import ConfirmationModal from '../UIComponents/ConfirmationModal';
import { isDarkMode } from '../../utils/utils';
import { postWindowMessage } from '../../utils/messageSender';
import './LeadCreation.css'; // Reuse styles for now
import '../UIComponents/ConfirmationModal.css';

const LeadListing = ({
    onCreateLead,
    contact,
    onContactUpdate,
    chatId,
    customerId,
    forceExpanded,
    isLoadingContact,
    leads,
    pipelines = [],
    setLeads,
    onLeadClick,
    onUpdateLead
}) => {
    const isDark = isDarkMode();
    const [deleteModalOpen, setDeleteModalOpen] = useState(false);
    const [leadToDelete, setLeadToDelete] = useState(null);

    const handleDeleteLead = (leadId) => {
        setLeadToDelete(leadId);
        setDeleteModalOpen(true);
    };

    const confirmDelete = () => {
        if (leadToDelete) {
            postWindowMessage('LEAD_DELETE', { lead_id: leadToDelete });
            setLeadToDelete(null);
        }
        setDeleteModalOpen(false);
    };

    const handleUpdateLead = (leadId, updates) => {
        if (onUpdateLead) {
            onUpdateLead(leadId, updates);
        }
    };

    return (
        <div className="cq-lead-creation">
            {/* Contact Card Section */}
            <ContactCard
                contact={contact}
                onContactUpdate={onContactUpdate}
                chatId={chatId}
                customerId={customerId}
                forceExpanded={forceExpanded}
                isLoadingContact={isLoadingContact}
            />

            {/* Header with Create Action */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px', padding: '0 4px' }}>
                <span className="cq-lead-header" style={{ marginBottom: 0, fontSize: '14px' }}>Leads</span>
            </div>

            {/* Lead Lists Grouped by Pipeline */}
            <div className="cq-lead-list">
                {leads.map((group, groupIdx) => {
                    const currentPipeline = pipelines.find(p => String(p.id) === String(group.id));
                    const pipelineStages = currentPipeline ? (currentPipeline.stages || []) : [];

                    return (
                        <div key={groupIdx} style={{ marginBottom: '20px' }}>
                            <div style={{
                                fontSize: '12px',
                                fontWeight: '600',
                                color: 'var(--text-secondary)',
                                textTransform: 'uppercase',
                                marginBottom: '8px',
                                letterSpacing: '0.5px'
                            }}>
                                {group.pipeline}
                            </div>

                            {group.leads.map((lead, idx) => (
                                <div key={lead.id} style={{ marginBottom: '8px' }}>
                                    <LeadCard
                                        index={idx}
                                        lead={lead}
                                        allStages={pipelineStages}
                                        onUpdate={handleUpdateLead}
                                        onDelete={handleDeleteLead}
                                        onClick={() => onLeadClick(lead)}
                                        isDark={isDark}
                                    />
                                </div>
                            ))}
                        </div>
                    );
                })}
            </div>

            <ConfirmationModal
                isOpen={deleteModalOpen}
                onClose={() => setDeleteModalOpen(false)}
                onConfirm={confirmDelete}
                title="Delete Lead"
                message="Are you sure you want to delete this lead? This action cannot be undone."
                confirmText="Delete"
                confirmButtonStyle="danger"
            />
        </div>
    );
};

export default LeadListing;
