import React, { useState, useEffect } from 'react';
import './NoteForm.css';

const NoteForm = ({
    initialValue = '',
    onSave,
    onCancel,
    placeholder = 'Add a note...',
    saveLabel = 'Save',
    autoFocus = false,
    className = ''
}) => {
    const [noteText, setNoteText] = useState(initialValue);

    useEffect(() => {
        setNoteText(initialValue);
    }, [initialValue]);

    const handleSave = (e) => {
        e.preventDefault();
        if (onSave) {
            onSave(noteText);
        }
        setNoteText('');
    };

    const handleCancel = (e) => {
        e.preventDefault();
        if (onCancel) {
            onCancel();
        }
    };

    return (
        <form onSubmit={handleSave} className={`cq-note-form ${className}`}>
            <textarea
                className="cq-note-input"
                placeholder={placeholder}
                value={noteText}
                onChange={(e) => setNoteText(e.target.value)}
                autoFocus={autoFocus}
            />
            <div className="cq-form-actions">
                {onCancel && (
                    <button type="button" className="cq-btn" onClick={handleCancel} title="Cancel">
                        Cancel
                    </button>
                )}
                <button type="submit" className="cq-btn primary" title={saveLabel} disabled={!noteText.trim()}>
                    {saveLabel}
                </button>
            </div>
        </form>
    );
};

export default NoteForm;
