import React, { useState, useEffect, useRef } from 'react';

import { icons } from '../../Constants/svg';
import { DEFAULT_PIPELINE } from '../../Constants/constant';
import StageEditor from './StageEditor';
import { postWindowMessage } from '../../utils/messageSender';
import './PipelineManager.css';
import ConfirmationModal from '../UIComponents/ConfirmationModal';

const mapStageToApi = (s) => ({
    ...(s.id ? { id: s.id } : {}),
    stage_type: s.type,
    label: s.name,
    position: s.order,
    meta: {
        color: s.color,
        probability: s.probability
    }
});

const mapStageToUI = (stage) => ({
    id: stage.id,
    name: stage.label,
    type: stage.stage_type,
    color: stage.meta?.color || '#94a3b8',
    probability: stage.meta?.probability || 0,
    order: stage.position,
    is_active: stage.is_active
});

const mapPipelineToUI = (p) => ({
    ...p,
    isDefault: p.is_default, // map snake_case to camelCase
    stages: (p.stages || []).sort((a, b) => a.position - b.position).map(mapStageToUI)
});

const createVirtualPipeline = () => ({
    id: 'virtual-default-pipeline',
    name: DEFAULT_PIPELINE.name || 'Default Pipeline',
    isDefault: true,
    isVirtual: true,
    stages: (DEFAULT_PIPELINE.stages || []).map((s, i) => ({
        id: s.id || `virtual-stage-${i}`,
        name: s.name,
        type: s.type,
        color: s.color,
        probability: s.probability,
        order: s.order,
        is_active: true
    }))
});

const PipelineManager = () => {
    const [pipelines, setPipelines] = useState([]);
    const [activePipelineId, setActivePipelineId] = useState(null);
    const [modifiedPipeline, setModifiedPipeline] = useState(null);
    const [isCreating, setIsCreating] = useState(false);
    const [newPipelineName, setNewPipelineName] = useState('');
    const [confirmationModal, setConfirmationModal] = useState({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
        confirmText: 'Confirm',
        confirmButtonStyle: 'primary'

    });
    const [error, setError] = useState(null);

    // clear error after 5s
    useEffect(() => {
        if (error) {
            const timer = setTimeout(() => setError(null), 5000);
            return () => clearTimeout(timer);
        }
    }, [error]);

    const modifiedPipelineRef = useRef(modifiedPipeline);
    useEffect(() => {
        modifiedPipelineRef.current = modifiedPipeline;
    }, [modifiedPipeline]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'PIPELINES_LIST') {
                if (payload && Array.isArray(payload.results)) {
                    // Transform API response to match UI structure
                    let mappedPipelines = payload.results.map(mapPipelineToUI);

                    if (mappedPipelines.length === 0) {
                        mappedPipelines = [createVirtualPipeline()];
                    }

                    setPipelines(mappedPipelines);

                    // Sync currently open pipeline with fetched data to show new stages/changes
                    const currentModified = modifiedPipelineRef.current;
                    if (currentModified) {
                        const updatedActive = mappedPipelines.find(p => p.id === currentModified.id);
                        if (updatedActive) {
                            setModifiedPipeline(updatedActive);
                        }
                    }
                }
            } else if (type === 'PIPELINES_LIST_ERROR') {
                console.error('Failed to fetch pipelines:', payload.error);
                // Fallback or error state? For now, just log.
            } else if (type === 'PIPELINE_UPDATED_SUCCESS') {
                const { version, pipelineId } = payload;
                const currentModified = modifiedPipelineRef.current;

                setPipelines(prev => prev.map(p =>
                    p.id === pipelineId && currentModified && currentModified.id === pipelineId
                        ? { ...currentModified, version }
                        : (p.id === pipelineId ? { ...p, version } : p)
                ));

                if (currentModified && currentModified.id === pipelineId) {
                    setModifiedPipeline(prev => ({ ...prev, version }));
                }

            } else if (type === 'PIPELINE_UPDATED_ERROR') {
                console.error('Failed to update pipeline:', payload.error);
            } else if (type === 'PIPELINE_CREATED_SUCCESS') {
                const newPipelineData = payload.data;
                if (newPipelineData) {
                    const mappedNewPipeline = mapPipelineToUI(newPipelineData);

                    setPipelines(prev => {
                        // Remove virtual pipeline if it exists and replace with real one
                        const filtered = prev.filter(p => !p.isVirtual);
                        return [...filtered, mappedNewPipeline];
                    });
                    setActivePipelineId(mappedNewPipeline.id);
                    setModifiedPipeline(mappedNewPipeline);
                }

                setIsCreating(false);
                setNewPipelineName('');
            } else if (type === 'PIPELINE_CREATED_ERROR') {
                console.error('Failed to create pipeline:', payload.error);
                alert('Failed to create pipeline: ' + payload.error);
            } else if (type === 'STAGE_CREATED_SUCCESS') {
                const { version, stage, pipelineId } = payload;

                if (stage && version) {
                    // Update local state optimistically
                    const currentModified = modifiedPipelineRef.current;

                    setPipelines(prev => prev.map(p => {
                        if (p.id === pipelineId) {
                            const newStages = [...(p.stages || []), stage];
                            return { ...p, version, stages: newStages };
                        }
                        return p;
                    }));

                    if (currentModified && currentModified.id === pipelineId) {
                        setModifiedPipeline(prev => ({
                            ...prev,
                            version,
                            stages: [...(prev.stages || []), stage]
                        }));
                    }
                } else {
                    postWindowMessage('GET_PIPELINES', {});
                }
            } else if (type === 'STAGE_CREATED_ERROR') {
                console.error(payload.error);
                alert('Failed to create stage: ' + payload.error);
            } else if (type === 'STAGE_DELETED_SUCCESS') {
                postWindowMessage('GET_PIPELINES', {});
            } else if (type === 'STAGE_DELETED_ERROR') {
                console.error(payload.error);
            } else if (type === 'DELETE_PIPELINE_SUCCESS') {
                const { pipelineId } = payload;
                if (pipelineId) {
                    setPipelines(prev => {
                        const remaining = prev.filter(p => p.id !== pipelineId);
                        if (remaining.length === 0) {
                            return [createVirtualPipeline()];
                        }
                        return remaining;
                    });
                    if (activePipelineId === pipelineId) {
                        setActivePipelineId(null);
                        setModifiedPipeline(null);
                    }
                } else {
                    // Fallback to fetch if ID is missing for some reason
                    postWindowMessage('GET_PIPELINES', {});
                    setActivePipelineId(null);
                    setModifiedPipeline(null);
                }
            } else if (type === 'DELETE_PIPELINE_ERROR') {
                console.error('Failed to delete pipeline:', payload.error);
                setError('Failed to delete pipeline: ' + payload.error);
            }
        };

        window.addEventListener('message', handleMessage);

        // Fetch pipelines from API
        postWindowMessage('GET_PIPELINES', {});

        return () => window.removeEventListener('message', handleMessage);
    }, []);

    const savePipelines = (updatedPipelines) => {
        setPipelines(updatedPipelines);

        alert('Saving changes via API is not yet implemented. Changes will not persist after reload.');
    };

    const handleCreatePipeline = () => {
        if (!newPipelineName.trim()) return;

        let stagesToUse = [];
        if (DEFAULT_PIPELINE && DEFAULT_PIPELINE.stages) {
            // Deep copy default stages
            const defaults = JSON.parse(JSON.stringify(DEFAULT_PIPELINE.stages));
            // Map to API format using the outer helper and enforce 0-based order
            stagesToUse = defaults.map((s, i) => mapStageToApi({ ...s, order: i }));
        }

        const payload = {
            name: newPipelineName.trim(),
            stages: stagesToUse
        };

        setIsCreating(false);
        postWindowMessage('CREATE_PIPELINE', payload);
    };

    const handleDeletePipeline = (e, id) => {
        e.stopPropagation();
        if (pipelines.length <= 1) {
            setError('You must have at least one pipeline.');
            return;
        }

        const pipeline = pipelines.find(p => p.id === id);
        if (pipeline && pipeline.isDefault) {
            setError('Cannot delete the default pipeline. Please set another pipeline as default first.');
            return;
        }

        setConfirmationModal({
            isOpen: true,
            title: 'Delete Pipeline',
            message: 'Are you sure you want to delete this pipeline? This action cannot be undone.',
            confirmText: 'Delete',
            confirmButtonStyle: 'danger',
            onConfirm: () => {
                postWindowMessage('DELETE_PIPELINE', { pipelineId: id });
            }
        });
    };

    const handleSetDefault = (e, id) => {
        e.stopPropagation();

        // 1. Optimistic Update
        const updatedPipelines = pipelines.map(p => ({
            ...p,
            isDefault: p.id === id
        }));
        setPipelines(updatedPipelines);

        // 2. Sync Modified State if Open
        if (modifiedPipeline) {
            setModifiedPipeline(prev => ({
                ...prev,
                isDefault: prev.id === id
            }));
        }

        // 3. Trigger Save for the NEW default one
        const targetPipeline = pipelines.find(p => p.id === id);
        if (targetPipeline) {
            // We pass independent change 
            savePipelineData({ ...targetPipeline, isDefault: true });
        }
    };


    const togglePipeline = (id) => {
        if (activePipelineId === id) {
            // Collapse
            setActivePipelineId(null);
            setModifiedPipeline(null);
        } else {
            // Expand
            const p = pipelines.find(pip => pip.id === id);
            if (p) {
                setActivePipelineId(id);
                setModifiedPipeline(JSON.parse(JSON.stringify(p))); // Deep copy for editing
            }
        }
    };

    const savePipelineData = (pipelineToSave) => {
        if (!pipelineToSave) return;

        // Handle Virtual Pipeline Creation
        if (pipelineToSave.isVirtual) {
            const stagesToUse = (pipelineToSave.stages || []).map((s, i) => mapStageToApi({ ...s, order: i }));
            const payload = {
                name: pipelineToSave.name,
                stages: stagesToUse
            };
            postWindowMessage('CREATE_PIPELINE', payload);
            return;
        }

        const original = pipelines.find(p => p.id === pipelineToSave.id);
        if (!original) {
            console.warn('Auto-save: Original pipeline not found');
            return;
        }

        const nameChanged = original.name !== pipelineToSave.name;
        const isDefaultChanged = original.isDefault !== pipelineToSave.isDefault;

        const apiStages = (pipelineToSave.stages || []).map(mapStageToApi);
        const originalApiStages = (original.stages || []).map(mapStageToApi);

        const stagesChanged = JSON.stringify(originalApiStages) !== JSON.stringify(apiStages);

        if (!nameChanged && !isDefaultChanged && !stagesChanged) {
            return;
        }

        const payload = {
            pipelineId: pipelineToSave.id,
            currentVersion: original.version,
            name: nameChanged ? pipelineToSave.name : undefined,
            is_default: isDefaultChanged ? pipelineToSave.isDefault : undefined,
            stages: stagesChanged ? apiStages : undefined
        };

        postWindowMessage('UPDATE_PIPELINE', payload);
    };

    const handlePipelineNameBlur = (e) => {
        savePipelineData({ ...modifiedPipeline, name: e.target.value });
    };

    const handleStagesAutoSave = (newStages) => {
        // Should update modifiedPipeline AND save
        const updated = { ...modifiedPipeline, stages: newStages };
        setModifiedPipeline(updated); // Sync UI
        savePipelineData(updated); // Trigger Save
    };

    const isDirty = (pipeline) => {
        if (!modifiedPipeline || !pipeline) return false;
        return JSON.stringify(modifiedPipeline) !== JSON.stringify(pipeline);
    };

    const handleStageCreate = () => {
        if (!modifiedPipeline) return;

        // 1. Generate Unique Name
        const stages = modifiedPipeline.stages || [];
        let counter = 1;
        let newName = `New Stage ${counter}`;
        const existingNames = new Set(stages.map(s => (s.name || '').toLowerCase()));
        while (existingNames.has(newName.toLowerCase())) {
            counter++;
            newName = `New Stage ${counter}`;
        }

        const position = stages.length; // 0-based, so sequential

        // If Virtual, update local state and save (creates pipeline)
        if (modifiedPipeline.isVirtual) {
            const newStage = {
                id: `virtual-stage-new-${Date.now()}`,
                name: newName,
                type: 'OPEN',
                color: 'blue',
                probability: 10,
                order: position,
                is_active: true
            };
            const updated = {
                ...modifiedPipeline,
                stages: [...stages, newStage]
            };
            setModifiedPipeline(updated);
            savePipelineData(updated);
            return;
        }

        const newStagePayload = {
            label: newName,
            stage_type: 'OPEN',
            position: position,
            meta: {
                color: 'blue', // Default per request
                probability: 10
            }
        };

        // 3. Send Message
        const payload = {
            pipelineId: modifiedPipeline.id,
            version: modifiedPipeline.version,
            stage: newStagePayload
        };

        postWindowMessage('CREATE_PIPELINE_STAGE', payload);
    };

    const handleStageDelete = (stageId) => {
        if (!modifiedPipeline) return;

        setConfirmationModal({
            isOpen: true,
            title: 'Delete Stage',
            message: 'Are you sure you want to delete this stage? This action cannot be undone.',
            confirmText: 'Delete',
            confirmButtonStyle: 'danger',
            onConfirm: () => {
                if (modifiedPipeline.isVirtual) {
                    const newStages = modifiedPipeline.stages.filter(s => s.id !== stageId);
                    const updated = {
                        ...modifiedPipeline,
                        stages: newStages
                    };
                    setModifiedPipeline(updated);
                    savePipelineData(updated);
                } else {
                    const payload = {
                        pipelineId: modifiedPipeline.id,
                        stageId: stageId
                    };
                    postWindowMessage('DELETE_PIPELINE_STAGE', payload);
                }
            }
        });
    };

    return (
        <div className="cq-pipeline-manager">
            <div className="cq-pipeline-list-section">
                <div className="cq-pipeline-list-header">
                    <h3>Pipelines</h3>
                    {!isCreating && (
                        <button
                            className="cq-pipeline-add-btn"
                            onClick={() => setIsCreating(true)}
                            title="New Pipeline"
                        >
                            {icons?.PLUS_IN_SQUARE || '+'}
                        </button>
                    )}
                </div>
                {error && (
                    <div className="cq-error-banner" style={{ margin: '8px 16px', borderRadius: '4px' }}>
                        {icons?.WARNING || '!'} {error}
                    </div>
                )}

                {isCreating && (
                    <div className="cq-new-pipeline-form">
                        <div className="cq-input-group">
                            <label className="cq-input-label">Pipeline Name</label>
                            <input
                                className="cq-input"
                                value={newPipelineName}
                                onChange={(e) => setNewPipelineName(e.target.value)}
                                placeholder="e.g. B2B Sales"
                                autoFocus
                            />
                        </div>
                        <div className="cq-form-actions">
                            <button
                                className="cq-btn cq-btn-secondary"
                                onClick={() => setIsCreating(false)}
                            >
                                Cancel
                            </button>
                            <button
                                className="cq-btn cq-btn-primary"
                                onClick={handleCreatePipeline}
                            >
                                Create
                            </button>
                        </div>
                    </div>
                )}

                <div className="cq-pipeline-list">
                    {Array.isArray(pipelines) && pipelines.filter(p => p && p.id).map(pipeline => {
                        const isExpanded = activePipelineId === pipeline.id;
                        const currentData = isExpanded ? modifiedPipeline : pipeline;

                        return (
                            <div
                                key={pipeline.id}
                                className={`cq-pipeline-item-container ${isExpanded ? 'expanded' : ''}`}
                            >
                                <div
                                    className={`cq-pipeline-item ${isExpanded ? 'active' : ''}`}
                                    onClick={() => togglePipeline(pipeline.id)}
                                >
                                    <div className="cq-pipeline-info">
                                        {isExpanded ? (
                                            <div className="cq-pipeline-name-edit" onClick={e => e.stopPropagation()}>
                                                <input
                                                    className="cq-rename-input"
                                                    value={currentData?.name || ''}
                                                    onChange={e => setModifiedPipeline({ ...modifiedPipeline, name: e.target.value })}
                                                    onBlur={handlePipelineNameBlur}
                                                    placeholder="Pipeline Name"
                                                />
                                            </div>
                                        ) : (
                                            <span className="cq-pipeline-name" title={pipeline.name}>
                                                {pipeline.name}
                                            </span>
                                        )}

                                        <div className="cq-pipeline-meta">
                                            {pipeline.isDefault && (
                                                <span className="cq-pipeline-badge">Default</span>
                                            )}
                                        </div>
                                    </div>

                                    <div className="cq-pipeline-actions-wrapper">
                                        <div className="cq-pipeline-actions">
                                            <button
                                                className={`cq-pipeline-action-btn ${pipeline.isDefault ? 'is-default' : ''}`}
                                                title={pipeline.isDefault ? "Default Pipeline" : "Set as Default"}
                                                onClick={(e) => !pipeline.isDefault && handleSetDefault(e, pipeline.id)}
                                                disabled={pipeline.isDefault}
                                            >
                                                {icons?.PIN || 'Set Default'}
                                            </button>
                                            <button
                                                className="cq-pipeline-action-btn delete"
                                                title="Delete Pipeline"
                                                onClick={(e) => handleDeletePipeline(e, pipeline.id)}
                                            >
                                                {icons?.DELETE || 'Del'}
                                            </button>
                                        </div>
                                        <span className="cq-pipeline-arrow">
                                            {isExpanded ? '▼' : '▶'}
                                        </span>
                                    </div>
                                </div>

                                {/* Inline Stage Editor */}
                                {isExpanded && modifiedPipeline && (
                                    <div className="cq-pipeline-inline-content">
                                        <StageEditor
                                            pipeline={modifiedPipeline}
                                            onUpdate={(updatedPipeline) => {
                                                setModifiedPipeline(updatedPipeline);
                                            }}
                                            onAutoSave={handleStagesAutoSave}
                                            onAddStage={handleStageCreate}
                                            onDeleteStage={handleStageDelete}
                                        />
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
            <ConfirmationModal
                {...confirmationModal}
                onClose={() => setConfirmationModal(prev => ({ ...prev, isOpen: false }))}
            />
        </div >
    );
};

export default PipelineManager;
