import React, { useState } from 'react';
import ActivityDetails from './ActivityDetails';
import { icons } from '../../../../Constants/svg';

const ActivityLead = ({ activity, formatTime }) => {
    const [expanded, setExpanded] = useState(false);
    const isCreation = activity.activity_type.includes('create') ||
        activity.activity_type.includes('add') ||
        (activity.title && activity.title.toLowerCase().includes('created'));

    const isLeadCreated = activity.activity_type === 'lead_created';
    // Identify stage changes. Assuming title convention "Moved to..." holds or we can check data.
    // Based on user request/image, title starts with "Moved to"
    const isStageChange = activity.title && activity.title.startsWith('Moved to');
    const isLeadUpdated = activity.activity_type === 'lead_updated';

    // Lead creation, stage changes, and lead updates should be non-collapsible (no chevron)
    const isNonCollapsible = isLeadCreated || isStageChange || isLeadUpdated;

    return (
        <div className={`cq-feed-item ${activity.activity_type}`}>
            <div className="cq-feed-main">
                <div
                    className="cq-feed-header"
                    onClick={() => !isNonCollapsible && setExpanded(!expanded)}
                    style={{
                        cursor: isNonCollapsible ? 'default' : 'pointer',
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center'
                    }}
                >
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-title">{activity.title}</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-time">{formatTime(activity.timestamp)}</span>
                        {!isNonCollapsible && (
                            <span
                                style={{
                                    transition: 'transform 0.2s',
                                    transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
                                    display: 'flex',
                                    alignItems: 'center'
                                }}
                            >
                                {icons.DROPDOWN_CHEVRON}
                            </span>
                        )}
                    </div>
                </div>

                {isStageChange && activity.description && (
                    <div
                        className="cq-feed-desc"
                        style={{ marginTop: '0px', marginBottom: '4px', color: '#667781', fontSize: '13px' }}
                        dangerouslySetInnerHTML={{ __html: activity.description }}
                    />
                )}

                {isLeadUpdated && activity.description && (
                    <div
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '4px',
                            cursor: 'pointer',
                            marginTop: '0px',
                            marginBottom: '4px'
                        }}
                        onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
                    >
                        <div
                            className="cq-feed-desc"
                            style={{
                                marginTop: '0',
                                marginBottom: '0',
                                color: '#667781',
                                fontSize: '13px'
                            }}
                            dangerouslySetInnerHTML={{ __html: activity.description }}
                        />

                        {activity.details && Object.keys(activity.details).length > 0 && (
                            <span
                                style={{
                                    transition: 'transform 0.2s',
                                    transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    marginBottom: '2px', // Visual alignment
                                    marginTop: '2px'
                                }}
                            >
                                {icons.DROPDOWN_CHEVRON}
                            </span>
                        )}
                    </div>
                )}



                {(expanded || (isLeadCreated && !isLeadUpdated)) && !isNonCollapsible && (
                    <div className="cq-feed-content">
                        <div className="cq-feed-desc" dangerouslySetInnerHTML={{ __html: activity.description }} />

                        <ActivityDetails details={activity.details} hideOldValue={isCreation} />

                        {activity.actor && (
                            <div className="cq-feed-actor">by {activity.actor.name}</div>
                        )}
                    </div>
                )}

                {(expanded || (isLeadCreated && !isLeadUpdated)) && isLeadUpdated && (
                    <div className="cq-feed-content" style={{ marginTop: '0' }}>
                        <ActivityDetails details={activity.details} hideOldValue={false} />
                    </div>
                )}

                {isNonCollapsible && activity.actor && (
                    <div className="cq-feed-actor" style={{ marginLeft: '0px' }}>by {activity.actor.name}</div>
                )}
            </div>
        </div>
    );
};

export default ActivityLead;
