import React from 'react';
import './EmptyState.css';

const EmptyState = ({ icon, heading, description, action }) => {
    return (
        <div className="cq-empty-state">
            {icon && <div className="cq-empty-state-icon">{icon}</div>}
            {heading && <div className="cq-empty-state-heading">{heading}</div>}
            {description && <div className="cq-empty-state-description">{description}</div>}
            {action && (
                <div className="cq-empty-state-action">
                    <button
                        type="button"
                        className="cq-btn-primary"
                        onClick={action.onClick}
                    >
                        {action.label}
                    </button>
                </div>
            )}
        </div>
    );
};

export default EmptyState;
