import React, { useState, useRef, useEffect } from 'react';
import { getActiveChatId } from '../../utils/WppFunctions';
import './SidePanel.css';

export const SidePanelContext = React.createContext({
  setHeaderActions: () => { },
  setPanelTitle: () => { },
  setLeftHeaderAction: () => { },
  chatId: null
});

const SidePanel = ({ children, onClose, title, className = '', monitorChat = false }) => {
  const [headerActions, setHeaderActions] = useState(null);
  const [panelTitle, setPanelTitle] = useState(title);
  const [leftHeaderAction, setLeftHeaderAction] = useState(null);
  const [chatId, setChatId] = useState(null);
  const [isResizing, setIsResizing] = useState(false);
  const panelRef = useRef(null);
  const startXRef = useRef(0);
  const startWidthRef = useRef(0);

  // Sync prop title with state
  useEffect(() => {
    setPanelTitle(title);
  }, [title]);

  const handleMouseDown = (e) => {
    setIsResizing(true);
    startXRef.current = e.clientX;
    const panel = panelRef.current?.closest('.cq-wide-sidepanel');
    if (panel) {
      startWidthRef.current = panel.offsetWidth;
    }
    e.preventDefault();
  };

  useEffect(() => {
    if (!monitorChat) return;

    const checkChat = async () => {
      try {
        const id = await getActiveChatId();
        setChatId(id);
      } catch (error) {
        // Ignore errors
      }
    };

    checkChat();
    const interval = setInterval(checkChat, 250);

    return () => clearInterval(interval);
  }, [monitorChat]);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!isResizing) return;

      const panel = panelRef.current?.closest('.cq-wide-sidepanel');
      if (!panel) return;

      const deltaX = startXRef.current - e.clientX;
      const newWidth = startWidthRef.current + deltaX;
      const viewportWidth = window.innerWidth;

      // Calculate min and max widths as percentages
      const minWidthPx = Math.max(300, viewportWidth * 0.25); // 25% or 300px minimum
      const maxWidthPx = viewportWidth * 0.6; // 60% maximum

      const constrainedWidth = Math.min(Math.max(newWidth, minWidthPx), maxWidthPx);
      const widthPercentage = (constrainedWidth / viewportWidth) * 100;

      panel.style.width = `${widthPercentage}%`;

      // Save the new width to localStorage
      localStorage.setItem('cq-sidepanel-width', `${widthPercentage}%`);
    };

    const handleMouseUp = () => {
      setIsResizing(false);
    };

    if (isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'ew-resize';
      document.body.style.userSelect = 'none';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };
  }, [isResizing]);

  return (
    <div ref={panelRef} className={`cq-side-panel ${className}`}>
      <div className="cq-side-panel-resizer" onMouseDown={handleMouseDown}>
        <div className="cq-side-panel-resizer-dots">
          <div className="cq-resizer-dot"></div>
          <div className="cq-resizer-dot"></div>
          <div className="cq-resizer-dot"></div>
        </div>
      </div>
      <div className="cq-side-panel-header" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>

        {/* Left Action Area */}
        {leftHeaderAction && (
          <div className="cq-side-panel-left-action">
            {leftHeaderAction}
          </div>
        )}

        {/* Title Area - Flexible */}
        <div style={{ flex: 1, minWidth: 0, display: 'flex', alignItems: 'center' }}>
          {/* If title is a string, render h3, otherwise render component directly */}
          {typeof panelTitle === 'string' ? (
            <h3 className="cq-side-panel-title" style={{ margin: 0, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {panelTitle}
            </h3>
          ) : (
            panelTitle
          )}
        </div>

        {/* Right Actions Area */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
          {headerActions && <div className="cq-side-panel-actions">{headerActions}</div>}
          {onClose && (
            <button
              className="cq-side-panel-close"
              onClick={onClose}
              aria-label="Close panel"
            >
              ×
            </button>
          )}
        </div>
      </div>
      <div className="cq-side-panel-content">
        <SidePanelContext.Provider value={React.useMemo(() => ({
          setHeaderActions,
          setPanelTitle,
          setLeftHeaderAction,
          chatId
        }), [setHeaderActions, setPanelTitle, setLeftHeaderAction, chatId])}>
          {children}
        </SidePanelContext.Provider>
      </div>
    </div >
  );
};

export default SidePanel;