import React from 'react';

const UpcomingTasksWidget = ({ tasks, loading, hasMore, onLoadMore, onToggleTask }) => {

    const getTaskDateDisplay = (dateStr) => {
        if (!dateStr) return { text: '', color: '#6b7280' };

        try {
            const date = new Date(dateStr);
            if (isNaN(date.getTime())) return { text: 'Invalid Date', color: '#6b7280' };

            const now = new Date();
            const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
            const taskDate = new Date(date.getFullYear(), date.getMonth(), date.getDate());

            const diffTime = taskDate - today;
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            const day = String(date.getDate()).padStart(2, '0');
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const year = date.getFullYear();
            const formattedDate = `${day}/${month}/${year}`;

            if (diffDays === 0) {
                return { text: 'Today', color: '#10b981', fontWeight: '500' }; // Green
            } else if (diffDays < 0) {
                return { text: formattedDate, color: '#ef4444' }; // Red
            } else {
                return { text: formattedDate, color: '#6b7280' }; // Grey
            }
        } catch (e) {
            console.error('Error parsing date:', dateStr, e);
            return { text: '', color: '#6b7280' };
        }
    };

    return (
        <div className="cq-list-widget">
            <div className="cq-list-header">
                <h3>Upcoming Tasks</h3>
            </div>
            <div className="cq-list-body" style={{ overflowY: 'auto', maxHeight: '300px' }}>
                {loading && (!Array.isArray(tasks) || tasks.length === 0) ? (
                    <div className="cq-loading-spinner"></div>
                ) : (!Array.isArray(tasks) || tasks.length === 0) ? (
                    <div className="cq-empty-list">No upcoming tasks.</div>
                ) : (
                    <>
                        {tasks.map((task, idx) => {
                            if (!task) return null;
                            const { text, color, fontWeight } = getTaskDateDisplay(task?.due_at);
                            const taskKey = task.id || `task-${idx}`;

                            return (
                                <div key={taskKey} className="cq-list-item" style={{ justifyContent: 'flex-start', alignItems: 'flex-start' }}>
                                    <div
                                        className="cq-list-item-left"
                                        style={{ marginRight: '16px', paddingTop: '4px' }}
                                    >
                                        <input
                                            type="checkbox"
                                            checked={!!task.is_completed}
                                            onChange={() => onToggleTask(task)}
                                            style={{ cursor: 'pointer', width: '18px', height: '18px', accentColor: '#3b82f6' }}
                                        />
                                    </div>
                                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                                        <span className={`cq-item-title ${task.is_completed ? 'cq-item-title-completed' : ''}`} style={{
                                            fontSize: '14px',
                                            lineHeight: '1.4'
                                        }}>
                                            {task.title || 'Untitled Task'}
                                        </span>
                                        <span style={{
                                            color: color,
                                            fontSize: '13px',
                                            fontWeight: fontWeight || '400',
                                            marginTop: '2px'
                                        }}>
                                            {text}
                                        </span>
                                    </div>
                                </div>
                            );
                        })}
                        {loading && <div className="cq-loading-spinner"></div>}
                        {!loading && hasMore && (
                            <div style={{ textAlign: 'center', padding: '8px' }}>
                                <button
                                    className="cq-btn-xs"
                                    onClick={onLoadMore}
                                >
                                    Load More
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
};

export default UpcomingTasksWidget;
