import React from 'react';
import { PieChart, Pie, Cell, Legend, ResponsiveContainer } from 'recharts';
import ReactDOM from 'react-dom';

const LeadSourceChart = ({ stats }) => {

    const pieColors = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#AF19FF'];
    const sourceData = (Array.isArray(stats?.lead_source_breakdown?.sources) ? stats.lead_source_breakdown.sources : []).map((s, index) => ({
        name: s?.source || 'Unknown',
        value: s?.count || 0
    }));

    const [hoverData, setHoverData] = React.useState(null);
    const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 });

    const handleMouseEnter = (data, index, e) => {
        setHoverData(data);
        if (e && e.clientX) setTooltipPos({ x: e.clientX, y: e.clientY });
    };

    const handleMouseMove = (data, index, e) => {
        if (e && e.clientX) setTooltipPos({ x: e.clientX, y: e.clientY });
    };

    const handleMouseLeave = () => {
        setHoverData(null);
    };

    const chartRef = React.useRef(null);

    React.useEffect(() => {
        if (!hoverData) return;

        const handleGlobalMouseMove = (e) => {
            if (!chartRef.current) return;
            const rect = chartRef.current.getBoundingClientRect();
            const margin = 20; // Extra buffer

            if (
                e.clientX < rect.left - margin ||
                e.clientX > rect.right + margin ||
                e.clientY < rect.top - margin ||
                e.clientY > rect.bottom + margin
            ) {
                setHoverData(null);
            }
        };

        window.addEventListener('mousemove', handleGlobalMouseMove);
        return () => window.removeEventListener('mousemove', handleGlobalMouseMove);
    }, [hoverData]);

    const TooltipPortal = ({ children }) => {
        return ReactDOM.createPortal(children, document.body);
    };

    return (
        <div className="cq-chart-card">
            <div className="cq-chart-header">
                <h3 className="cq-chart-title">Lead Source Breakdown</h3>
            </div>
            <div className="cq-chart-body"
                ref={chartRef}
                style={{ height: '300px', position: 'relative', width: '100%' }}
                onMouseLeave={handleMouseLeave}
            >
                {sourceData.length > 0 ? (
                    <ResponsiveContainer width="100%" height={300} minWidth={100} minHeight={100} debounce={0}>
                        <PieChart onMouseLeave={handleMouseLeave}>
                            <Pie
                                data={sourceData}
                                cx="50%"
                                cy="45%"
                                labelLine={false}
                                label={false}
                                outerRadius={80}
                                fill="#8884d8"
                                dataKey="value"
                                nameKey="name"
                                animationDuration={800}
                                onMouseEnter={handleMouseEnter}
                                onMouseLeave={handleMouseLeave}
                                onMouseMove={handleMouseMove}
                            >
                                {sourceData.map((entry, index) => (
                                    <Cell
                                        key={`cell-${index}`}
                                        fill={pieColors[index % pieColors.length]}
                                        style={{ outline: 'none', cursor: 'pointer', pointerEvents: 'all' }}
                                    />
                                ))}
                            </Pie>
                            <Legend
                                layout="horizontal"
                                verticalAlign="bottom"
                                align="center"
                                wrapperStyle={{ paddingTop: '20px' }}
                            />
                        </PieChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="cq-empty-chart">
                        <span>No data available</span>
                    </div>
                )}

                {hoverData && (
                    <TooltipPortal>
                        <div style={{
                            position: 'fixed',
                            left: tooltipPos.x + 15,
                            top: tooltipPos.y + 15,
                            backgroundColor: '#fff',
                            color: '#1f2937',
                            border: '1px solid #e5e7eb',
                            padding: '8px 12px',
                            borderRadius: '6px',
                            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                            fontSize: '13px',
                            fontWeight: 500,
                            zIndex: 2147483647,
                            pointerEvents: 'none',
                            whiteSpace: 'nowrap'
                        }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                                <div style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: hoverData.payload?.fill || hoverData.fill }}></div>
                                <span>{hoverData.name}: {hoverData.value}</span>
                            </div>
                        </div>
                    </TooltipPortal>
                )}
            </div>
        </div>
    );
};

export default LeadSourceChart;
