import React, { useEffect, useState, useRef } from 'react';
import { icons } from '../../../Constants/svg';
import './Toast.css';

const Toast = ({
    id,
    message,
    type = 'success', // success, error, info, warning
    duration, // milliseconds. If null/undefined, toast does not auto-dismiss
    onClose,
    actions = [], // Array of { label, onClick, primary: boolean }
    showProgress = true
}) => {
    const [isExiting, setIsExiting] = useState(false);
    const progressRef = useRef(null);
    const startTimeRef = useRef(null);
    const timerRef = useRef(null);
    const animationFrameRef = useRef(null);

    // Icons map
    const typeIcons = {
        success: icons.CHECK_CIRCLE || <span>✓</span>,
        error: icons.ALERT_CIRCLE || <span>!</span>,
        info: icons.INFO || <span>i</span>,
        warning: icons.ALERT_TRIANGLE || <span>⚠</span>
    };

    const handleClose = () => {
        setIsExiting(true);
        // Wait for animation to finish before calling onClose
        setTimeout(() => {
            onClose(id);
        }, 300); // Matches CSS animation duration
    };

    const handleAction = (action) => {
        if (action.onClick) {
            action.onClick();
        }
        handleClose();
    };

    useEffect(() => {
        // Only set up auto-dismiss if duration is provided
        if (duration) {
            startTimeRef.current = Date.now();

            const tick = () => {
                if (!progressRef.current) return;
                const elapsed = Date.now() - startTimeRef.current;
                const remaining = Math.max(0, duration - elapsed);
                const percentage = (remaining / duration) * 100;

                progressRef.current.style.width = `${percentage}%`;

                if (remaining > 0) {
                    animationFrameRef.current = requestAnimationFrame(tick);
                } else {
                    handleClose();
                }
            };

            animationFrameRef.current = requestAnimationFrame(tick);

            // Backup timer just in case
            timerRef.current = setTimeout(handleClose, duration);
        }

        return () => {
            if (timerRef.current) clearTimeout(timerRef.current);
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
        };
    }, [duration]);

    // Icon for the type
    const Icon = typeIcons[type] || typeIcons.info;

    return (
        <div className={`cq-toast ${type} ${isExiting ? 'exiting' : ''}`} role="alert">
            <div className="cq-toast-content">
                <div className={`cq-toast-icon ${type}`}>
                    {Icon}
                </div>
                <div className="cq-toast-body">
                    <div className="cq-toast-message">{message}</div>
                    {actions.length > 0 && (
                        <div className="cq-toast-actions">
                            {actions.map((action, idx) => (
                                <button
                                    key={idx}
                                    className={`cq-toast-action-btn ${action.primary ? 'primary' : ''}`}
                                    onClick={() => handleAction(action)}
                                >
                                    {action.label}
                                </button>
                            ))}
                        </div>
                    )}
                </div>
                <button
                    className="cq-toast-close"
                    onClick={handleClose}
                    aria-label="Close"
                >
                    {icons.CROSS || '×'}
                </button>
            </div>

            {/* Progress Bar - Only valid if duration is set */}
            {duration && showProgress && (
                <div className="cq-toast-progress-container">
                    <div
                        ref={progressRef}
                        className="cq-toast-progress-bar"
                        style={{ width: '100%' }} // Put initial width to 100%
                    />
                </div>
            )}
        </div>
    );
};

export default Toast;
