import React, { useState } from 'react';
import './Dashboard.css';
import AnalyticsTab from './AnalyticsTab';
import KanbanTab from './KanbanTab';

import { icons } from '../../../Constants/svg';
import { ToastManager, showToast } from '../../UIComponents/Toast/ToastManager';

const DashboardContainer = ({ onLeadClick }) => {
    const [activeTab, setActiveTab] = useState('overview'); // 'overview' | 'pipeline'
    const [pipelineList, setPipelineList] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedPipelineId, setSelectedPipelineId] = useState('');
    const [dateRange, setDateRange] = useState('30_days');
    const [customRange, setCustomRange] = useState({ start: '', end: '' });
    const [isVisible, setIsVisible] = useState(true);
    const [currencyList, setCurrencyList] = useState({});
    const [selectedCurrency, setSelectedCurrency] = useState('USD');
    const [exchangeRates, setExchangeRates] = useState({});

    const [statsCurrencies, setStatsCurrencies] = useState([]);

    React.useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'DASHBOARD_VISIBILITY_CHANGE') {
                setIsVisible(!!payload.isVisible);
            } else if (type === 'PIPELINES_LIST') {
                const data = payload;
                const list = Array.isArray(data) ? data : (data.pipelines || data.results || []);

                setPipelineList(list);

                setSelectedPipelineId(prevId => {
                    // If we have a selected ID and it's still in the list, keep it
                    if (prevId && list.some(p => p.id === prevId)) {
                        return prevId;
                    }
                    // Otherwise, pick default or first one
                    const defaultPipe = list.find(p => p.is_default) || list[0];
                    return defaultPipe ? defaultPipe.id : '';
                });

                setLoading(false);
            } else if (type === 'PIPELINES_LIST_ERROR') {
                console.error('Failed to fetch pipelines:', payload.error);
                setLoading(false);
            } else if (type === 'CURRENCY_DATA') {
                const { list, rates, localCurrency } = payload;
                setCurrencyList(list || {});
                setExchangeRates(rates || {});
                if (localCurrency) {
                    setSelectedCurrency(prev => prev === 'USD' ? localCurrency.toLowerCase() : prev);
                }
            } else if (type === 'DASHBOARD_STATS_GET_SUCCESS') {
                if (payload?.pipeline_value?.values) {
                    const currencies = payload.pipeline_value.values.map(v => v.currency.toLowerCase());
                    setStatsCurrencies(currencies);
                }
            }
        };

        window.addEventListener('message', handleMessage);

        // Fetch pipelines
        window.postMessage({ type: 'GET_PIPELINES', payload: {} }, '*');
        // Fetch currency data
        window.postMessage({ type: 'GET_CURRENCY_DATA' }, '*');

        return () => window.removeEventListener('message', handleMessage);
    }, []);

    // Refresh pipelines when dashboard becomes visible
    React.useEffect(() => {
        if (isVisible) {
            window.postMessage({ type: 'GET_PIPELINES', payload: {} }, '*');
            window.postMessage({ type: 'GET_CURRENCY_DATA' }, '*');
        }
    }, [isVisible]);

    const handleDateRangeChange = (e) => {
        const value = e.target.value;
        setDateRange(value);

        if (value === 'custom') {
            const today = new Date();
            const year = today.getFullYear();
            const month = String(today.getMonth() + 1).padStart(2, '0');
            const day = String(today.getDate()).padStart(2, '0');
            const todayStr = `${year}-${month}-${day}`;
            setCustomRange({ start: todayStr, end: todayStr });
        }
    };

    const handleCustomDateChange = (type, value) => {
        // value is 'YYYY-MM-DD' from the date input

        // Get today's local date string for comparison
        const today = new Date();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        const todayStr = `${year}-${month}-${day}`;

        if (value > todayStr) {
            showToast({ message: 'Date cannot be in the future', type: 'error', duration: 3000 });
            return;
        }

        if (type === 'end' && customRange.start) {
            if (value < customRange.start) {
                showToast({ message: 'End date cannot be smaller than start date', type: 'error', duration: 3000 });
                return;
            }
        }

        if (type === 'start' && customRange.end) {
            // "End date cannot be smaller than start date" implies Start cannot be larger than End
            if (value > customRange.end) {
                showToast({ message: 'Start date cannot be after end date', type: 'error', duration: 3000 });
                return;
            }
        }

        setCustomRange(prev => ({ ...prev, [type]: value }));
    };

    const selectedPipeline = pipelineList.find(p => p.id === selectedPipelineId);

    // Calculate today's string for max attribute
    const today = new Date();
    const maxDate = today.toISOString().split('T')[0];

    if (loading) {
        return <div className="cq-dashboard-container" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}>Loading...</div>;
    }

    return (
        <ToastManager>
            <div className="cq-dashboard-container">
                {/* TOP BAR */}
                <div className="cq-dashboard-top-bar">
                    <h2 className="cq-dashboard-title">CRM Dashboard</h2>

                    <div className="cq-global-filters">
                        {/* Currency Selector */}
                        <div className="cq-filter-group">
                            <label>Currency</label>
                            <div className="cq-select-wrapper custom-currency-select">
                                <div className="cq-select-display">
                                    {selectedCurrency.toUpperCase()}
                                </div>
                                <select
                                    value={selectedCurrency}
                                    onChange={(e) => {
                                        const newVal = e.target.value;
                                        setSelectedCurrency(newVal);
                                        if (statsCurrencies.includes(newVal.toLowerCase())) {
                                            localStorage.setItem('CQ_LOCAL_CURRENCY', newVal);
                                        }
                                    }}
                                    className="cq-dashboard-select transparent-select"
                                >
                                    {Object.keys(currencyList).length > 0 ? (
                                        Object.entries(currencyList).map(([code, name]) => (
                                            <option key={code} value={code}>{code.toUpperCase()} - {name}</option>
                                        ))
                                    ) : (
                                        <option value="usd">USD</option>
                                    )}
                                </select>
                                <span className="cq-select-arrow">{icons.DROPDOWN_CHEVRON}</span>
                            </div>
                        </div>

                        {/* Pipeline Selector */}
                        <div className="cq-filter-group">
                            <label>Pipeline</label>
                            <div className="cq-select-wrapper">
                                <select
                                    value={selectedPipelineId}
                                    onChange={(e) => setSelectedPipelineId(e.target.value)}
                                    className="cq-dashboard-select"
                                >
                                    {pipelineList.map(p => (
                                        <option key={p.id} value={p.id}>{p.name}</option>
                                    ))}
                                </select>
                                <span className="cq-select-arrow">{icons.DROPDOWN_CHEVRON}</span>
                            </div>
                        </div>

                        {/* Date Range (Only for Analytics) */}
                        {activeTab === 'overview' && (
                            <div className="cq-filter-group">
                                <label>Timeframe</label>
                                <div className="cq-select-wrapper">
                                    <select
                                        value={dateRange}
                                        onChange={handleDateRangeChange}
                                        className="cq-dashboard-select"
                                    >
                                        <option value="7_days">Last 7 Days</option>
                                        <option value="14_days">Last 14 Days</option>
                                        <option value="30_days">This Month</option>
                                        <option value="3_months">Last 3 Months</option>
                                        <option value="custom">Custom Range</option>
                                    </select>
                                    <span className="cq-select-arrow">{icons.DROPDOWN_CHEVRON}</span>
                                </div>
                                {dateRange === 'custom' && (
                                    <div className="cq-custom-date-inputs">
                                        <input
                                            type="date"
                                            className="cq-date-input"
                                            value={customRange.start}
                                            max={maxDate}
                                            onChange={(e) => handleCustomDateChange('start', e.target.value)}
                                        />
                                        <span style={{ color: '#9ca3af', alignSelf: 'center' }}>-</span>
                                        <input
                                            type="date"
                                            className="cq-date-input"
                                            value={customRange.end}
                                            min={customRange.start}
                                            max={maxDate}
                                            onChange={(e) => handleCustomDateChange('end', e.target.value)}
                                        />
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {/* NAVIGATION TABS */}
                <div className="cq-dashboard-tabs">
                    <button
                        className={`cq-tab-btn ${activeTab === 'overview' ? 'active' : ''}`}
                        onClick={() => setActiveTab('overview')}
                    >
                        Overview
                    </button>
                    <button
                        className={`cq-tab-btn ${activeTab === 'pipeline' ? 'active' : ''}`}
                        onClick={() => setActiveTab('pipeline')}
                    >
                        Pipeline
                    </button>
                </div>

                {/* CONTENT AREA */}
                <div className="cq-dashboard-content">
                    {activeTab === 'overview' ? (
                        <AnalyticsTab
                            pipelineId={selectedPipelineId}
                            pipeline={selectedPipeline}
                            dateRange={dateRange}
                            customRange={customRange}
                            isVisible={isVisible}
                            currency={selectedCurrency}
                            exchangeRates={exchangeRates}
                        />
                    ) : (
                        <KanbanTab
                            pipelineId={selectedPipelineId}
                            pipeline={selectedPipeline}
                            onLeadClick={(lead) => onLeadClick({
                                ...lead,
                                pipeline_id: lead.pipeline_id || selectedPipelineId
                            }, pipelineList)}
                        />
                    )}
                </div>
            </div>
        </ToastManager>
    );
};

export default DashboardContainer;
