import React, { useState, useEffect, useRef } from 'react';
import { icons } from '../../Constants/svg';
import ClickToEditInput from '../UIComponents/ClickToEditInput';
import InputBox from '../UIComponents/InputBox';
import Select from '../UIComponents/Select';
import LeadActivity from './LeadDetails/LeadActivity';
import LeadTasks from './LeadDetails/LeadTasks';
import LeadStages from './LeadDetails/LeadStages';
import LeadPeople from './LeadDetails/LeadPeople';
import WonLostModal from './LeadDetails/WonLostModal';
import { useToast } from '../UIComponents/Toast/ToastManager';
import ConfirmationModal from '../UIComponents/ConfirmationModal';
import { postWindowMessage } from '../../utils/messageSender';
import { CURRENCY_OPTIONS, PRIORITY_OPTIONS } from '../../Constants/constant';
import './LeadDetailsPanel.css';

const TABS = [
    { id: 'activity', label: 'Activity' },
    { id: 'details', label: 'Details' },
    { id: 'tasks', label: 'Tasks' },
    { id: 'people', label: 'People' }
];


const LeadDetailsPanel = ({ lead, pipelines = [], onUpdate, onBack }) => {
    const [activeTab, setActiveTab] = useState('activity');
    const [localLead, setLocalLead] = useState(lead);
    const activityRef = useRef(null);
    const { addToast } = useToast();

    const [refreshTrigger, setRefreshTrigger] = useState(0);

    // Get stages for current lead's pipeline
    const currentPipeline = pipelines.find(p => p.id === localLead.pipeline_id || p.id === localLead.pipelineId);
    const stages = currentPipeline ? currentPipeline.stages : [];

    // Won/Lost Modal State
    const [modalState, setModalState] = useState({
        isOpen: false,
        type: 'won', // 'won' or 'lost'
        pendingStage: null
    });

    const [deleteModalOpen, setDeleteModalOpen] = useState(false);

    const handleDeleteLead = () => {
        postWindowMessage('LEAD_DELETE', { lead_id: localLead.id });
        setDeleteModalOpen(false);
        if (onBack) onBack(); // Optimistically go back
    };

    useEffect(() => {
        setLocalLead(lead);
    }, [lead]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'LEAD_UPDATE_SUCCESS') {
                const updatedLead = payload;
                if (updatedLead && (updatedLead.id == localLead.id)) {
                    setRefreshTrigger(prev => prev + 1);
                }
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [localLead.id]);

    if (!localLead) return null;

    const handleFieldSave = (field, value) => {
        const updatedLead = { ...localLead, [field]: value };
        setLocalLead(updatedLead);
        // Propagate to parent
        if (onUpdate) {
            onUpdate(localLead.id, { [field]: value });
        }
    };

    const handleStageClick = (stageObj) => {
        const newStageName = stageObj.name;
        const newProbability = stageObj.probability;
        const previousStageName = localLead.pipeline;
        const previousProbability = localLead.probability;

        // If clicking same stage, do nothing
        if (newStageName === previousStageName) return;

        // Check for Won (100%) or Lost (0%) to trigger Modal
        if (newProbability === 100 || newProbability === 0) {
            setModalState({
                isOpen: true,
                type: newProbability === 100 ? 'won' : 'lost',
                pendingStage: newStageName,
                pendingProbability: newProbability,
                pendingStageId: stageObj.id
            });
            return;
        }

        // Normal Stage Change
        updateStage(newStageName, newProbability, previousStageName, previousProbability, stageObj.id);
    };

    const updateStage = (newStageName, newProbability, previousStageName, previousProbability, stageId) => {
        const updates = {
            pipeline: newStageName,
            probability: `${newProbability}%`,
            stageId: stageId,
            stage_id: stageId // Sync stage_id for Stepper
        };

        // Apply updates locally and propagate
        const updatedLead = { ...localLead, ...updates };
        setLocalLead(updatedLead);
        if (onUpdate) {
            onUpdate(localLead.id, updates);
        }





        // Show Toast with Undo
        const oldStageId = localLead.stageId || localLead.stage_id;

    };

    const handleModalSave = (data) => {
        const newStageName = modalState.pendingStage;
        const newProbability = modalState.pendingProbability;
        const newStageId = modalState.pendingStageId;

        // Update with extra data (value or reason)
        const updates = {
            pipeline: newStageName,
            probability: `${newProbability}%`,
            stageId: newStageId,
            stage_id: newStageId // Sync stage_id for Stepper
        };

        if (newProbability === 100 && data.value) {
            updates.expectedValue = data.value;
        } else if (newProbability === 0 && data.reason) {
            updates.meta = {
                ...(localLead.meta || {}),
                lost_reason: data.reason
            };
        }

        // Apply updates
        const updatedLead = { ...localLead, ...updates };
        setLocalLead(updatedLead);
        if (onUpdate) {
            onUpdate(localLead.id, updates);
        }


    };
    const currency = localLead.currencyType ? `${localLead.currencyType} ` : 'INR';
    const valueDisplay = `${currency}${localLead.expectedValue || '0'}`;

    return (
        <div className="cq-lead-details-panel">
            {/* Scrollable Content Area */}
            <div className="cq-scrollable-content">

                {/* Pipeline Stepper */}
                <LeadStages
                    lead={localLead}
                    stages={stages}
                    pipelineName={currentPipeline ? currentPipeline.name : ''}
                    onStageChange={handleStageClick}
                />

                {/* Zone B: Highlights Bar */}
                <div className="cq-highlights-bar">
                    <div className="cq-highlight-item">
                        <span className="cq-highlight-label">Value</span>
                        <ClickToEditInput
                            value={valueDisplay}
                            className="cq-highlight-value"
                            onEditEnd={() => {
                                if (
                                    onUpdate &&
                                    (
                                        localLead.currencyType !== lead.currencyType ||
                                        localLead.expectedValue !== lead.expectedValue
                                    )
                                ) {
                                    onUpdate(localLead.id, {
                                        currencyType: localLead.currencyType,
                                        expectedValue: localLead.expectedValue
                                    });
                                }
                            }}
                            customEditor={({ stopEditing }) => (
                                <div className="cq-combined-input" style={{ marginTop: '2px' }}>
                                    <div style={{ width: '50px' }}>
                                        <Select
                                            options={CURRENCY_OPTIONS.map(c => ({ label: c, value: c }))}
                                            value={localLead.currencyType || 'INR'}
                                            onChange={(val) => {
                                                setLocalLead(prev => ({ ...prev, currencyType: val }));
                                                if (onUpdate) {
                                                    onUpdate(localLead.id, {
                                                        currencyType: val,
                                                        expectedValue: localLead.expectedValue
                                                    });
                                                }
                                                stopEditing();
                                            }}
                                            placeholder="CUR"
                                            menuPlacement="auto"
                                        />
                                    </div>
                                    <InputBox
                                        value={localLead.expectedValue}
                                        onChange={(e) => {
                                            const val = e.target.value;
                                            setLocalLead(prev => ({ ...prev, expectedValue: val }));
                                        }}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter') {
                                                stopEditing(true);
                                                // onEditEnd prop on wrapper will handle the save
                                            }
                                            if (e.key === 'Escape') {
                                                stopEditing();
                                            }
                                        }}
                                        autoFocus
                                        placeholder="0.00"
                                        type="number"
                                    />
                                </div>
                            )}
                        />
                    </div>
                    <div className="cq-highlight-item">
                        <span className="cq-highlight-label">Priority</span>
                        <ClickToEditInput
                            value={localLead.priority || 'HOT'}
                            displayValue={localLead.priority || 'HOT'}
                            className="cq-highlight-value"
                            customEditor={({ stopEditing }) => (
                                <div style={{ minWidth: '100px', marginTop: '2px' }}>
                                    <Select
                                        options={PRIORITY_OPTIONS.map(p => ({ label: p, value: p }))}
                                        value={localLead.priority ? localLead.priority.toUpperCase() : 'HOT'}
                                        onChange={(val) => {
                                            handleFieldSave('priority', val);
                                            stopEditing();
                                        }}
                                        autoFocus
                                        menuPlacement="auto"
                                        placeholder="Select Priority"
                                    />
                                </div>
                            )}
                        />
                    </div>
                    <div className="cq-highlight-item">
                        <span className="cq-highlight-label">Close Date</span>
                        <ClickToEditInput
                            value={(localLead.expectedClose || localLead.closingDate || '').split('T')[0]}
                            displayValue={((val) => {
                                if (!val) return '';
                                const [y, m, d] = val.split('T')[0].split('-');
                                return `${d}/${m}/${y}`;
                            })(localLead.expectedClose || localLead.closingDate)}
                            onSave={(val) => handleFieldSave('closingDate', val)}
                            placeholder="Set Date"
                            className="cq-highlight-value"
                            type="date"
                            inputProps={{
                                min: new Date().toISOString().split('T')[0],
                                onFocus: (e) => e.target.showPicker && e.target.showPicker(),
                                onChange: (e) => e.target.blur()
                            }}
                        />
                    </div>
                </div>

                {/* Zone C: Tabbed Workspace */}
                <div className="cq-tabs-container">
                    <div className="cq-tabs-nav">
                        {TABS.map(tab => (
                            <button
                                key={tab.id}
                                className={`cq-tab-btn ${activeTab === tab.id ? 'active' : ''}`}
                                onClick={() => setActiveTab(tab.id)}
                            >
                                {tab.label}
                            </button>
                        ))}
                    </div>

                    <div className="cq-tab-content">
                        {activeTab === 'activity' && (
                            <LeadActivity
                                ref={activityRef}
                                leadId={localLead.id}
                                refreshTrigger={refreshTrigger}
                            />
                        )}

                        {activeTab === 'details' && (
                            <div className="cq-details-form">
                                <div className="cq-form-group">
                                    <span className="cq-lead-label">Source</span>
                                    <ClickToEditInput
                                        value={localLead.source || ''}
                                        onSave={(val) => {
                                            if (val && val.trim() !== '') {
                                                handleFieldSave('source', val);
                                            } else {
                                                addToast({
                                                    message: 'Source value is required',
                                                    type: 'error',
                                                    duration: 3000
                                                });
                                            }
                                        }}
                                        placeholder="Add source..."
                                    />
                                </div>
                                {/* <div className="cq-form-group">
                                    <span className="cq-lead-label">Description</span>
                                    <ClickToEditInput
                                        value={localLead.description}
                                        onSave={(val) => handleFieldSave('description', val)}
                                        placeholder="Add description..."
                                    />
                                </div> */}
                                <div className="cq-form-group">
                                    <span className="cq-lead-label">Probability</span>
                                    <div
                                        className="cq-highlight-value"
                                        style={{
                                            padding: '4px 6px',
                                            minHeight: '28px',
                                            display: 'flex',
                                            alignItems: 'center',
                                            cursor: 'not-allowed',
                                            opacity: 0.7
                                        }}
                                    >
                                        {((val) => {
                                            if (val === undefined || val === null || val === '') return '50%';
                                            const num = String(val).replace('%', '');
                                            return `${num}%`;
                                        })(localLead.probability !== undefined ? localLead.probability : localLead.stageProbability)}
                                    </div>
                                </div>
                            </div>
                        )}

                        {activeTab === 'tasks' && (
                            <LeadTasks leadId={localLead.id} />
                        )}

                        {activeTab === 'people' && (
                            <LeadPeople leadId={localLead.id} />
                        )}
                    </div>
                </div>
            </div >

            {activeTab === 'details' && (
                <div className="cq-lead-delete-float">
                    <button
                        className="cq-btn-icon-danger shake-on-hover"
                        onClick={() => setDeleteModalOpen(true)}
                        title="Delete Lead"
                    >
                        {icons.DELETE}
                    </button>
                </div>
            )}

            <WonLostModal
                isOpen={modalState.isOpen}
                onClose={() => setModalState(prev => ({ ...prev, isOpen: false }))}
                type={modalState.type}
                leadValue={localLead.expectedValue}
                onSave={handleModalSave}
            />

            <ConfirmationModal
                isOpen={deleteModalOpen}
                onClose={() => setDeleteModalOpen(false)}
                onConfirm={handleDeleteLead}
                title="Delete Lead"
                message="Are you sure you want to delete this lead? This action cannot be undone."
                confirmText="Delete"
                confirmButtonStyle="danger"
            />
        </div >
    );
};

export default LeadDetailsPanel;
