import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { icons } from '../../Constants/svg';
import Icon from '../UIComponents/Icon';
import InputBox from '../UIComponents/InputBox';
import TextAreaBox from '../UIComponents/TextAreaBox';
import Select from '../UIComponents/Select';
import { getActiveChatId, getContactName } from '../../utils/WppFunctions';
import { postWindowMessage } from '../../utils/messageSender';
import { isDarkMode } from '../../utils/utils';
import { formatDateTime, formatISODateTime } from '../../utils/dateUtils';
import './ScheduledMessages.css';
import ArtifactIconCard from '../UIComponents/ArtifactIconCard';
import ErrorBoundary from '../UIComponents/ErrorBoundary';

const ScheduledMessages = ({ isOpen, chatId: initialChatId }) => {
  const isDark = isDarkMode();

  // Separate arrays like Reminders pattern
  const [pendingMessages, setPendingMessages] = useState([]);
  const [processedMessages, setProcessedMessages] = useState([]);
  const [currentChatId, setCurrentChatId] = useState(initialChatId);
  const [isLoading, setIsLoading] = useState(false);
  const [editingId, setEditingId] = useState(null);

  // Pagination state - separate loading states like ChatTodo
  const [pendingPage, setPendingPage] = useState(1);
  const [processedPage, setProcessedPage] = useState(1);
  const [isPendingLoadingMore, setIsPendingLoadingMore] = useState(false);
  const [isProcessedLoadingMore, setIsProcessedLoadingMore] = useState(false);
  const [hasMorePending, setHasMorePending] = useState(true);
  const [hasMoreProcessed, setHasMoreProcessed] = useState(true);
  const [pendingNextPageNumber, setPendingNextPageNumber] = useState(null);
  const [processedNextPageNumber, setProcessedNextPageNumber] = useState(null);

  // Collapsible sections state
  const [isPendingOpen, setIsPendingOpen] = useState(true);
  const [isProcessedOpen, setIsProcessedOpen] = useState(false);
  const [processedDataFetched, setProcessedDataFetched] = useState(false);

  const ITEMS_PER_PAGE = 10;

  // View state management like QuickReplyManager
  const [showForm, setShowForm] = useState(false);
  const [formError, setFormError] = useState('');

  const [formData, setFormData] = useState({
    message: '',
    date: '',
    time: '',
    recurrence: '',
    recurrenceType: 'minutes'
  });

  const [isRecurring, setIsRecurring] = useState(false);

  const recurrenceOptions = ['minutes', 'hour', 'day', 'week', 'month', 'year'];

  useEffect(() => {
    const handleMessage = (event) => {
      if (event.source !== window) return;

      const { type, payload } = event.data;
      if ((type == 'CHAT_ARTIFACTS_UPDATED' || type == 'CHAT_ARTIFACT_UPDATE') && payload.chatId === currentChatId && payload.dataType === 'scheduled_messages') {
        handleScheduledMessagesUpdate(payload);
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [currentChatId, handleScheduledMessagesUpdate]);

  const handleScheduledMessagesUpdate = useCallback((payload) => {
    const messages = payload.data;
    const nextUrl = payload.paginationMeta?.next;
    const requestStatus = payload.paginationMeta?.status;

    // Only update UI state if the panel is open (like ChatTodo)
    if (!isOpen || !Array.isArray(messages)) return;

    const transformedMessages = messages.map(message => {
      let messageText = '';
      let metaData = {};

      // main_content contains only the message text
      if (message.main_content) {
        messageText = message.main_content;
      }

      // meta_data follows Reminders.js structure - contains date, time, recurrence, etc.
      if (message.meta_data) {
        metaData = message.meta_data;
      }

      // Get status from message object
      let status = message.status;
      if (!status) {
        // Fallback: determine status based on message date/time and recurrence
        const now = new Date();
        let messageDate;

        if (metaData.nextDue) {
          // For recurring messages, use nextDue
          messageDate = new Date(metaData.nextDue);
        } else if (metaData.date && metaData.time) {
          // For one-time messages, use date and time
          messageDate = new Date(`${metaData.date}T${metaData.time}`);
        } else {
          // Fallback to current time if no valid date
          messageDate = now;
        }

        status = 'pending';
      }

      return {
        id: message.id,
        message: messageText,
        date: metaData.date,
        time: metaData.time,
        nextDue: metaData.nextDue,
        recurrence: metaData.recurrence || 0,
        recurrenceType: metaData.recurrenceType || 'day',
        contactName: metaData.contactName || 'Unknown Contact',
        status: status,
        deliveryStatus: metaData.deliveryStatus, // 'sent' or 'failed'
        failedAt: metaData.failedAt,
        sentAt: metaData.sentAt,
        failureReason: metaData.failureReason,
        createdAt: message.created_at || message.lastUpdated,
        apiId: message.id
      };
    });

    // Determine status from pagination metadata first, then from data (like ChatTodo)
    const dataStatus = transformedMessages.length > 0 ? transformedMessages[0].status : null;
    const effectiveStatus = requestStatus || dataStatus;

    if (effectiveStatus === 'pending' || (!effectiveStatus && (transformedMessages.length === 0 || transformedMessages.every(m => m.status === 'pending')))) {
      // Handle pending messages
      if (isPendingLoadingMore && pendingPage > 1) {
        setPendingMessages(prev => {
          const allMessages = [...prev, ...transformedMessages];
          const deduplicated = Array.from(new Map(allMessages.map(m => [m.apiId || m.id, m])).values());
          return deduplicated;
        });
      } else {
        setPendingMessages(transformedMessages);
        setPendingPage(1);
      }

      if (nextUrl) {
        const url = new URL(nextUrl);
        const pageFromUrl = parseInt(url.searchParams.get('page'), 10);
        setHasMorePending(true);
        setPendingNextPageNumber(pageFromUrl);
      } else {
        setHasMorePending(false);
        setPendingNextPageNumber(null);
      }
      setIsPendingLoadingMore(false);
    } else if (effectiveStatus === 'processed' || (transformedMessages.length > 0 && transformedMessages.every(m => m.status === 'processed'))) {
      // Handle processed messages
      if (isProcessedLoadingMore && processedPage > 1) {
        setProcessedMessages(prev => {
          const allMessages = [...prev, ...transformedMessages];
          const deduplicated = Array.from(new Map(allMessages.map(m => [m.apiId || m.id, m])).values());
          return deduplicated;
        });
      } else {
        setProcessedMessages(transformedMessages);
        setProcessedPage(1);
      }

      if (nextUrl) {
        const url = new URL(nextUrl);
        const pageFromUrl = parseInt(url.searchParams.get('page'), 10);
        setHasMoreProcessed(true);
        setProcessedNextPageNumber(pageFromUrl);
      } else {
        setHasMoreProcessed(false);
        setProcessedNextPageNumber(null);
      }
      setIsProcessedLoadingMore(false);
      setProcessedDataFetched(true);
    } else {
      // Handle mixed data or backwards compatibility
      const pending = transformedMessages.filter(m => m.status === 'pending');
      const processed = transformedMessages.filter(m => m.status === 'processed');
      setPendingMessages(pending);
      setProcessedMessages(processed);
    }

    setIsLoading(false);
  }, [isOpen, isPendingLoadingMore, isProcessedLoadingMore, pendingPage, processedPage]);

  useEffect(() => {
    getActiveChatId().then(id => {
      setCurrentChatId(id);
    });

    const handleChatChange = (chat) => {
      const chatId = chat?.id?._serialized;
      setCurrentChatId(chatId);
      setEditingId(null);
      resetForm();
      setShowForm(false);

      // Reset all data and pagination states for new chat - ChatTodo pattern
      setPendingMessages([]);
      setProcessedMessages([]);
      setPendingPage(1);
      setProcessedPage(1);
      setHasMorePending(false);
      setHasMoreProcessed(false);
      setPendingNextPageNumber(null);
      setProcessedNextPageNumber(null);
      setProcessedDataFetched(true);
      setIsPendingLoadingMore(false);
      setIsProcessedLoadingMore(false);
    };

    window.WPP.on('chat.active_chat', handleChatChange);

    return () => {
      window.WPP.off('chat.active_chat', handleChatChange);
    };
  }, []);


  useEffect(() => {
    if (currentChatId) {
      // Clear existing data and reset states - ChatTodo pattern
      setPendingMessages([]);
      setProcessedMessages([]);
      setPendingPage(1);
      setProcessedPage(1);
      setHasMorePending(false);
      setHasMoreProcessed(false);
      setPendingNextPageNumber(null);
      setProcessedNextPageNumber(null);
      setProcessedDataFetched(true);
      setIsPendingLoadingMore(false);
      setIsProcessedLoadingMore(false);
      setIsLoading(true);

      // Fetch all message types immediately
      postWindowMessage('CHAT_ARTIFACTS_FETCH', {
        chatId: currentChatId,
        data_type: "scheduled_messages",
        status: "pending",
        section: "pending",
        page: 1,
        page_size: ITEMS_PER_PAGE
      });

      postWindowMessage('CHAT_ARTIFACTS_FETCH', {
        chatId: currentChatId,
        data_type: "scheduled_messages",
        status: "processed",
        section: "processed",
        page: 1,
        page_size: ITEMS_PER_PAGE
      });
    } else {
      // Clear data if no chat is selected
      setPendingMessages([]);
      setProcessedMessages([]);
      setIsLoading(false);
    }
  }, [currentChatId]);

  // Fetch processed messages when processed section is expanded
  useEffect(() => {
    if (currentChatId && isProcessedOpen && !processedDataFetched) {
      setIsProcessedLoadingMore(true);
      setProcessedDataFetched(true);

      postWindowMessage('CHAT_ARTIFACTS_FETCH', {
        chatId: currentChatId,
        data_type: "scheduled_messages",
        status: "processed",
        section: "processed",
        page: 1,
        page_size: ITEMS_PER_PAGE
      });
    }
  }, [currentChatId, isProcessedOpen, processedDataFetched]);

  // Clear form errors when form fields change
  useEffect(() => {
    if (formError) {
      setFormError('');
    }
  }, [formData.message, formData.date, formData.time]);

  const resetForm = useCallback(() => {
    const now = new Date();
    now.setMinutes(now.getMinutes() + 1);
    const currentDate = now.toISOString().split('T')[0]; // YYYY-MM-DD format
    const currentTime = now.toTimeString().slice(0, 5); // HH:MM format

    setFormData({
      message: '',
      date: currentDate,
      time: currentTime,
      recurrence: '',
      recurrenceType: 'day'
    });
    setIsRecurring(false);
    setEditingId(null);
    setFormError('');
  }, []);

  const handleCancel = useCallback(() => {
    resetForm();
    setShowForm(false);
  }, [resetForm]);

  const handleInputChange = useCallback((field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  }, []);

  const validateBasicForm = useCallback(() => {
    // Basic validation for button enablement
    return formData.message.trim() && formData.date && formData.time;
  }, [formData.message, formData.date, formData.time]);

  const validateTime = useCallback(() => {
    // Time validation for non-recurring messages (like Reminders.js)
    if (!isRecurring && formData.date && formData.time) {
      const messageDateTime = new Date(`${formData.date}T${formData.time}`);
      const currentTime = new Date();

      if (messageDateTime <= currentTime) {
        return 'Message time must be in the future for non-recurring messages';
      }
    }

    return null;
  }, [formData.date, formData.time, isRecurring]);

  // Show error immediately when validation fails
  const currentTimeError = useMemo(() => {
    return validateTime();
  }, [validateTime]);

  // Button is enabled when basic form is valid (regardless of time error)
  const isButtonEnabled = useMemo(() => {
    return validateBasicForm();
  }, [validateBasicForm]);

  // Using same calculation logic as Reminders.js
  const calculateNextDue = (date, time, recurrence, recurrenceType) => {
    const dateTime = new Date(`${date}T${time}`);

    // For non-repeating messages, return the original date/time
    if (!recurrence || recurrence === 0) {
      return dateTime.toISOString();
    }

    // For repeating messages, calculate the next occurrence
    const now = new Date();
    let nextDue = new Date(dateTime);

    // If the message time has already passed, calculate the next occurrence
    while (nextDue <= now) {
      switch (recurrenceType) {
        case 'minutes':
          nextDue.setMinutes(nextDue.getMinutes() + recurrence);
          break;
        case 'hour':
          nextDue.setHours(nextDue.getHours() + recurrence);
          break;
        case 'day':
          nextDue.setDate(nextDue.getDate() + recurrence);
          break;
        case 'week':
          nextDue.setDate(nextDue.getDate() + (recurrence * 7));
          break;
        case 'month':
          nextDue.setMonth(nextDue.getMonth() + recurrence);
          break;
        case 'year':
          nextDue.setFullYear(nextDue.getFullYear() + recurrence);
          break;
        default:
          // Safety: if unknown type, break the loop to prevent infinite loop
          nextDue = new Date(now.getTime() + 60000); // Add 1 minute as fallback
          break;
      }
    }

    return nextDue.toISOString();
  };

  const handleSubmit = async () => {
    if (!currentChatId) return;

    // Clear previous form errors
    setFormError('');

    // Validate basic form fields
    if (!validateBasicForm()) {
      setFormError('Please fill in all required fields');
      return;
    }

    // Check if there's a time validation error
    if (currentTimeError) {
      // Don't proceed if there's a time error
      return;
    }

    setIsLoading(true);

    try {
      // Get contact name for the current chat
      let contactName = '';
      try {
        contactName = await getContactName(currentChatId);
      } catch (error) {
        console.log('Could not get contact name, using default:', error);
      }

      // main_content contains only the message text
      const main_content = formData.message.trim();

      // meta_data follows Reminders.js structure
      const recurrence = isRecurring ? parseInt(formData.recurrence) || 1 : 0;
      const recurrenceType = isRecurring ? formData.recurrenceType : 'day';

      // Calculate nextDue using same logic as Reminders.js
      const currentTime = new Date().getTime();
      let messageStatus;
      let nextDue;

      if (isRecurring && recurrence > 0) {
        nextDue = calculateNextDue(formData.date, formData.time, recurrence, recurrenceType);
        const nextDueTime = new Date(nextDue).getTime();
        messageStatus = nextDueTime > currentTime ? 'pending' : 'processed';
      } else {
        // For one-time messages, set status based on the message date/time
        const messageDateTime = new Date(`${formData.date}T${formData.time}`);
        nextDue = messageDateTime.toISOString();
        messageStatus = messageDateTime.getTime() > currentTime ? 'pending' : 'processed';
      }

      const meta_data = {
        contactName: contactName,
        date: formData.date,
        time: formData.time,
        recurrence: recurrence,
        recurrenceType: recurrenceType,
        nextDue: nextDue
      };

      if (editingId !== null) {
        postWindowMessage('CHAT_ARTIFACTS_UPDATE', {
          chatId: currentChatId,
          artifact_id: editingId,
          main_content,
          meta_data,
          data_type: 'scheduled_messages',
          status: messageStatus
        });
      } else {
        postWindowMessage('CHAT_ARTIFACTS_CREATE', {
          chatId: currentChatId,
          main_content,
          meta_data,
          data_type: 'scheduled_messages',
          status: messageStatus
        });
      }

      resetForm();
      setShowForm(false);

      // Note: No manual refresh - API response will update UI via message handler
    } catch (error) {
      console.error('Failed to save scheduled message:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEdit = useCallback((message) => {
    setFormData({
      message: message.message,
      date: message.date,
      time: message.time,
      recurrence: message.recurrence.toString(),
      recurrenceType: message.recurrenceType
    });
    setIsRecurring(message.recurrence > 0);
    setEditingId(message.apiId || message.id);
    setShowForm(true);
  }, []);

  const handleDelete = useCallback((message) => {
    if (!currentChatId) return;
    if (!window.confirm('Are you sure you want to delete this scheduled message?')) return;

    setIsLoading(true);

    try {
      postWindowMessage('CHAT_ARTIFACTS_DELETE', {
        chatId: currentChatId,
        artifact_id: message.apiId || message.id,
        data_type: 'scheduled_messages'
      });
      // Note: No manual refresh - API response will update UI via message handler
    } catch (error) {
      console.error('Failed to delete scheduled message:', error);
    } finally {
      setIsLoading(false);
    }
  }, [currentChatId]);

  const renderCollapsibleSection = useCallback((title, isOpen, setIsOpen, messages, hasMore, isLoadingMore, loadMoreFunction, sectionType) => {
    return (
      <div style={{
        marginBottom: '24px'
      }}>
        <div
          style={{
            fontSize: '16px',
            fontWeight: '600',
            color: isDark ? '#e9edef' : '#333',
            marginBottom: '12px',
            padding: '12px 16px',
            borderBottom: `1px solid ${isDark ? '#2a3942' : '#e0e0e0'}`,
            transition: 'color 0.2s ease, border-color 0.2s ease',
            userSelect: 'none',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between'
          }}
          onClick={() => setIsOpen(!isOpen)}
        >
          <span>{title}</span>
          <span style={{ transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }}>
            {icons.DOWN_ARROW}
          </span>
        </div>
        {isOpen && (
          <>
            <div style={{
              padding: '8px 0'
            }}>
              {messages.length > 0 ? (
                messages.map((message, i) => (
                  <ArtifactIconCard
                    key={message.apiId || message.id || i}
                    index={i}
                    isDark={isDark}
                    title={message.message}
                    description={
                      sectionType === 'processed' &&
                        message.deliveryStatus === 'failed' &&
                        message.failureReason
                        ? `Reason: ${message.failureReason}`
                        : ""
                    }

                    footerItems={[
                      {
                        icon: icons.CALENDAR,
                        text: formatDateTime(message.date, message.time),
                      },
                      {
                        icon: icons.REPEAT,
                        text: formatRecurrence(message.recurrence, message.recurrenceType),
                      },

                      ...(sectionType === 'processed' &&
                        message.deliveryStatus === 'sent' &&
                        message.sentAt
                        ? [
                          {
                            icon: icons.SUCCESS,
                            text: `Sent: ${formatISODateTime(message.sentAt)}`,
                            color: isDark ? '#9ca3af' : '#6b7280',
                          },
                        ]
                        : []),

                      ...(sectionType === 'processed' &&
                        message.deliveryStatus === 'failed'
                        ? [
                          {
                            icon: icons.FAILED,
                            text: `Failed${message.failedAt ? `: ${formatISODateTime(message.failedAt)}` : ''
                              }`,
                            color: isDark ? '#9ca3af' : '#6b7280',
                          },
                        ]
                        : []),
                    ]}

                    actions={[
                      ...(sectionType === 'pending'
                        ? [
                          {
                            icon: icons.EDIT,
                            tooltip: 'Edit Message',
                            label: 'Edit',
                            onClick: () => handleEdit(message),
                            disabled: isLoading,
                          },
                        ]
                        : []),

                      {
                        icon: icons.DELETE,
                        tooltip: 'Delete Message',
                        label: 'Delete',
                        onClick: () => handleDelete(message),
                        disabled: isLoading,
                      },
                    ]}
                  />
                ))
              ) : (
                <div style={{
                  padding: '20px',
                  textAlign: 'center',
                  color: isDark ? '#adb5bd' : '#666'
                }}>
                  {title === 'Pending' ? (
                    <>
                      <div style={{
                        fontSize: '18px',
                        fontWeight: '600',
                        marginBottom: '8px',
                        color: isDark ? '#e9edef' : '#333'
                      }}>No scheduled messages yet</div>
                      <div style={{
                        fontSize: '14px',
                        lineHeight: '1.5',
                        maxWidth: '280px',
                        margin: '0 auto',
                        color: isDark ? '#adb5bd' : '#666'
                      }}>
                        Schedule messages to be sent automatically at the right time.
                      </div>
                    </>
                  ) : (
                    `No ${title.toLowerCase()} messages`
                  )}
                </div>
              )}
            </div>
            {hasMore && messages.length > 0 && (
              <div style={{ textAlign: 'center', padding: '20px' }}>
                <button
                  onClick={loadMoreFunction}
                  disabled={isLoadingMore}
                  style={{
                    padding: '10px 20px',
                    backgroundColor: isDark ? '#00d9ff' : '#25d366',
                    color: isDark ? '#111b21' : 'white',
                    border: 'none',
                    borderRadius: '8px',
                    cursor: isLoadingMore ? 'not-allowed' : 'pointer',
                    fontSize: '14px',
                    fontWeight: '500',
                    opacity: isLoadingMore ? 0.6 : 1
                  }}
                >
                  {isLoadingMore ? 'Loading...' : `Load More ${title}`}
                </button>
              </div>
            )}
          </>
        )}
      </div>
    );
  }, [isDark, isLoading, handleEdit, handleDelete]);

  const formatRecurrence = useCallback((recurrence, recurrenceType) => {
    if (!recurrence || recurrence === 0) return 'One-time';
    return `Every ${recurrence} ${recurrenceType}${recurrence > 1 ? 's' : ''}`;
  }, []);

  // Load more functions matching ChatTodo pattern
  const loadMorePendingMessages = useCallback(() => {
    if (!hasMorePending || isPendingLoadingMore || !pendingNextPageNumber) return;

    setIsPendingLoadingMore(true);
    setPendingPage(pendingNextPageNumber);

    postWindowMessage('CHAT_ARTIFACTS_FETCH', {
      chatId: currentChatId,
      data_type: "scheduled_messages",
      status: "pending",
      page: pendingNextPageNumber,
      page_size: ITEMS_PER_PAGE
    });
  }, [currentChatId, hasMorePending, isPendingLoadingMore, pendingNextPageNumber]);

  const loadMoreProcessedMessages = useCallback(() => {
    if (!hasMoreProcessed || isProcessedLoadingMore || !processedNextPageNumber) return;

    setIsProcessedLoadingMore(true);
    setProcessedPage(processedNextPageNumber);

    postWindowMessage('CHAT_ARTIFACTS_FETCH', {
      chatId: currentChatId,
      data_type: "scheduled_messages",
      status: "processed",
      page: processedNextPageNumber,
      page_size: ITEMS_PER_PAGE
    });
  }, [currentChatId, hasMoreProcessed, isProcessedLoadingMore, processedNextPageNumber]);

  if (!isOpen) return null;

  return (
    <ErrorBoundary isDark={isDark}>
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          height: '100%',
          overflow: 'hidden',
          backgroundColor: isDark ? '#1f2c33' : '#f0f2f5',
          padding: '0',
        }}
      >
        {currentChatId ? (
          <>
            {/* Alert header - always show when chat is selected */}
            <div className="cq-scheduled-messages-alert-header">
              <div className="cq-scheduled-messages-alert-status">
                <span className="cq-scheduled-messages-alert-icon">
                  {icons.WARNING}
                </span>
                <span className="cq-scheduled-messages-alert-text">
                  Scheduled messages work only if WhatsApp Web is open.
                </span>
              </div>
            </div>

            {showForm ? (
              <div style={{
                padding: '20px',
                flex: 1,
                overflow: 'auto'
              }}>
                <div style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: '16px'
                }}>
                  <div style={{
                    fontSize: '18px',
                    fontWeight: '600',
                    color: isDark ? '#e9edef' : '#333',
                    marginBottom: '8px'
                  }}>
                    {editingId !== null ? 'Edit Scheduled Message' : 'Schedule New Message'}
                  </div>

                  <div>
                    <TextAreaBox
                      value={formData.message}
                      onChange={(e) => handleInputChange('message', e.target.value)}
                      placeholder="Type your message here..."
                      disabled={isLoading}
                      rows="4"
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '8px' }}>
                    <InputBox
                      type="date"
                      value={formData.date}
                      onChange={(e) => handleInputChange('date', e.target.value)}
                      onClick={(e) => e.target.showPicker && e.target.showPicker()}
                      disabled={isLoading}
                      min={new Date().toISOString().split('T')[0]}
                    />
                    <InputBox
                      type="time"
                      value={formData.time}
                      onChange={(e) => handleInputChange('time', e.target.value)}
                      onClick={(e) => e.target.showPicker && e.target.showPicker()}
                      disabled={isLoading}
                      min={formData.date === new Date().toISOString().split('T')[0] ? new Date().toTimeString().slice(0, 5) : undefined}
                    />
                  </div>

                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                    padding: '4px 0'
                  }}>
                    <input
                      type="checkbox"
                      id="recurring-checkbox"
                      checked={isRecurring}
                      onChange={(e) => {
                        setIsRecurring(e.target.checked);
                        if (!e.target.checked) {
                          // Clear recurrence fields when unchecked
                          setFormData(prev => ({
                            ...prev,
                            recurrence: '',
                            recurrenceType: 'day'
                          }));
                        }
                      }}
                      disabled={isLoading}
                      style={{
                        width: '16px',
                        height: '16px',
                        cursor: 'pointer'
                      }}
                    />
                    <label
                      htmlFor="recurring-checkbox"
                      style={{
                        fontSize: '14px',
                        color: isDark ? '#e9edef' : '#333',
                        cursor: 'pointer',
                        userSelect: 'none'
                      }}
                    >
                      Repeat every
                    </label>
                  </div>

                  {isRecurring && (
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <div style={{ width: '80px' }}>
                        <InputBox
                          type="number"
                          value={formData.recurrence}
                          onChange={(e) => handleInputChange('recurrence', e.target.value)}
                          placeholder="1"
                          disabled={isLoading}
                          min="1"
                        />
                      </div>
                      <div style={{ flex: 1 }}>
                        <Select
                          options={recurrenceOptions}
                          value={formData.recurrenceType}
                          onChange={(value) => handleInputChange('recurrenceType', value)}
                          placeholder="Select frequency"
                        />
                      </div>
                    </div>
                  )}

                  {(formError || currentTimeError) && (
                    <div style={{
                      padding: '12px',
                      backgroundColor: isDark ? '#2a1f1f' : '#ffebee',
                      border: `1px solid ${isDark ? '#5c1e1e' : '#e57373'}`,
                      borderRadius: '6px',
                      color: isDark ? '#ff6b6b' : '#d32f2f',
                      fontSize: '14px',
                      lineHeight: '1.4'
                    }}>
                      {formError || currentTimeError}
                    </div>
                  )}

                  <div style={{ display: 'flex', gap: '8px', marginTop: '16px' }}>
                    <button
                      onClick={handleSubmit}
                      style={{
                        flex: 1,
                        backgroundColor: isDark ? '#00d9ff' : '#007bff',
                        color: isDark ? '#111b21' : '#fff',
                        border: 'none',
                        borderRadius: '8px',
                        padding: '12px 16px',
                        fontSize: '14px',
                        fontWeight: '600',
                        cursor: 'pointer',
                        opacity: (!isButtonEnabled || isLoading) ? 0.5 : 1
                      }}
                      disabled={isLoading || !isButtonEnabled}
                    >
                      {isLoading ? '...' : editingId !== null ? 'Update' : 'Schedule'}
                    </button>

                    <button
                      onClick={handleCancel}
                      style={{
                        flex: 1,
                        backgroundColor: isDark ? '#2a3942' : '#6c757d',
                        color: '#fff',
                        border: 'none',
                        borderRadius: '8px',
                        padding: '12px 16px',
                        fontSize: '14px',
                        fontWeight: '600',
                        cursor: 'pointer'
                      }}
                      disabled={isLoading}
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              </div>
            ) : (
              <div style={{
                display: 'flex',
                flexDirection: 'column',
                height: '100%',
                overflow: 'hidden'
              }}>
                <div style={{
                  flex: 1,
                  overflow: 'auto',
                  padding: '16px',
                  paddingBottom: '100px',
                  width: '100%',
                  boxSizing: 'border-box'
                }}>
                  {isLoading && pendingMessages.length === 0 && processedMessages.length === 0 ? (
                    <div style={{
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      padding: '40px 20px',
                      textAlign: 'center'
                    }}>
                      <div style={{
                        fontSize: '48px',
                        color: isDark ? '#6b7280' : '#999',
                        marginBottom: '16px',
                        opacity: 0.5
                      }}>
                        {icons.SCHEDULE}
                      </div>
                      <div style={{
                        fontSize: '18px',
                        fontWeight: '600',
                        color: isDark ? '#e9edef' : '#374151',
                        marginBottom: '8px'
                      }}>
                        Loading scheduled messages...
                      </div>
                      <div style={{
                        fontSize: '14px',
                        color: isDark ? '#adb5bd' : '#6b7280',
                        lineHeight: '1.5'
                      }}>
                        Please wait while we load your scheduled messages.
                      </div>
                    </div>
                  ) : (
                    <>
                      {renderCollapsibleSection(
                        'Pending',
                        isPendingOpen,
                        setIsPendingOpen,
                        pendingMessages,
                        hasMorePending,
                        isPendingLoadingMore,
                        loadMorePendingMessages,
                        'pending'
                      )}

                      {renderCollapsibleSection(
                        'History',
                        isProcessedOpen,
                        setIsProcessedOpen,
                        processedMessages,
                        hasMoreProcessed,
                        isProcessedLoadingMore,
                        loadMoreProcessedMessages,
                        'processed'
                      )}
                    </>
                  )}
                </div>
                <div style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  right: 0,
                  padding: '20px',
                  borderTop: `1px solid ${isDark ? '#2a3942' : '#e0e0e0'}`,
                  backgroundColor: isDark ? '#111b21' : '#f0f2f5',
                  zIndex: 10
                }}>
                  <button
                    onClick={() => {
                      setEditingId(null);
                      resetForm();
                      setShowForm(true);
                    }}
                    style={{
                      width: '100%',
                      backgroundColor: isDark ? '#00d9ff' : '#007bff',
                      color: isDark ? '#111b21' : '#fff',
                      border: 'none',
                      borderRadius: '8px',
                      padding: '12px 16px',
                      fontSize: '14px',
                      fontWeight: '600',
                      cursor: 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      gap: '8px',
                      transition: 'all 0.2s ease',
                    }}
                    onMouseEnter={(e) => {
                      e.target.style.backgroundColor = isDark ? '#00c4e6' : '#0056b3';
                      e.target.style.transform = 'translateY(-1px)';
                      e.target.style.boxShadow = `0 4px 12px ${isDark ? 'rgba(0, 217, 255, 0.3)' : 'rgba(0, 123, 255, 0.3)'}`;
                    }}
                    onMouseLeave={(e) => {
                      e.target.style.backgroundColor = isDark ? '#00d9ff' : '#007bff';
                      e.target.style.transform = 'translateY(0)';
                      e.target.style.boxShadow = 'none';
                    }}
                  >
                    <span style={{ fontSize: '16px', fontWeight: 'bold' }}>+</span>
                    Schedule Message
                  </button>
                </div>
              </div>
            )}
          </>
        ) : (
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '40px 20px',
            textAlign: 'center',
            height: '100%'
          }}>
            <div style={{
              fontSize: '48px',
              color: isDark ? '#6b7280' : '#999',
              marginBottom: '20px',
              opacity: 0.5
            }}>
              {icons.SCHEDULE}
            </div>
            <div style={{
              fontSize: '18px',
              fontWeight: '600',
              color: isDark ? '#e9edef' : '#333',
              marginBottom: '8px'
            }}>
              Select Chat
            </div>
            <div style={{
              fontSize: '14px',
              color: isDark ? '#adb5bd' : '#666',
              lineHeight: '1.5',
              maxWidth: '280px'
            }}>
              Please select a chat to schedule and manage messages.
            </div>
          </div>
        )}
      </div>
    </ErrorBoundary>
  );
};

export default ScheduledMessages;