import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Cell, LabelList, Tooltip, ResponsiveContainer } from 'recharts';

const PipelineFunnelChart = ({ stats }) => {

    const funnelColors = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];
    const funnelData = (Array.isArray(stats?.leads_by_stage?.stages) ? stats.leads_by_stage.stages : []).map((s, index) => ({
        name: s?.stage || 'Unknown',
        value: s?.count || 0,
        fill: funnelColors[index % funnelColors.length]
    }));

    // Calculate dynamic height: ~50px per bar + 60px padding/header
    // Minimum height of 200px to look decent if empty or single item
    const chartHeight = Math.max(funnelData.length * 50 + 60, 250);
    const marginTop = 20;
    const marginBottom = 5;
    const gridHeight = chartHeight - marginTop - marginBottom;

    return (
        <div className="cq-chart-card" style={{ marginBottom: '24px' }}>
            <div className="cq-chart-header">
                <h3 className="cq-chart-title">Pipeline Funnel</h3>
            </div>
            <div className="cq-chart-body" style={{ height: `${chartHeight}px`, width: '100%', position: 'relative' }}>
                {funnelData.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%" minWidth={100} minHeight={100} debounce={0}>
                        <BarChart
                            layout="vertical"
                            data={funnelData}
                            margin={{ top: marginTop, right: 30, left: 40, bottom: marginBottom }}
                            barSize={30}
                        >
                            <CartesianGrid
                                vertical={false}
                                horizontalPoints={[0, gridHeight]}
                                stroke="#e5e7eb"
                                strokeDasharray="3 3"
                            />
                            <XAxis type="number" hide />
                            <YAxis
                                dataKey="name"
                                type="category"
                                tick={{ fontSize: 13, textAnchor: 'end', fill: '#6b7280' }}
                                width={100}
                                tickLine={false}
                                axisLine={{ stroke: '#e5e7eb' }}
                            />
                            <Tooltip
                                cursor={{ fill: 'transparent' }}
                                contentStyle={{ zIndex: 1000, borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                            />
                            <Bar dataKey="value" radius={[0, 4, 4, 0]}>
                                {funnelData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={entry.fill} />
                                ))}
                                <LabelList dataKey="value" position="right" fill="#6b7280" fontSize={13} />
                            </Bar>
                        </BarChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="cq-empty-chart">
                        <span>No data available</span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PipelineFunnelChart;
