import React from 'react';

const SlippingLeadsWidget = ({ leads, loading, hasMore, onLoadMore, onNudge }) => {

    const handleScroll = (e) => {
        const { scrollTop, scrollHeight, clientHeight } = e.target;
        if (scrollTop + clientHeight >= scrollHeight - 5 && !loading && hasMore) {
            onLoadMore();
        }
    };

    const formatCurrency = (val) => {
        try {
            return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumSignificantDigits: 3 }).format(val || 0);
        } catch (e) {
            return '₹0';
        }
    };

    const handleNudgeClick = (lead) => {
        if (onNudge && lead) {
            onNudge(lead);
        }
    };

    return (
        <div className="cq-list-widget">
            <div className="cq-list-header">
                <h3>Slipping Away<span className="cq-item-subtitle-secondary">(Inactive &gt; 7 Days)</span></h3>
            </div>
            <div className="cq-list-body" onScroll={handleScroll} style={{ overflowY: 'auto', maxHeight: '300px' }}>
                {loading && (!Array.isArray(leads) || leads.length === 0) ? (
                    <div className="cq-loading-spinner"></div>
                ) : (!Array.isArray(leads) || leads.length === 0) ? (
                    <div className="cq-empty-list">No slipping leads. Good job!</div>
                ) : (
                    <>
                        {leads.map((lead, idx) => {
                            if (!lead) return null;
                            const created = new Date(lead.created_at);
                            const daysAgo = Math.floor((new Date() - created) / (1000 * 60 * 60 * 24));
                            const customerName = lead.customer ? `${lead.customer.first_name || ''} ${lead.customer.last_name || ''}`.trim() : 'Unknown';

                            return (
                                <div key={lead.id || `lead-${idx}`} className="cq-list-item">
                                    <div className="cq-list-item-main">
                                        <span className="cq-item-title">{lead.title || 'Untitled Lead'}</span>
                                        <span className="cq-item-subtitle">
                                            {customerName} • {daysAgo} days old
                                        </span>
                                    </div>
                                    <div className="cq-list-item-right" style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end' }}>
                                        <span style={{ fontSize: '13px', fontWeight: '500' }}>{formatCurrency(lead.expected_value || 0)}</span>
                                        <button
                                            className="cq-btn-xs"
                                            style={{ marginTop: '4px' }}
                                            onClick={() => handleNudgeClick(lead)}
                                        >
                                            Nudge
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                        {loading && <div className="cq-loading-spinner"></div>}
                        {!loading && hasMore && (
                            <div style={{ textAlign: 'center', padding: '8px' }}>
                                <button
                                    className="cq-btn-xs"
                                    onClick={onLoadMore}
                                >
                                    Load More
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
};

export default SlippingLeadsWidget;
