import React from 'react';
import ExpandableText from '../../../UIComponents/ExpandableText';

const ActivityDetails = ({ details, hideOldValue = false, hideLabel = false, useExpandable = false }) => {
    if (!details || details.length === 0) return null;

    const formatVal = (val) => {
        if (val === null || val === undefined || val === '') return <span className="cq-val-null">Empty</span>;

        if (typeof val === 'object' && Object.keys(val).length === 0) return <span className="cq-val-null">None</span>;
        if (typeof val === 'object') return JSON.stringify(val).replace(/"/g, '');

        const str = String(val);

        if (str === 'True') return 'True';
        if (str === 'False') return 'False';

        if (/^\d{4}-\d{2}-\d{2}T/.test(str) || /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}/.test(str)) {
            const d = new Date(str);
            if (!isNaN(d.getTime())) {
                return d.toLocaleDateString() + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            }
        }

        if (str.startsWith("{'") && str.includes("interval_type")) {
            try {
                const typeMatch = str.match(/'interval_type':\s*'(\w+)'/);
                const valMatch = str.match(/'interval_value':\s*(\d+)/);
                if (typeMatch && valMatch) {
                    return `${valMatch[1]} ${typeMatch[1]}`;
                }
            } catch (e) {
            }
        }
        if (str === '{}') return <span className="cq-val-null">None</span>;

        return str;
    };

    return (
        <div className="cq-activity-details-list">
            {details.map((detail, idx) => {
                let newVal = formatVal(detail.to_value ?? detail.new_value);
                const oldVal = formatVal(detail.from_value ?? detail.old_value);

                if (useExpandable && typeof newVal === 'string') {
                    newVal = <ExpandableText text={newVal} maxLength={100} />;
                }

                if (hideLabel) {
                    return (
                        <div key={idx} className="cq-activity-change-row">
                            <span className="cq-val-new">{newVal}</span>
                        </div>
                    );
                }

                if (hideOldValue) {
                    return (
                        <div key={idx} className="cq-activity-change-row">
                            <span className="cq-change-sentence">
                                {detail.label} set to <strong>{newVal}</strong>
                            </span>
                        </div>
                    );
                }

                const rawOldVal = detail.from_value ?? detail.old_value;
                const isEmpty = (val) => val === null || val === undefined || val === '' || (typeof val === 'object' && Object.keys(val).length === 0) || val === '{}';

                return (
                    <div key={idx} className="cq-activity-change-row">
                        <span className="cq-change-sentence">
                            Changed {detail.label} {!isEmpty(rawOldVal) ? <span>from <strong>{oldVal}</strong></span> : ''} to <strong>{newVal}</strong>
                        </span>
                    </div>
                );
            })}
        </div>
    );
};

export default ActivityDetails;
