
import React from 'react';
import './Dashboard.css';
import Scorecard from './Widgets/Scorecard';
import SlippingLeadsWidget from './Widgets/SlippingLeadsWidget';
import UpcomingTasksWidget from './Widgets/UpcomingTasksWidget';
import LeadSourceChart from './Widgets/LeadSourceChart';
import PipelineFunnelChart from './Widgets/PipelineFunnelChart';
import { openChat, getActiveChatMessages } from '../../../utils/WppFunctions';
import { showToast } from '../../UIComponents/Toast/ToastManager';
import { postWindowMessage } from '../../../utils/messageSender';
import { showSuggestionPreview } from '../../../utils/showSuggestionPreview';



const AnalyticsTab = ({ pipelineId, pipeline, dateRange, customRange, onTaskClick, isVisible, currency, exchangeRates }) => {

    const [loadingStats, setLoadingStats] = React.useState(true);
    const [stats, setStats] = React.useState(null);
    const [slippingLeads, setSlippingLeads] = React.useState([]);
    const [loadingSlipping, setLoadingSlipping] = React.useState(true);
    const [slippingPage, setSlippingPage] = React.useState(1);
    const [hasMoreSlipping, setHasMoreSlipping] = React.useState(true);
    const [upcomingTasks, setUpcomingTasks] = React.useState([]);
    const [loadingTasks, setLoadingTasks] = React.useState(true);
    const [tasksPage, setTasksPage] = React.useState(1);
    const [hasMoreTasks, setHasMoreTasks] = React.useState(true);

    // Calculate Date Range
    const getDateRangeParams = () => {
        if (dateRange === 'custom') {
            if (customRange?.start && customRange?.end) {
                return {
                    start_date: customRange.start,
                    end_date: customRange.end
                };
            }
            // Fallback if incomplete custom range
            return null; // Don't fetch yet
        }

        const end = new Date();
        const start = new Date();
        if (dateRange === '7_days') start.setDate(start.getDate() - 7);
        else if (dateRange === '14_days') start.setDate(start.getDate() - 14);
        else if (dateRange === '30_days') start.setDate(start.getDate() - 30);
        else if (dateRange === '3_months') start.setDate(start.getDate() - 90);
        else start.setDate(start.getDate() - 30);

        return {
            start_date: start.toISOString().split('T')[0],
            end_date: end.toISOString().split('T')[0]
        };
    };

    const lastFetchedRef = React.useRef({ pipelineId: null, start_date: null, end_date: null });
    const lastFetchedSlippingRef = React.useRef({ pipelineId: null, page: null });
    const lastFetchedTasksRef = React.useRef({ pipelineId: null, page: null });

    // Clear fetch tracking when hidden to ensure fresh data on reappearance
    React.useEffect(() => {
        if (!isVisible) {
            lastFetchedRef.current = { pipelineId: null, start_date: null, end_date: null };
            lastFetchedSlippingRef.current = { pipelineId: null, page: null };
            lastFetchedTasksRef.current = { pipelineId: null, page: null };
        }
    }, [isVisible]);

    React.useEffect(() => {
        if (!pipelineId) {
            setLoadingStats(false);
            setStats(null);
            return;
        }

        const ranges = getDateRangeParams();
        if (!ranges) return; // Wait for valid range

        const { start_date, end_date } = ranges;

        // Prevent redundant fetch
        if (lastFetchedRef.current.pipelineId === pipelineId &&
            lastFetchedRef.current.start_date === start_date &&
            lastFetchedRef.current.end_date === end_date) {
            return;
        }

        if (!isVisible) return;

        setLoadingStats(true);
        window.postMessage({
            type: 'DASHBOARD_STATS_GET',
            payload: { pipeline_id: pipelineId, start_date, end_date }
        }, '*');

        lastFetchedRef.current = { pipelineId, start_date, end_date };

        // Reset slipping leads
        setSlippingLeads([]);
        setSlippingPage(1);
        setHasMoreSlipping(true);
        lastFetchedSlippingRef.current = { pipelineId: null, page: null };

        // Reset upcoming tasks
        setUpcomingTasks([]);
        setTasksPage(1);
        setHasMoreTasks(true);
        lastFetchedTasksRef.current = { pipelineId: null, page: null };

    }, [pipelineId, dateRange, customRange?.start, customRange?.end, isVisible]);

    React.useEffect(() => {
        if (!pipelineId) {
            setLoadingSlipping(false);
            setSlippingLeads([]);
            return;
        }
        if (!hasMoreSlipping) return;
        if (!isVisible) return;

        // Prevent redundant fetch
        if (lastFetchedSlippingRef.current.pipelineId === pipelineId &&
            lastFetchedSlippingRef.current.page === slippingPage) {
            return;
        }

        setLoadingSlipping(true);
        window.postMessage({
            type: 'DASHBOARD_LEADS_INACTIVE',
            payload: { pipeline_id: pipelineId, page: slippingPage, pageSize: 10 }
        }, '*');
        lastFetchedSlippingRef.current = { pipelineId, page: slippingPage };
    }, [pipelineId, slippingPage, hasMoreSlipping, isVisible]);

    React.useEffect(() => {
        if (!pipelineId) {
            setLoadingTasks(false);
            setUpcomingTasks([]);
            return;
        }
        if (!hasMoreTasks) return;
        if (!isVisible) return;

        // Prevent redundant fetch
        if (lastFetchedTasksRef.current.pipelineId === pipelineId &&
            lastFetchedTasksRef.current.page === tasksPage) {
            return;
        }

        setLoadingTasks(true);
        window.postMessage({
            type: 'DASHBOARD_TASKS_UPCOMING_GET',
            payload: { pipeline_id: pipelineId, page: tasksPage, pageSize: 10 }
        }, '*');
        lastFetchedTasksRef.current = { pipelineId, page: tasksPage };
    }, [pipelineId, tasksPage, hasMoreTasks, isVisible]);

    const handleTaskToggle = (task) => {
        if (!task.lead_id) {
            console.error('Task missing lead_id, cannot update');
            return;
        }

        // Force boolean conversion to prevent any non-boolean issues
        const currentStatus = !!task.is_completed;
        const newStatus = !currentStatus;

        console.log('Toggling Task:', { id: task.id, old: currentStatus, new: newStatus });

        // Optimistic update
        setUpcomingTasks(prev => prev.map(t =>
            t.id === task.id ? { ...t, is_completed: newStatus } : t
        ));

        window.postMessage({
            type: 'LEAD_TASK_UPDATE',
            payload: {
                leadId: task.lead_id,
                taskId: task.id,
                payload: { is_completed: newStatus },
                initiator: 'dashboard'
            }
        }, '*');
    };

    const handleNudge = async (lead) => {
        const chatId = lead.whatsapp_chat_id || lead.chat_id || (lead.customer && (lead.customer.chat_id || lead.customer.id));
        if (chatId) {
            await openChat(chatId);

            const chatMessages = (await getActiveChatMessages()) || [];

            const getReply = 'GET_AI_REPLY';

            postWindowMessage(getReply, chatMessages);
            showSuggestionPreview();

        } else {
            console.warn('No chat ID found for nudge', lead);
        }
    };

    React.useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'DASHBOARD_STATS_GET_SUCCESS') {
                if (payload) {
                    setStats(payload);
                }
                setLoadingStats(false);
            } else if (type === 'DASHBOARD_LEADS_INACTIVE_SUCCESS') {
                const results = payload.results || [];
                setSlippingLeads(prev => {
                    const page = payload.page || 1;
                    if (results.length < 10) setHasMoreSlipping(false);
                    return slippingPage === 1 ? results : [...prev, ...results];
                });
                setLoadingSlipping(false);
            } else if (type === 'DASHBOARD_TASKS_UPCOMING_GET_SUCCESS') {
                const results = payload.results || [];
                setUpcomingTasks(prev => {
                    if (results.length < 10) setHasMoreTasks(false);
                    return tasksPage === 1 ? results : [...prev, ...results];
                });
                setLoadingTasks(false);
            } else if (type === 'LEAD_TASK_UPDATE_SUCCESS') {
                // Update the task status in the list first (don't remove yet)
                setUpcomingTasks(prev => prev.map(t =>
                    t.id === payload.id ? { ...t, ...payload } : t
                ));

                // Show Toast on Success
                if (payload.initiator === 'dashboard') {
                    if (payload.is_completed) {
                        showToast({ message: 'Task marked as completed', type: 'success', duration: 3000 });
                    } else {
                        showToast({ message: 'Task marked as pending', type: 'info', duration: 3000 });
                    }
                }

                // If completed, wait 3 seconds then remove if STILL completed
                if (payload.is_completed) {
                    setTimeout(() => {
                        setUpcomingTasks(currentList => {
                            const task = currentList.find(t => t.id === payload.id);
                            // Only remove if it exists and is STILL completed (user didn't uncheck it)
                            if (task && task.is_completed) {
                                return currentList.filter(t => t.id !== payload.id);
                            }
                            return currentList;
                        });
                    }, 3000);
                }
            } else if (type === 'LEAD_TASK_CREATE_SUCCESS') {
                const newTask = {
                    id: payload.id || payload.taskId,
                    title: payload.title || payload.description,
                    due_at: payload.due_at || payload.date,
                    is_completed: false,
                    lead_id: payload.lead_id || payload.leadId
                };

                // Check if it belongs to this pipeline (though analytics usually shows all tasks for pipeline)
                setUpcomingTasks(prev => {
                    if (prev.some(t => String(t.id) === String(newTask.id))) return prev;
                    return [newTask, ...prev];
                });
            } else if (type === 'LEAD_TASK_DELETE_SUCCESS') {
                const deletedTaskId = payload.taskId || payload.id;
                if (deletedTaskId) {
                    setUpcomingTasks(prev => prev.filter(t => String(t.id) !== String(deletedTaskId)));
                }
            } else if (type === 'LEAD_TASK_UPDATE_ERROR') {
                console.error('Task update failed:', payload.error);
                showToast({ message: 'Failed to update task', type: 'error', duration: 3000 });

                // Revert optimistic update
                if (payload.id) {
                    setUpcomingTasks(prev => prev.map(t =>
                        t.id === payload.id ? { ...t, is_completed: !t.is_completed } : t
                    ));
                }
            }
        };
        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [slippingPage, tasksPage]);

    return (
        <div className="cq-analytics-tab">
            {/* ROW 1: SCORECARD */}
            <Scorecard
                stats={stats}
                loading={loadingStats}
                currency={currency}
                exchangeRates={exchangeRates}
            />

            {/* ROW 2: ACTION CENTER */}
            <div className="cq-action-center-grid">
                <div className="cq-action-lists">
                    {/* Slipping Away */}
                    <SlippingLeadsWidget
                        leads={slippingLeads}
                        loading={loadingSlipping}
                        hasMore={hasMoreSlipping}
                        onLoadMore={() => setSlippingPage(prev => prev + 1)}
                        onNudge={handleNudge}
                    />

                    {/* Upcoming Tasks */}
                    <UpcomingTasksWidget
                        tasks={upcomingTasks}
                        loading={loadingTasks}
                        hasMore={hasMoreTasks}
                        onLoadMore={() => setTasksPage(prev => prev + 1)}
                        onToggleTask={handleTaskToggle}
                    />
                </div>

                {/* Pie Chart */}
                <LeadSourceChart stats={stats} />
            </div>

            {/* ROW 3: PIPELINE FUNNEL */}
            <PipelineFunnelChart stats={stats} />
        </div>
    );
};

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true, error };
    }

    componentDidCatch(error, errorInfo) {
        console.error('AnalyticsTab Error:', error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="cq-analytics-tab" style={{ padding: '20px', textAlign: 'center' }}>
                    <h3>Something went wrong in the Analytics Dashboard.</h3>
                    <p style={{ color: '#ef4444' }}>{this.state.error && this.state.error.toString()}</p>
                    <button
                        className="cq-btn-primary"
                        onClick={() => this.setState({ hasError: false })}
                        style={{ marginTop: '10px' }}
                    >
                        Try Again
                    </button>
                </div>
            );
        }

        return this.props.children;
    }
}

export default function AnalyticsTabWrapper(props) {
    return (
        <ErrorBoundary>
            <AnalyticsTab {...props} />
        </ErrorBoundary>
    );
};
