import React, { useState } from 'react';
import InputBox from '../InputBox';
import './TaskForm.css';

const TASK_TYPES = ['Call', 'Email', 'Meeting', 'To-Do'];

const TaskForm = ({
    onSave,
    onCancel,
    initialData = null,
    saveLabel = 'Create Task',
    className = ''
}) => {
    const [taskData, setTaskData] = useState(initialData || {
        type: 'Call',
        date: '',
        description: '',
        reminderEnabled: false,
        reminderValue: '',
        reminderUnit: 'minutes'
    });
    const [error, setError] = useState('');
    const dateInputRef = React.useRef(null);

    const handleSubmit = (e) => {
        e.preventDefault();
        setError('');

        if (taskData.reminderEnabled) {
            if (!taskData.reminderValue) {
                setError('Please enter a value for the reminder');
                return;
            }

            const val = parseInt(taskData.reminderValue, 10);
            if (taskData.reminderUnit === 'minutes' && val > 59) {
                setError('Minutes cannot be greater than 59');
                return;
            }
            if (taskData.reminderUnit === 'hours' && val > 24) {
                setError('Hours cannot be greater than 24');
                return;
            }

            if (taskData.date) {
                const dueDate = new Date(taskData.date);
                const value = parseInt(taskData.reminderValue, 10);
                let multiplier = 0;

                switch (taskData.reminderUnit) {
                    case 'minutes': multiplier = 60 * 1000; break;
                    case 'hours': multiplier = 60 * 60 * 1000; break;
                    case 'days': multiplier = 24 * 60 * 60 * 1000; break;
                    case 'weeks': multiplier = 7 * 24 * 60 * 60 * 1000; break;
                    default: multiplier = 60 * 1000;
                }

                const reminderTime = new Date(dueDate.getTime() - (value * multiplier));
                if (reminderTime < new Date()) {
                    setError('Reminder time cannot be in the past');
                    return;
                }
            }
        }

        // Validate that the task date itself is in the future
        if (taskData.date && new Date(taskData.date) < new Date()) {
            setError('Task date cannot be in the past');
            return;
        }

        if (onSave) {
            onSave(taskData);
        }
        // Reset if it was a create operation
        if (!initialData) {
            setTaskData({
                type: 'Call',
                date: '',
                description: '',
                reminderEnabled: false,
                reminderValue: '10', // Default for minutes
                reminderUnit: 'minutes'
            });
        }
    };

    const handleCancel = (e) => {
        if (e) e.preventDefault();
        if (onCancel) {
            onCancel();
        }
    };

    // Helper to generate options based on unit
    const getReminderOptions = () => {
        const unit = taskData.reminderUnit;
        let max = 60; // Default for minutes
        if (unit === 'minutes') max = 60;
        else if (unit === 'hours') max = 24;
        else if (unit === 'days') max = 30;
        else if (unit === 'weeks') max = 4;

        return Array.from({ length: max }, (_, i) => i + 1);
    };

    const getMinDate = () => {
        const now = new Date();
        const offset = now.getTimezoneOffset() * 60000;
        return new Date(now - offset).toISOString().slice(0, 16);
    };

    return (
        <form onSubmit={handleSubmit} className={`cq-task-form ${className}`}>
            <InputBox
                placeholder="Task description..."
                value={taskData.description}
                onChange={(e) => setTaskData({ ...taskData, description: e.target.value })}
            />
            <div className="cq-task-form-row">
                <div className="cq-task-form-col">
                    <div className="cq-input-container">
                        <select
                            value={taskData.type}
                            onChange={(e) => setTaskData({ ...taskData, type: e.target.value })}
                            className="cq-select-primitive"
                        >
                            {TASK_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>
                </div>
                <div className="cq-task-form-col">
                    <InputBox
                        ref={dateInputRef}
                        type="datetime-local"
                        value={taskData.date}
                        onChange={(e) => setTaskData({ ...taskData, date: e.target.value })}
                        min={getMinDate()}
                        onClick={() => {
                            if (dateInputRef.current && dateInputRef.current.showPicker) {
                                dateInputRef.current.showPicker();
                            }
                        }}
                    />
                </div>
            </div>


            <div style={{ marginTop: '8px' }}>
                <label className="cq-task-reminder-label">
                    <input
                        type="checkbox"
                        checked={taskData.reminderEnabled || false}
                        onChange={(e) => {
                            const enabled = e.target.checked;
                            setTaskData({
                                ...taskData,
                                reminderEnabled: enabled,
                                reminderValue: enabled ? (taskData.reminderUnit === 'minutes' ? '10' : '1') : ''
                            });
                            setError('');
                        }}
                    />
                    {taskData.reminderEnabled
                        ? `Remind me ${taskData.reminderValue} ${taskData.reminderUnit} before`
                        : 'Remind me'}
                </label>

                {taskData.reminderEnabled && (
                    <div className="cq-task-form-row" style={{ marginTop: '8px', alignItems: 'center' }}>
                        <div className="cq-task-form-col">
                            <div className="cq-input-container">
                                <select
                                    value={taskData.reminderValue || ''}
                                    onChange={(e) => {
                                        setTaskData({ ...taskData, reminderValue: e.target.value });
                                        setError('');
                                    }}
                                    className="cq-select-primitive"
                                >
                                    {getReminderOptions().map(num => (
                                        <option key={num} value={num}>{num}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="cq-task-form-col">
                            <div className="cq-input-container">
                                <select
                                    value={taskData.reminderUnit || 'minutes'}
                                    onChange={(e) => {
                                        const newUnit = e.target.value;
                                        setTaskData({
                                            ...taskData,
                                            reminderUnit: newUnit,
                                            reminderValue: newUnit === 'minutes' ? '10' : '1'
                                        });
                                        setError('');
                                    }}
                                    className="cq-select-primitive"
                                >
                                    <option value="minutes">Minutes</option>
                                    <option value="hours">Hours</option>
                                    <option value="days">Days</option>
                                    <option value="weeks">Weeks</option>
                                </select>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            <div className="cq-form-actions">
                {error && <div style={{ color: '#ef4444', fontSize: '13px', marginBottom: '8px', textAlign: 'right' }}>{error}</div>}
                {onCancel && (
                    <button type="button" className="cq-btn-secondary" onClick={handleCancel}>
                        Cancel
                    </button>
                )}
                <button
                    type="submit"
                    className="cq-btn-primary"
                    disabled={!taskData.description.trim() || !taskData.date}
                >
                    {saveLabel}
                </button>
            </div>
        </form>
    );
};

export default TaskForm;
