import React, { useState, useEffect } from 'react';
import InputBox from './InputBox';
import './ClickToEditInput.css';

const ClickToEditInput = ({
    value,
    onSave,
    placeholder = 'Click to edit',
    type = 'text',
    textStyle = {},
    inputProps = {},
    className = '',
    customEditor = null,
    displayValue,
    onEditEnd
}) => {
    const [isEditing, setIsEditing] = useState(false);
    const [currentValue, setCurrentValue] = useState(value || '');
    const containerRef = React.useRef(null);
    const valRef = React.useRef(value || '');

    // Sync state with prop updates when not editing
    useEffect(() => {
        if (!isEditing) {
            setCurrentValue(value || '');
            valRef.current = value || '';
        }
    }, [value, isEditing]);

    const handleStartEdit = (e) => {
        e.stopPropagation();
        setIsEditing(true);
        const val = value || '';
        setCurrentValue(val); // Ensure we start with the latest prop value
        valRef.current = val;
    };

    const handleSave = () => {
        // Only trigger save if value has changed
        if (valRef.current !== (value || '')) {
            if (onSave) {
                onSave(valRef.current);
            }
        }
        setIsEditing(false);
    };

    const handleKeyDown = (e) => {
        if (e.key === 'Enter') {
            handleSave();
        } else if (e.key === 'Escape') {
            setIsEditing(false);
            setCurrentValue(value || ''); // Revert
            valRef.current = value || '';
        }
    };

    const handleClickWrapper = (e) => {
        // Prevent click propagation to parent containers (like cards)
        e.stopPropagation();
    }

    // Handle click outside to close edit mode
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (isEditing && containerRef.current && !containerRef.current.contains(event.target)) {
                // Check if we should save before closing (for custom editor, we might assume auto-save or cancel)
                // For customEditor, we just set editing false, assuming component handles its own save/sync
                if (!customEditor) {
                    // For standard input, if we click outside, trigger save.
                    // We can call onSave with currentValue if defined.
                    handleSave();
                } else {
                    // For custom editor, notify parent that edit ended
                    if (onEditEnd) onEditEnd();
                }
                setIsEditing(false);
            }
        };

        if (isEditing) {
            document.addEventListener('mousedown', handleClickOutside);
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isEditing, customEditor, handleSave, onEditEnd]);

    if (isEditing) {
        if (customEditor) {
            return (
                <div ref={containerRef} onClick={handleClickWrapper} style={{ width: '100%' }}>
                    {customEditor({
                        stopEditing: (save = false) => {
                            if (save && onEditEnd) {
                                onEditEnd();
                            }
                            setIsEditing(false);
                        }
                    })}
                </div>
            );
        }

        const { onChange: customOnChange, ...restInputProps } = inputProps;

        return (
            <div ref={containerRef} onClick={handleClickWrapper} style={{ width: '100%' }}>
                <InputBox
                    autoFocus
                    value={currentValue}
                    onChange={(e) => {
                        const val = e.target.value;
                        setCurrentValue(val);
                        valRef.current = val;
                        if (customOnChange) customOnChange(e);
                    }}
                    onBlur={handleSave}
                    onKeyDown={handleKeyDown}
                    type={type}
                    placeholder={placeholder}
                    {...restInputProps}
                    style={{ ...inputProps.style, marginBottom: 0 }}
                />
            </div>
        );
    }

    return (
        <div
            className={`cq-click-to-edit-text ${className}`}
            onClick={handleStartEdit}
            style={textStyle}
            title="Click to edit"
        >
            {(displayValue !== undefined ? displayValue : value) ? (
                <span>{displayValue !== undefined ? displayValue : value}</span>
            ) : (
                <span className="cq-click-to-edit-placeholder">{placeholder}</span>
            )}
        </div>
    );
};

export default ClickToEditInput;
