import React, { useState, useEffect, useRef } from 'react';
import LeadCreation from './LeadCreation';
import LeadListing from './LeadListing';
import LeadDetailsPanel from './LeadDetailsPanel';
import { getActiveChatId, getActiveChatNumber, getContactName, isIndividualChat } from '../../utils/WppFunctions';
import { postWindowMessage } from '../../utils/messageSender';
import { mapPipelineToUI } from '../../utils/utils';
import EmptyState from '../UIComponents/EmptyState';
import { icons } from '../../Constants/svg';
import { SidePanelContext } from '../UIComponents/SidePanel';
import ClickToEditInput from '../UIComponents/ClickToEditInput';
import { useToast } from '../UIComponents/Toast/ToastManager';


const LeadsPanel = ({ initialView, initialLead, showBackButton = true, initialPipelines = [] }) => {
    const { setHeaderActions, setPanelTitle, setLeftHeaderAction, chatId } = React.useContext(SidePanelContext);
    const { addToast } = useToast();

    // 1. State
    const [leads, setLeads] = useState([]);
    const [pipelines, setPipelines] = useState(initialPipelines);
    const [view, setView] = useState(initialView || (initialLead ? 'details' : (leads.length > 0 ? 'listing' : 'creation')));
    const [selectedLead, setSelectedLead] = useState(initialLead || null);
    const [isRestrictedContext, setIsRestrictedContext] = useState(false);
    const [loading, setLoading] = useState(true);
    const [customerId, setCustomerId] = useState(null);
    const [checkingLeads, setCheckingLeads] = useState(true);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [initialLoadComplete, setInitialLoadComplete] = useState(false);

    const [form, setForm] = useState({
        firstName: '', lastName: '', phone: '', email: '', company: null, designation: '', title: '',
        expectedValue: '', closingDate: '', source: '', address: '', city: '', state: '', zip: '', country: ''
    });

    // 2. Refs
    const suggestionTriggeredRef = useRef(false);
    const switchToListingRef = useRef(false);
    const activeChatIdRef = useRef(chatId);
    const pipelinesFetchedRef = useRef(initialPipelines.length > 0);


    const hasLeads = leads.length > 0;

    const handleLeadUpdate = async (leadId, updates) => {
        // Map updates to snake_case for local state (because groupedLeads uses snake_case)
        const localUpdates = { ...updates };
        if (updates.stageId) localUpdates.stage_id = updates.stageId;
        if (updates.expectedValue) localUpdates.expected_value = updates.expectedValue;
        if (updates.currencyType) localUpdates.currency_type = updates.currencyType;
        if (updates.closingDate) localUpdates.expected_closing_date = updates.closingDate;

        // Optimistic UI update
        setLeads(prevLeads => {
            return prevLeads.map(lead =>
                lead.id === leadId ? { ...lead, ...localUpdates } : lead
            );
        });

        // Also update selectedLead if it's the one being modified
        if (selectedLead && selectedLead.id === leadId) {
            setSelectedLead(prev => ({ ...prev, ...updates }));
        }

        // Prepare API payload
        const apiPayload = {};
        if (updates.title !== undefined) apiPayload.title = updates.title;
        if (updates.expectedValue !== undefined) apiPayload.expected_value = parseFloat(updates.expectedValue) || 0;
        if (updates.currencyType !== undefined) apiPayload.currency_type = updates.currencyType;
        if (updates.closingDate !== undefined) apiPayload.expected_closing_date = updates.closingDate;
        if (updates.source !== undefined) apiPayload.source = updates.source;
        if (updates.priority !== undefined) apiPayload.priority = updates.priority.toUpperCase();
        if (updates.stageId !== undefined) apiPayload.stage_id = updates.stageId;
        if (updates.meta !== undefined) apiPayload.meta = updates.meta;


        if (Object.keys(apiPayload).length > 0) {
            postWindowMessage('LEAD_UPDATE', {
                lead_id: leadId,
                updates: apiPayload
            });
        }
    };

    // Header Management Effect
    useEffect(() => {
        if (view === 'details' && selectedLead && setPanelTitle && setLeftHeaderAction) {
            // Set Custom Title
            setPanelTitle(
                <ClickToEditInput
                    value={selectedLead.title}
                    onSave={(val) => handleLeadUpdate(selectedLead.id, { title: val })}
                    placeholder="Lead Title"
                    textStyle={{ fontSize: '16px', fontWeight: '600' }}
                    className="cq-lead-title-input"
                />
            );

            // Set Back Button
            if (showBackButton) {
                setLeftHeaderAction(
                    <div
                        onClick={() => setView('listing')}
                        style={{ cursor: 'pointer', padding: '4px', display: 'flex' }}
                        title="Back to Leads"
                    >
                        {icons.LEFT_ARROW}
                    </div>
                );
            } else {
                setLeftHeaderAction(null);
            }
        } else if (view === 'creation' && setPanelTitle && setLeftHeaderAction) {
            setPanelTitle('Create Lead');
            if (hasLeads) {
                setLeftHeaderAction(
                    <div
                        onClick={() => setView('listing')}
                        style={{ cursor: 'pointer', padding: '4px', display: 'flex' }}
                        title="Back to Leads"
                    >
                        {icons.LEFT_ARROW}
                    </div>
                );
            } else {
                setLeftHeaderAction(null);
            }
        } else if (setPanelTitle && setLeftHeaderAction) {
            // Reset to default
            setPanelTitle('Leads');
            setLeftHeaderAction(null);
        }

        // Cleanup on unmount or view change
        return () => {
            // Optional: could reset here, but the next effect run usually handles it.
            // Relying on the 'else' block above for listing/creation views.
        };
    }, [view, selectedLead, setPanelTitle, setLeftHeaderAction, hasLeads]);





    useEffect(() => {
        const currentHasLeads = leads.length > 0;
        if (!initialLead && !currentHasLeads && view === 'listing' && !checkingLeads) {
            if (pipelines.length > 0) {
                handleCreateLead();
            } else {
                setView('creation');
            }
        }
    }, [leads, view, pipelines, initialLead, checkingLeads]);


    useEffect(() => {
        if (view === 'creation' && !form.pipelineId && pipelines.length > 0) {
            const defaultPipe = pipelines.find(p => p.is_default) || pipelines[0];
            if (defaultPipe) {
                const defaultStageId = (defaultPipe.stages && defaultPipe.stages.length > 0) ? defaultPipe.stages[0].id : '';

                setForm(prev => ({
                    ...prev,
                    pipelineId: defaultPipe.id,
                    stageId: defaultStageId
                }));

                // Trigger suggestion
                triggerSuggestion();
                suggestionTriggeredRef.current = true;
            }
        }
    }, [view, form.pipelineId, pipelines]);

    useEffect(() => {
        if (!initialLoadComplete && leads.length > 0 && !selectedLead && !initialLead) {
            setView('listing');
            setInitialLoadComplete(true);
        }
    }, [leads, initialLoadComplete, selectedLead, initialLead]);

    // Sync Props to State (especially for dashboard toggles)
    useEffect(() => {
        if (initialLead) {
            console.log('Syncing initialLead to state:', initialLead);
            setSelectedLead(initialLead);
            setView('details');
        } else if (initialView) {
            console.log('Syncing initialView to state:', initialView);
            setView(initialView);
        }
    }, [initialLead, initialView]);

    const triggerSuggestion = () => {
        setIsAnalyzing(true);
        postWindowMessage('TRIGGER_LEAD_SUGGESTION', {});
    };

    const handleCreateLead = () => {
        let defaultPipelineId = '';
        let defaultStageId = '';

        if (pipelines.length > 0) {
            const defaultPipe = pipelines.find(p => p.is_default) || pipelines[0];
            defaultPipelineId = defaultPipe.id;
            if (defaultPipe.stages && defaultPipe.stages.length > 0) {
                defaultStageId = defaultPipe.stages[0].id;
            }
        }

        setForm(prev => ({
            ...prev,
            title: '',
            expectedValue: '',
            closingDate: '',
            pipelineId: defaultPipelineId,
            stageId: defaultStageId,
            priority: 'HOT',
            currency: 'INR'
        }));

        // Trigger AI suggestion
        triggerSuggestion();
        suggestionTriggeredRef.current = true;

        setView('creation');
    };

    useEffect(() => {
        const currentHasLeads = leads.length > 0;
        if (view === 'listing' && currentHasLeads && setHeaderActions && !isRestrictedContext) {
            setHeaderActions(
                <button
                    className="cq-btn-secondary"
                    style={{
                        padding: '4px 12px',
                        fontSize: '13px',
                        height: '32px',
                        display: 'flex',
                        alignItems: 'center'
                    }}
                    onClick={handleCreateLead}
                >
                    Create New
                </button>
            );
        } else if (setHeaderActions) {
            setHeaderActions(null);
        }

        return () => {
            if (setHeaderActions) setHeaderActions(null);
        };
    }, [view, leads, setHeaderActions, isRestrictedContext, pipelines]);

    // 1. Effect: Update activeChatIdRef when chatId changes
    useEffect(() => {
        activeChatIdRef.current = chatId;
    }, [chatId]);

    // 2. Effect: Reset form and context when chatId becomes null
    useEffect(() => {
        if (!chatId) {
            setCustomerId(null);
            setIsRestrictedContext(true);
            setForm(prev => ({
                firstName: '',
                lastName: '',
                phone: '',
                email: '',
                company: null,
                designation: '',
                title: '',
                expectedValue: '',
                closingDate: '',
                source: '',
                address: '',
                city: '',
                state: '',
                zip: '',
                country: ''
            }));
            // setCurrentChatId(null); // This is now handled by activeChatIdRef
        }
    }, [chatId]);

    // 3. Effect: Handle Global Setup (Post Message Listener)
    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'CUSTOMER_UPDATE') {
                const { actionType, data } = payload || {};
                if (actionType === 'CUSTOMER_RETRIEVED' && data) {
                    const customer = data;
                    if (customer.id) setCustomerId(customer.id);
                    setForm(prev => ({
                        ...prev,
                        email: customer.email || prev.email,
                        source: customer.source || prev.source,
                        company: customer.company || null,
                        designation: customer.company?.relationship_type || prev.designation,
                        address: customer.address || '',
                        city: customer.city || '',
                        state: customer.state || '',
                        zip: customer.zip_code || '',
                        country: customer.country || '',
                        firstName: customer.first_name || prev.firstName,
                        lastName: customer.last_name || prev.lastName
                    }));
                } else if ((actionType === 'CUSTOMER_CREATED' || actionType === 'CUSTOMER_UPDATED') && data) {
                    const id = data.customer_id || data.id;
                    if (id) setCustomerId(id);
                }
                // Post-creation handler for pipelines (moved from original fetchChatData)
                const newPipelineData = payload.data;
                if (newPipelineData && newPipelineData.id && newPipelineData.name) { // Basic validation
                    const mappedNewPipeline = mapPipelineToUI(newPipelineData);
                    setPipelines(prev => [...prev, mappedNewPipeline]);
                }
            } else if (type === 'DELETE_PIPELINE_SUCCESS') {
                const { pipelineId } = payload;
                if (pipelineId) {
                    setPipelines(prev => prev.filter(p => p.id !== pipelineId));
                }
            } else if (type === 'PIPELINES_LIST') {
                const data = payload;
                const newPipelineList = (Array.isArray(data) ? data : (data.pipelines || data.results || [])).map(mapPipelineToUI);
                setPipelines(prev => {
                    const newHasStages = newPipelineList.some(p => p.stages && p.stages.length > 0);
                    const prevHasStages = prev.some(p => p.stages && p.stages.length > 0);
                    if (prevHasStages && !newHasStages) return prev;
                    return newPipelineList;
                });
            } else if (type === 'LEAD_GET_SUCCESS') {
                const fetchedLeads = Array.isArray(payload) ? payload : (payload.leads || payload.results || []);
                setLeads(fetchedLeads);
                setCheckingLeads(false);
                if (switchToListingRef.current) {
                    setView('listing');
                    switchToListingRef.current = false;
                }
            } else if (type === 'LEAD_CREATE_SUCCESS') {
                const newLead = payload;
                if (newLead && newLead.id) {
                    setLeads(prev => {
                        const exists = prev.some(l => String(l.id) === String(newLead.id));
                        if (exists) return prev;
                        return [newLead, ...prev];
                    });
                    setCheckingLeads(false);
                    setView('listing');
                }
            } else if (type === 'LEAD_DELETE_SUCCESS') {
                const deletedLeadId = payload.id || payload.lead_id;
                if (deletedLeadId) {
                    setLeads(prev => prev.filter(l => String(l.id) !== String(deletedLeadId)));
                    setCheckingLeads(false);
                }
            } else if (type === 'LEAD_SUGGESTION_SUCCESS') {
                const suggestion = payload;
                setIsAnalyzing(false);
                const activeChatId = activeChatIdRef.current;
                const normalizeId = (id) => id ? String(id).replace(/@.*$/, '') : '';
                if (normalizeId(suggestion.whatsapp_chat_id) !== normalizeId(activeChatId)) return;

                setForm(prev => {
                    const newForm = { ...prev };
                    if (!newForm.title && suggestion.title) newForm.title = suggestion.title;
                    if (!newForm.expectedValue && suggestion.expected_value) newForm.expectedValue = suggestion.expected_value;
                    if (suggestion.priority) newForm.priority = suggestion.priority.toUpperCase();
                    if (!newForm.closingDate && suggestion.expected_closing_date) newForm.closingDate = suggestion.expected_closing_date;
                    if (suggestion.currency_type) newForm.currency = suggestion.currency_type;
                    return newForm;
                });
            } else if (type === 'PIPELINE_CREATED_SUCCESS') {
                const newPipelineData = payload.data || payload; // Handle nested data
                if (newPipelineData && newPipelineData.id) {
                    const mappedNewPipeline = mapPipelineToUI(newPipelineData);
                    setPipelines(prev => [...prev.filter(p => !p.is_temp), mappedNewPipeline]);
                }
            } else if (type === 'LEAD_UPDATE_SUCCESS') {
                addToast({
                    message: 'Lead updated successfully',
                    type: 'success',
                    duration: 3000
                });
            } else if (type === 'LEAD_UPDATE_ERROR') {
                addToast({
                    message: 'Failed to update lead',
                    type: 'error',
                    duration: 3000
                });
            }
        };

        window.addEventListener('message', handleMessage);
        if (!pipelinesFetchedRef.current) {
            postWindowMessage('GET_PIPELINES', {});
            pipelinesFetchedRef.current = true;
        }

        return () => window.removeEventListener('message', handleMessage);
    }, []); // Empty dependency array for global listener

    // 4. Effect: Handle Chat Data Fetching
    useEffect(() => {
        const fetchChatData = async () => {
            if (!chatId) {
                setCustomerId(null);
                setIsRestrictedContext(true);
                setLoading(false); // Ensure loading is false if no chat
                return;
            }

            try {
                // Safeguard against missing WPP (e.g. in Dashboard overlay)
                if (!window.WPP || !window.WPP.chat) {
                    setIsRestrictedContext(false); // Assume unrestricted if WPP is missing (Dashboard mode)
                    setLoading(false);
                    return;
                }

                setIsRestrictedContext(false);

                const isIndiv = await isIndividualChat(chatId);
                if (!isIndiv) {
                    setIsRestrictedContext(true);
                    setLoading(false);
                    return;
                }

                // Reset Leads/Form for new chat
                setLeads([]);
                setCheckingLeads(true);
                setCustomerId(null);
                suggestionTriggeredRef.current = false;

                const number = await getActiveChatNumber();
                let name = '';
                try { name = await getContactName(chatId, true); } catch (e) { console.error('Error getting contact name:', e); }

                const nameParts = (name || '').trim().split(/\s+/);
                setForm({
                    firstName: nameParts[0] || '',
                    lastName: nameParts.slice(1).join(' ') || '',
                    phone: number ? (String(number).startsWith('+') ? number : `+${number}`) : '',
                    email: '', source: '', company: null, designation: '', title: '',
                    expectedValue: '', closingDate: '', address: '', city: '', state: '', zip: '', country: ''
                });

                postWindowMessage('CUSTOMER_GET', { chat_id: chatId });
                postWindowMessage('LEAD_GET', { chat_id: chatId });
                setLoading(false);
            } catch (e) {
                console.error('Error fetching chat data:', e);
                setLoading(false);
                setIsRestrictedContext(true);
            }
        };

        fetchChatData();

        // Only reset if NOT in initial lead/view mode (dashboard mode)
        if (!initialLead && !initialView) {
            setView('listing');
            setSelectedLead(null);
        }
    }, [chatId, initialLead, initialView]); // Re-run when chatId or initial props change


    useEffect(() => {
        if (view === 'creation' && chatId && !suggestionTriggeredRef.current) {
            triggerSuggestion();
            suggestionTriggeredRef.current = true;
        }
    }, [chatId, view]);

    const groupedLeads = React.useMemo(() => {
        if (!leads.length) return [];

        const groups = {};
        leads.forEach(lead => {
            let pipeId = lead.pipeline_id || lead.pipelineId;

            // If pipeline_id is missing, try to find it via stage_id
            if (!pipeId && lead.stage_id) {
                const foundPipe = pipelines.find(p => (p.stages || []).some(s => String(s.id) === String(lead.stage_id)));
                if (foundPipe) {
                    pipeId = foundPipe.id;
                }
            }

            // Fallback for key
            const groupKey = pipeId || 'unknown';

            if (!groups[groupKey]) {
                const pipe = pipelines.find(p => String(p.id) === String(pipeId));

                groups[groupKey] = {
                    id: pipeId || '',
                    pipeline: pipe ? pipe.name : 'Unknown Pipeline',
                    leads: []
                };
            }

            // Map stage color and name
            const pipe = pipelines.find(p => String(p.id) === String(pipeId));
            const stage = pipe ? (pipe.stages || []).find(s => String(s.id) === String(lead.stage_id)) : null;

            groups[groupKey].leads.push({
                id: lead.id,
                pipeline_id: pipeId,
                stage_id: lead.stage_id,
                title: lead.title,
                currencyType: lead.currency_type,
                expectedValue: lead.expected_value,
                source: lead.source,
                stage: stage ? stage.name : 'Unknown Stage',
                stageColor: stage ? stage.color : '#ccc',
                stageProbability: stage ? stage.probability : '',
                closingDate: lead.expected_closing_date,
                priority: lead.priority
            });
        });

        return Object.values(groups);
    }, [leads, pipelines]);


    const handleContactUpdate = (data) => {
        setForm(prev => ({ ...prev, ...data }));
    };

    const handleLeadClick = (lead) => {
        setSelectedLead(lead);
        setView('details');
    };

    if (loading) {
        return <div className="cq-lead-creation" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>Loading...</div>;
    }

    // Bypass restriction check if we have an initial lead or selected lead (dashboard mode)
    if (isRestrictedContext && !selectedLead && !initialLead) {
        return (
            <div className="cq-lead-creation" style={{ height: '100%' }}>
                <EmptyState
                    icon={icons.INFO}
                    heading="Lead Management not available"
                    description="Leads can only be managed for individual contacts, you can only attach leads to groups."
                    action={null}
                />
            </div>
        );
    }

    const forceExpanded = !customerId;

    return (
        <>
            {view === 'listing' ? (
                <LeadListing
                    onCreateLead={handleCreateLead}
                    contact={form}
                    onContactUpdate={handleContactUpdate}
                    onUpdateLead={handleLeadUpdate}
                    chatId={chatId}
                    customerId={customerId}
                    forceExpanded={forceExpanded}
                    leads={groupedLeads}
                    pipelines={pipelines}
                    setLeads={setLeads}
                    onLeadClick={handleLeadClick}
                />
            ) : view === 'creation' ? (
                <LeadCreation
                    onCancel={() => setView('listing')}
                    contact={form}
                    onContactUpdate={handleContactUpdate}
                    chatId={chatId}
                    customerId={customerId}
                    hasLeads={hasLeads}
                    forceExpanded={forceExpanded}
                    isAnalyzing={isAnalyzing}
                    pipelines={pipelines}
                />
            ) : (
                <LeadDetailsPanel
                    lead={selectedLead}
                    pipelines={pipelines}
                    onBack={() => setView('listing')}
                    onUpdate={handleLeadUpdate}
                />
            )}
        </>
    );
};

export default LeadsPanel;
