import React, { useState, useEffect, useRef } from 'react';
import { icons } from '../../Constants/svg';
import Icon from '../UIComponents/Icon';
import TextAreaBox from '../UIComponents/TextAreaBox';
import RelativeTime from '../UIComponents/RelativeTime';
import { getActiveChatId } from '../../utils/WppFunctions';
import { postWindowMessage, sendMessage } from '../../utils/messageSender';
import { TRACK_EVENTS } from '../../Constants/constant';
import './ChatNotes.css';
import ArtifactIconCard from '../UIComponents/ArtifactIconCard';
import { isDarkMode } from '../../utils/utils';

const ChatNotes = ({ isOpen, chatId: initialChatId }) => {
  const isDark = isDarkMode();
  const [notes, setNotes] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [editingIndex, setEditingIndex] = useState(null);
  const [currentChatId, setCurrentChatId] = useState(initialChatId);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [hasNextPage, setHasNextPage] = useState(false);
  const [totalCount, setTotalCount] = useState(0);
  const [nextPageNumber, setNextPageNumber] = useState(null);
  const [previousPageNumber, setPreviousPageNumber] = useState(null);

  const popupRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const handleMessage = (event) => {
      if (event.source !== window) return;
      
      const { type, payload } = event.data;
      if ((type == 'CHAT_ARTIFACTS_UPDATED' || type == 'CHAT_ARTIFACT_UPDATE') && payload.chatId === currentChatId && payload.dataType === 'notes') {
        handleNotesUpdate(payload);
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [currentChatId]);

  const handleNotesUpdate = (response) => {
    const notesData = response.data;
    const nextUrl = response.paginationMeta.next;
    
    // Always update totalCount from pagination metadata
    if (response.paginationMeta && response.paginationMeta.count !== undefined) {
      console.log('Total count from pagination metadata:', response.paginationMeta.count);
      setTotalCount(response.paginationMeta.count);
    }

    // Only update UI state if the panel is open
    if (isOpen && Array.isArray(notesData)) {
      const transformedNotes = notesData.map(note => ({
        id: note.id,
        text: note.main_content,
        timestamp: note.created_at
      }));
      
      if (isLoadingMore && currentPage > 1) {
        // Append new data for pagination
        setNotes(prev => {
          const allNotes = [...prev, ...transformedNotes];
          const deduplicated = Array.from(new Map(allNotes.map(note => [note.id, note])).values());
          return deduplicated;
        });
      } else {
        setNotes(transformedNotes);
        setCurrentPage(1);
      }
      if (nextUrl) {
        const url = new URL(nextUrl);
        const pageFromUrl = parseInt(url.searchParams.get('page'), 10);
        setHasNextPage(true);
        setNextPageNumber(pageFromUrl);
        setPreviousPageNumber(pageFromUrl > 1 ? pageFromUrl - 1 : null);
      } else {
        setHasNextPage(false);
        setNextPageNumber(null);
      }
    }
    setIsLoading(false);
    setIsLoadingMore(false);
  };


  const loadMoreNotes = () => {
    if (!hasNextPage || isLoadingMore || !nextPageNumber) return;
    
    setIsLoadingMore(true);
    setCurrentPage(nextPageNumber);
    
    postWindowMessage('CHAT_ARTIFACTS_FETCH', { 
      chatId: currentChatId, 
      data_type: "notes",
      page: nextPageNumber,
      page_size: 10
    });
  };

  const resetPagination = () => {
    setCurrentPage(1);
    setHasNextPage(false);
    setNextPageNumber(null);
    setTotalCount(0);
    setNotes([]);
  };

  useEffect(() => {
    getActiveChatId().then(id => {
      if (id) {
        setCurrentChatId(id);
        // API will be called by the second useEffect when currentChatId changes
      }
    });

    const handleChatChange = (chat) => {
      const chatId = chat?.id?._serialized;
      setCurrentChatId(chatId);
      setEditingIndex(null);
      resetPagination();
    };

    window.WPP.on('chat.active_chat', handleChatChange);

    return () => {
      window.WPP.off('chat.active_chat', handleChatChange);
    };
  }, []);

  useEffect(() => {
    if (currentChatId) {
      setIsLoading(true);
      resetPagination();
      postWindowMessage('CHAT_ARTIFACTS_FETCH', { 
        chatId: currentChatId, 
        data_type: "notes",
        page: 1,
        page_size: 10
      });
    } else {
      resetPagination();
    }
  }, [currentChatId]);

  const handleAddNote = async () => {
    if (inputValue.trim() === '' || !currentChatId) return;

    setIsLoading(true);
    
    if (editingIndex !== null) {
      await handleUpdateNote();
    } else {
      await handleCreateNote();
    }
  };

  const handleCreateNote = async () => {
    const noteText = inputValue.trim();

    try {
      await postWindowMessage('CHAT_ARTIFACTS_CREATE', {
        chatId: currentChatId,
        main_content: noteText,
        data_type: 'notes'
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.NOTE_CREATED,
        properties: { chatId: currentChatId }
      });
      setInputValue('');
    } catch (error) {
      console.error('Failed to create note:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateNote = async () => {
    const noteText = inputValue.trim();
    const noteToUpdate = notes[editingIndex];

    if (!noteToUpdate) return;

    try {
      await postWindowMessage('CHAT_ARTIFACTS_UPDATE', {
        chatId: currentChatId,
        artifact_id: noteToUpdate.id,
        main_content: noteText,
        data_type: 'notes',
        paginationMeta: {
          hasNextPage: !!nextPageNumber,
          count: totalCount,
          next: nextPageNumber,
          previous: previousPageNumber,
          currentPage: currentPage
      }
    });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.NOTE_UPDATED,
        properties: { chatId: currentChatId, noteId: noteToUpdate.id }
      });
      setEditingIndex(null);
      setInputValue('');
    } catch (error) {
      console.error('Failed to update note:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditNote = (index) => {
    setInputValue(notes[index].text);
    setEditingIndex(index);
  };

  const handleDeleteNote = async (index) => {
    if (!currentChatId) return;

    const noteToDelete = notes[index];
    if (!noteToDelete) return;

    setIsLoading(true);

    try {
      await postWindowMessage('CHAT_ARTIFACTS_DELETE', {
        chatId: currentChatId,
        artifact_id: noteToDelete.id,
        data_type: 'notes',
        paginationMeta: {
          hasNextPage: !!nextPageNumber,
          count: totalCount-1,
          next: nextPageNumber,
          previous: previousPageNumber,
          currentPage: currentPage
      }
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.NOTE_DELETED,
        properties: { chatId: currentChatId, noteId: noteToDelete.id }
      });
    } catch (error) {
      console.error('Failed to delete note:', error);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="cq-chatnotes-popup" ref={popupRef} style={{ backgroundColor: isDark ? '#1f2c33' : '#f0f2f5' }}>
        {currentChatId ? (
            <>
                <div className="cq-chatnotes-container" ref={containerRef}>
                    {isLoading && notes.length === 0 ? (
                        <div className="cq-chatnotes-empty-state">
                            <div className="cq-chatnotes-empty-icon">{icons.NOTE}</div>
                            <div className="cq-chatnotes-empty-title">Loading notes...</div>
                            <div className="cq-chatnotes-empty-description">
                                Please wait while we load your notes.
                            </div>
                        </div>
                    ) : notes.length > 0 ? (
                        notes.map((note, index) => (
                            <ArtifactIconCard
                                key={note.id}
                                index={index}
                                icon={icons.NOTE}
                                description={note.text}
                                footerItems={[
                                    {
                                        text: <RelativeTime timestamp={note.timestamp} />,
                                    },
                                ]}
                                actions={[
                                    {
                                        icon: icons.EDIT,
                                        tooltip: "Edit Note",
                                        label: "Edit",
                                        onClick: () => handleEditNote(index),
                                        disabled: isLoading,
                                    },
                                    {
                                        icon: icons.DELETE,
                                        tooltip: "Delete Note",
                                        label: "Delete",
                                        onClick: () => {
                                            const confirmed = window.confirm('Are you sure you want to delete this note?');
                                            if (confirmed) {
                                                handleDeleteNote(index);
                                            }
                                        },
                                        disabled: isLoading,
                                    },
                                ]}
                            />
                        ))
                    ) : (
                        <div className="cq-chatnotes-empty-state">
                            <div className="cq-chatnotes-empty-icon">{icons.NOTE}</div>
                            <div className="cq-chatnotes-empty-title">No notes yet</div>
                            <div className="cq-chatnotes-empty-description">
                                Start adding notes to keep track of important information from this chat.
                            </div>
                        </div>
                    )}
                    {hasNextPage && notes.length > 0 && (
                        <div style={{ textAlign: 'center', padding: '20px' }}>
                            <button 
                                onClick={loadMoreNotes}
                                disabled={isLoadingMore}
                                style={{
                                    padding: '10px 20px',
                                    backgroundColor: '#25d366',
                                    color: 'white',
                                    border: 'none',
                                    borderRadius: '8px',
                                    cursor: isLoadingMore ? 'not-allowed' : 'pointer',
                                    fontSize: '14px',
                                    fontWeight: '500',
                                    opacity: isLoadingMore ? 0.6 : 1
                                }}
                            >
                                {isLoadingMore ? 'Loading...' : 'Load More Notes'}
                            </button>
                        </div>
                    )}
                </div>
                <div className="cq-chatnotes-input-fixed">
                    <div className="cq-chatnotes-input">
                        <div style={{ position: 'relative' }}>
                            <TextAreaBox
                                value={inputValue}
                                onChange={(e) => setInputValue(e.target.value)}
                                placeholder="Add a note..."
                            />
                        </div>
                        <button 
                            onClick={handleAddNote} 
                            className="cq-chatnotes-button"
                            disabled={isLoading || inputValue.trim() === ''}
                        >
                            {isLoading ? '...' : editingIndex !== null ? 'Update' : 'Add'}
                        </button>
                    </div>
                </div>
            </>
        ) : (
            <div className="cq-chatnotes-container">
              <div className="cq-chatnotes-empty-state">
                  <div className="cq-chatnotes-empty-icon">{icons.NOTE}</div>
                  <div className="cq-chatnotes-empty-title">Select Chat</div>
                  <div className="cq-chatnotes-empty-description">
                      Please select a chat to see the notes.
                  </div>
              </div>
            </div>
        )}
    </div>
  );
};

export default ChatNotes;