import React, { useMemo, useState, useRef, useEffect, useLayoutEffect } from 'react';
import Stepper from '../../UIComponents/Stepper/Stepper';

const LeadStages = ({ lead, stages = [], pipelineName, onStageChange }) => {

    const normalizedStages = useMemo(() => {
        if (!Array.isArray(stages)) return [];
        return stages.map(s => {
            let prob = s.probability;
            if (prob === undefined && s.meta) prob = s.meta.probability;

            // Ensure probability is a number
            if (prob !== undefined && prob !== null) {
                prob = parseFloat(prob);
            }

            return {
                ...s,
                id: s.id,
                name: s.name || s.label,
                color: s.color || (s.meta && s.meta.color) || '#d1d5db',
                probability: prob
            };
        });
    }, [stages]);

    const wonStage = useMemo(() => normalizedStages.find(s => s.probability === 100 || s.probability === 1) || { id: 'Won', name: 'Won', color: '#16a34a' }, [normalizedStages]);
    const lostStage = useMemo(() => normalizedStages.find(s => s.probability === 0) || { id: 'Lost', name: 'Lost', color: '#ef4444' }, [normalizedStages]);

    const dynamicStages = useMemo(() => {
        // Filter out completed stages if they are marked as such via probability
        // Check for 100% (100 or 1)
        const ongoingStages = normalizedStages.filter(s => {
            const p = s.probability;
            return p !== 100 && p !== 1 && p !== 0 && !s.is_final;
        });

        const syntheticStage = {
            id: 'combined_closed',
            name: (wonStage.name || 'Won') + ' ▼',
            color: wonStage.color || '#16a34a',
            probability: 100,
            is_combined: true
        };

        const currentStageName = lead.pipeline || lead.stage;

        // Helper to parse probability safely
        const getProb = (p) => {
            if (p === undefined || p === null) return null;
            return parseFloat(String(p).replace('%', ''));
        };
        const leadProb = getProb(lead.probability) !== null ? getProb(lead.probability) : getProb(lead.stageProbability);

        const isLost = currentStageName === lostStage.name ||
            currentStageName === 'Lost' ||
            (lead.stage_id && lead.stage_id === lostStage.id) ||
            leadProb === 0;

        if (isLost) {
            syntheticStage.name = (lostStage.name || 'Lost') + ' ▼';
            syntheticStage.color = lostStage.color || '#ef4444';
            syntheticStage.probability = 0;
        }

        return [...ongoingStages, syntheticStage];
    }, [normalizedStages, lead.pipeline, lead.stage, wonStage, lostStage]);

    const [showClosedOptions, setShowClosedOptions] = useState(false);
    const optionsRef = useRef(null);
    const containerRef = useRef(null);
    const [dropdownStyle, setDropdownStyle] = useState({
        position: 'absolute',
        opacity: 0,
        zIndex: 100
    });

    const currentStageId = useMemo(() => {
        const currentStageName = lead.pipeline || lead.stage;

        const ongoingMatch = normalizedStages.find(s =>
            (s.id === lead.stage_id || s.name === currentStageName) &&
            s.probability !== 100 &&
            s.probability !== 1 &&
            s.probability !== 0 &&
            !s.is_final
        );

        if (ongoingMatch) return ongoingMatch.id;

        const isWon = currentStageName === wonStage.name || lead.stage_id === wonStage.id || currentStageName === 'Won';
        const isLost = currentStageName === lostStage.name || lead.stage_id === lostStage.id || currentStageName === 'Lost';

        if (isWon || isLost) {
            return 'combined_closed';
        }

        const inDynamic = dynamicStages.find(s => s.name === currentStageName);
        if (inDynamic) return inDynamic.id;

        return null;
    }, [normalizedStages, lead.pipeline, lead.stage, lead.stage_id, wonStage, lostStage, dynamicStages]);


    useLayoutEffect(() => {
        if (showClosedOptions && containerRef.current) {
            const steps = containerRef.current.querySelectorAll('.cq-stepper .cq-stepper-step');
            const lastStep = steps[steps.length - 1];

            if (lastStep) {
                const stepRect = lastStep.getBoundingClientRect();
                const containerRect = containerRef.current.getBoundingClientRect();
                const chevronOffset = 12;

                setDropdownStyle({
                    position: 'absolute',
                    top: (stepRect.bottom - containerRect.top) + 'px',
                    left: (stepRect.left - containerRect.left + chevronOffset) + 'px',
                    width: (stepRect.width - chevronOffset) + 'px',
                    zIndex: 100,
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '2px',
                    marginTop: '4px',
                    background: 'transparent',
                    opacity: 1
                });
            }
        }
    }, [showClosedOptions, dynamicStages]);


    useEffect(() => {
        const handleClickOutside = (event) => {
            if (optionsRef.current && !optionsRef.current.contains(event.target)) {
                setShowClosedOptions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleStepChange = (stageId) => {
        if (stageId === 'combined_closed') {
            setShowClosedOptions(prev => !prev);
            return;
        }

        const stageObj = normalizedStages.find(s => s.id === stageId);
        if (onStageChange && stageObj) {
            onStageChange(stageObj);
            setShowClosedOptions(false);
        }
    };

    const handleClosedOptionSelect = (type) => {
        const targetStage = type === 'Won' ? wonStage : lostStage;

        if (onStageChange && targetStage) {
            onStageChange({
                ...targetStage,
                id: targetStage.id || type,
                name: targetStage.name || type,
                probability: targetStage.probability !== undefined ? targetStage.probability : (type === 'Won' ? 100 : 0)
            });
        }
        setShowClosedOptions(false);
    };

    return (
        <div ref={containerRef} style={{ position: 'relative' }}>
            <Stepper
                title={pipelineName || "Standard Sales Pipeline"}
                steps={dynamicStages}
                activeStep={currentStageId}
                stepData={{}}
                onStepChange={handleStepChange}
            />
            {showClosedOptions && (
                <div
                    ref={optionsRef}
                    className="cq-closed-options-dropdown"
                    style={dropdownStyle}
                >
                    <div
                        onClick={() => handleClosedOptionSelect('Won')}
                        className="cq-stepper-step cq-dropdown-option"
                        style={{
                            color: wonStage.color || '#16a34a', // Stage text color
                        }}
                    >
                        {wonStage.name || 'Won'}
                    </div>
                    <div
                        onClick={() => handleClosedOptionSelect('Lost')}
                        className="cq-stepper-step cq-dropdown-option"
                        style={{
                            color: lostStage.color || '#ef4444', // Stage text color
                        }}
                    >
                        {lostStage.name || 'Lost'}
                    </div>
                </div>
            )}
        </div>
    );
};

export default LeadStages;
