import React from 'react';

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null, errorInfo: null };
    }

    static getDerivedStateFromError(error) {
        // Update state so the next render will show the fallback UI.
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        // Log the error to the console with full details
        console.error('ErrorBoundary caught an error:', error);
        console.error('Error details:', errorInfo);
        console.error('Component stack:', errorInfo.componentStack);

        // Update state with error details
        this.setState({
            error,
            errorInfo
        });
    }

    render() {
        if (this.state.hasError) {
            const isDark = this.props.isDark || false;

            // You can render any custom fallback UI
            return (
                <div style={{
                    padding: '20px',
                    margin: '20px',
                    backgroundColor: isDark ? '#2a1f1f' : '#ffebee',
                    border: `2px solid ${isDark ? '#5c1e1e' : '#e57373'}`,
                    borderRadius: '8px',
                    color: isDark ? '#ff6b6b' : '#d32f2f'
                }}>
                    <h2 style={{ marginTop: 0 }}>Something went wrong</h2>
                    <details style={{ whiteSpace: 'pre-wrap', fontSize: '12px', marginTop: '10px' }}>
                        <summary style={{ cursor: 'pointer', fontWeight: 'bold', marginBottom: '10px' }}>
                            Error Details (Click to expand)
                        </summary>
                        <div style={{
                            backgroundColor: isDark ? '#1a1a1a' : '#fff',
                            padding: '10px',
                            borderRadius: '4px',
                            marginTop: '10px',
                            maxHeight: '300px',
                            overflow: 'auto'
                        }}>
                            <p><strong>Error:</strong> {this.state.error && this.state.error.toString()}</p>
                            <p><strong>Stack:</strong></p>
                            <pre style={{ fontSize: '11px', overflow: 'auto' }}>
                                {this.state.error && this.state.error.stack}
                            </pre>
                            {this.state.errorInfo && (
                                <>
                                    <p><strong>Component Stack:</strong></p>
                                    <pre style={{ fontSize: '11px', overflow: 'auto' }}>
                                        {this.state.errorInfo.componentStack}
                                    </pre>
                                </>
                            )}
                        </div>
                    </details>
                    <button
                        onClick={() => this.setState({ hasError: false, error: null, errorInfo: null })}
                        style={{
                            marginTop: '15px',
                            padding: '8px 16px',
                            backgroundColor: isDark ? '#00d9ff' : '#007bff',
                            color: isDark ? '#111b21' : '#fff',
                            border: 'none',
                            borderRadius: '6px',
                            cursor: 'pointer',
                            fontWeight: '600'
                        }}
                    >
                        Try Again
                    </button>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;
