import React from 'react';
import { createRoot } from 'react-dom/client';
import DashboardContainer from './Dashboard/DashboardContainer';
import { renderSidePanel } from '../../utils/renderSidePanel';
import LeadsPanel from './LeadsPanel';
import { postWindowMessage } from '../../utils/messageSender';

const DASHBOARD_ID = 'cq-dashboard-overlay';
const DASHBOARD_OVERLAY_MASK_ID = 'cq-dashboard-mask';

// Helper to find the main panel relative to the stable sidebar
const getMainContentPanel = () => {
    const sidePanel = document.getElementById('side');
    if (!sidePanel || !sidePanel.parentElement) return null;
    return sidePanel.parentElement.nextElementSibling;
};

// State check logic
const isChatOpen = () => {
    // Simplified logic: Check for #main inside the main content panel
    const mainPanel = getMainContentPanel();
    if (!mainPanel) return false;
    return !!mainPanel.querySelector('#main');
};

const initNavigationObserver = (mainPanel, dashboard, dashboardMask) => {
    const checkState = () => {
        const chatOpen = isChatOpen();
        // Check for .cq-wide-sidepanel existence
        const sidePanelOpen = !!document.querySelector('.cq-wide-sidepanel');
        const isSidebarClosed = document.body.classList.contains('cq-sidebar-closed');

        const isVisible = !chatOpen && !isSidebarClosed && !sidePanelOpen;
        postWindowMessage('DASHBOARD_VISIBILITY_CHANGE', { isVisible });

        if (chatOpen || isSidebarClosed) {
            // Chat is open OR Sidebar is collapsed -> Hide Dashboard by moving off-screen
            dashboard.style.left = '-100%';
        } else {
            // No chat open AND Sidebar is open -> Show Dashboard
            dashboard.style.left = '0';

            // Handle Side Panel Interaction
            if (sidePanelOpen) {
                // Side Panel Open: Apply mask and prevent interactions
                dashboardMask.style.display = 'block';
                dashboard.style.pointerEvents = 'none';
            } else {
                // Side Panel Closed: Normal interaction
                dashboardMask.style.display = 'none';
                dashboard.style.pointerEvents = 'auto';
            }
        }
    };

    // Run once immediately
    checkState();

    // Observe the Main Panel for child list changes (e.g. Chat view replacing Intro view)
    const navObserver = new MutationObserver(() => {
        checkState();
    });

    navObserver.observe(mainPanel, {
        childList: true,
        subtree: true
    });

    // Observe Side Panel changes
    // Detect where side panels are injected (header parent) and observe that container
    const checkSidePanel = () => {
        const header = document.querySelector('#app header');
        const appContainer = header ? header.parentElement : null;

        if (appContainer) {
            const sidePanelObserver = new MutationObserver(() => {
                checkState();
            });
            sidePanelObserver.observe(appContainer, {
                childList: true
            });
        } else {
            // Retry if app structure not yet ready
            setTimeout(checkSidePanel, 500);
        }
    };
    checkSidePanel();

    // Observe Body Class changes (for Sidebar Collapse state)
    const bodyObserver = new MutationObserver(() => {
        checkState();
    });
    bodyObserver.observe(document.body, {
        attributes: true,
        attributeFilter: ['class']
    });
};

export const mountDashboard = () => {
    // Wait for WA to load initially (side panel presence)
    const loader = setInterval(() => {
        const sidePanel = document.getElementById('side');
        if (sidePanel) {
            clearInterval(loader);
            injectDashboard();
        }
    }, 500);
};

const injectDashboard = () => {
    const mainPanel = getMainContentPanel();
    if (!mainPanel || document.getElementById(DASHBOARD_ID)) return;

    // 1. Create the Main Wrapper (Fixed Overlay)
    const wrapper = document.createElement('div');
    wrapper.id = DASHBOARD_ID;

    // CSS to overlap completely
    Object.assign(wrapper.style, {
        position: 'fixed',
        top: '0',
        left: '0',
        width: '100%',
        height: '100%',
        zIndex: '999',
        backgroundColor: '#f0f2f5',
        left: '-100%', // Hidden by default (off-screen)
        overflow: 'hidden'
    });

    // 2. Create Content Container (for React)
    const contentContainer = document.createElement('div');
    contentContainer.style.width = '100%';
    contentContainer.style.height = '100%';
    wrapper.appendChild(contentContainer);

    // 3. Create Mask (Overlay for side panel)
    const mask = document.createElement('div');
    mask.id = DASHBOARD_OVERLAY_MASK_ID;
    Object.assign(mask.style, {
        position: 'absolute', // Absolute relative to fixed wrapper
        top: '0',
        left: '0',
        width: '100%',
        height: '100%',
        backgroundColor: 'rgba(255, 255, 255, 0.6)',
        zIndex: '10000', // Higher than content
        display: 'none',
        backdropFilter: 'blur(1px)'
    });
    wrapper.appendChild(mask);

    // 4. Ensure parent is positioned correctly (legacy check, mostly irrelevant for fixed wrapper)
    if (getComputedStyle(mainPanel).position === 'static') {
        mainPanel.style.position = 'relative';
    }

    // 5. Inject
    mainPanel.appendChild(wrapper);

    // Handle Lead Click
    const handleLeadClick = (lead, pipelines = []) => {
        // Map snake_case properties to camelCase expected by LeadDetailsPanel
        const mappedLead = {
            ...lead,
            expectedValue: lead.expected_value || lead.estimated_value,
            currencyType: lead.currency_type,
            closingDate: lead.expected_closing_date,
            pipelineId: lead.pipeline_id,
            stageId: lead.stage_id
        };

        renderSidePanel(
            LeadsPanel,
            {
                initialView: 'details',
                initialLead: mappedLead,
                showBackButton: false,
                initialPipelines: pipelines
            },
            {
                title: mappedLead.title || mappedLead.name,
                containerId: 'leads-panel',
                monitorChat: true
            }
        );
    };

    // 7. Start Observing for navigation changes BEFORE rendering
    // This ensures visibility/display is calculated before charts try to measure
    initNavigationObserver(mainPanel, wrapper, mask);

    // 6. Render React Component into Content Container (NOT Wrapper)
    const root = createRoot(contentContainer);
    root.render(<DashboardContainer onLeadClick={handleLeadClick} />);
};
