import React from 'react';
import ExpandableText from './ExpandableText';
import Icon from './Icon';
import './ArtifactIconCard.css';

const ArtifactIconCard = React.memo(
    ({
        index = 0, // used for staggered animation delay
        title,
        description,
        descriptionNode,
        isDark = false,
        footerItems = [], // [{ icon, text, color }]
        footer,           // Custom footer node (takes precedence over footerItems)
        actions = [],      // [{ icon, tooltip, label, onClick, disabled }]
        style = {},
        children
    }) => (
        <div
            className={`artifact-card ${isDark ? 'dark' : 'light'}`}
            style={{ animationDelay: `${index * 50}ms`, ...style }} // staggered delay + override
        >
            <div className="artifact-content" style={{ marginBottom: '8px' }}>
                {/* LEFT SECTION */}
                <div className="artifact-left">

                    {/* Title */}
                    {title && (
                        <div className="artifact-title">
                            {typeof title === 'string' ? (
                                <ExpandableText text={title} isDark={isDark} maxLength={30} />
                            ) : (
                                title
                            )}
                        </div>
                    )}

                    {/* Description */}
                    {descriptionNode ? (
                        <div className="artifact-description" style={{ marginBottom: '8px' }}>
                            {descriptionNode}
                        </div>
                    ) : (
                        description && (
                            <ExpandableText
                                text={description}
                                isDark={isDark}
                                maxLength={88}
                                className="artifact-description"
                                style={{
                                    marginBottom: '8px',
                                }}
                            />
                        )
                    )}

                </div>

                {/* ACTIONS */}
                <div className="artifact-actions">
                    {actions.map((action, idx) => (
                        <Icon
                            key={idx}
                            icon={action.icon}
                            tooltip={action.tooltip}
                            label={action.label}
                            onClick={action.onClick}
                            disabled={action.disabled}
                            size="small"
                            style={{
                                padding: '0 12px',
                            }}
                        />
                    ))}
                </div>
            </div>

            {/* EXPANDED CONTENT (Children) */}
            {children && (
                <div className="artifact-children" style={{ marginBottom: '8px' }}>
                    {children}
                </div>
            )}

            {/* FOOTER ITEMS */}
            {(footer || footerItems.length > 0) && (
                <div className="artifact-footer">
                    {footer ? (
                        footer
                    ) : (
                        footerItems.map((item, idx) => (
                            <React.Fragment key={idx}>

                                {/* SEPARATOR */}
                                {idx > 0 && <span className="artifact-separator">•</span>}

                                <div
                                    className="artifact-footer-item"
                                    style={{ color: item.color }}
                                >
                                    <span className="artifact-icon">{item.icon}</span>
                                    {item.text}
                                </div>

                            </React.Fragment>
                        ))
                    )}
                </div>
            )}
        </div>
    )
);

export default ArtifactIconCard;
