import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { icons } from '../../Constants/svg';
import { sendTextMessage } from '../../utils/WppFunctions';
import ChatSummarizer from '../ChatSummarizer/ChatSummarizer';
import { QuickReplyManager } from '../QuickReply/QuickReplyManager';
import ScheduledMessages from '../ScheduledMessages/ScheduledMessages';

import { getActiveChatId } from '../../utils/WppFunctions';
import Icon from '../UIComponents/Icon';
import TasksFolder from './TasksFolder';
import ConfirmationModal from '../UIComponents/ConfirmationModal';
import { renderSidePanel, closeSidePanel } from '../../utils/renderSidePanel';
import { postWindowMessage } from '../../utils/messageSender';
import { onBoarding } from '../../utils/onBoarding';
import LeadsPanel from '../Leads/LeadsPanel';
import { TRACK_EVENTS } from '../../Constants/constant';
import SettingsPanel from '../SettingsModal/SettingsPanel';
import './Sidebar.css';
import '../UIComponents/ConfirmationModal.css';

const CollapsibleSidebar = () => {
  const [isOpen, setIsOpen] = useState(true);
  const [noteCount, setNoteCount] = useState(0);
  const [todoCount, setTodoCount] = useState(0);
  const [reminderCount, setReminderCount] = useState(0);
  const [scheduledMessageCount, setScheduledMessageCount] = useState(0);
  const [currentChatId, setCurrentChatId] = useState(null);
  const sidebarRef = useRef(null);
  const [systemConfig, setSystemConfig] = useState(null);
  const [showSupportModal, setShowSupportModal] = useState(false);

  const checkOnboardingAndExecute = (callback) => {
    if (localStorage.getItem('IS_USER_ONBOARDED') !== 'true') {
      onBoarding();
      return;
    }
    callback();
  };

  const fetchCountsForChat = async (chatId) => {
    if (!chatId) return;
    try {
      postWindowMessage('CHAT_DATA_COUNTS_GET', { chatId });
    } catch (_) { }
  };

  useEffect(() => {
    const configStr = localStorage.getItem('CQ_SYSTEM_CONFIG');
    if (configStr) {
      try {
        const config = JSON.parse(configStr);
        setSystemConfig(config);
      } catch (error) {
        console.error('Error parsing system config:', error);
      }
    }
  }, []);

  const [isDashboardVisible, setIsDashboardVisible] = useState(false);

  useEffect(() => {
    const handleMessage = (event) => {
      if (event.source !== window) return;
      const { type, payload } = event.data;
      if (type === 'DASHBOARD_VISIBILITY_CHANGE') {
        setIsDashboardVisible(payload.isVisible);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  useEffect(() => {
    const resetCounts = () => {
      setNoteCount(0);
      setTodoCount(0);
      setReminderCount(0);
      setScheduledMessageCount(0);
    };

    const handleChatChange = (chat) => {
      const chatId = chat?.id?._serialized;
      setCurrentChatId(chatId);
      resetCounts();

      // Fetch counts for the new chat
      if (chatId) {
        fetchCountsForChat(chatId);
      }
      // If no chatId, counts remain at 0 (which is correct)
    };

    const handleMessage = (event) => {
      if (event.source !== window) return;

      const { type, payload } = event.data;
      if ((type == 'CHAT_ARTIFACTS_UPDATED' || type == 'CHAT_ARTIFACT_UPDATE')) {
        // After any artifact change, refresh counts from IndexedDB
        const updatedChatId = payload.chatId || currentChatId;
        if (updatedChatId) fetchCountsForChat(updatedChatId);
      }

      if (type === 'CHAT_DATA_COUNTS') {
        const counts = payload?.counts || {};
        setNoteCount(counts.notes || 0);
        setTodoCount(counts.toDo || 0);
        setReminderCount(counts.reminders || 0);
        setScheduledMessageCount(counts.scheduled_messages || 0);
      }
    };

    window.WPP.on('chat.active_chat', handleChatChange);
    window.addEventListener('message', handleMessage);

    getActiveChatId().then(chatId => {
      setCurrentChatId(chatId);
      // Fetch counts for the current chat
      if (chatId) {
        fetchCountsForChat(chatId);
      } else {
        // Ensure counts are reset when no chat is selected
        resetCounts();
      }
    });

    return () => {
      window.WPP.off('chat.active_chat', handleChatChange);
      window.removeEventListener('message', handleMessage);
    };
  }, []);


  useEffect(() => {
    const bodyElement = document.body;
    if (isOpen) {
      bodyElement.classList.add('cq-sidebar-open');
      bodyElement.classList.remove('cq-sidebar-closed');
    } else {
      bodyElement.classList.add('cq-sidebar-closed');
      bodyElement.classList.remove('cq-sidebar-open');
    }

    return () => {
      bodyElement.classList.remove('cq-sidebar-open', 'cq-sidebar-closed');
    };
  }, [isOpen]);

  return (
    <>

      {/* Toggle button when sidebar is closed */}
      <div
        className={`cq-sidebar-toggle ${isOpen ? 'hidden' : 'visible'}`}
      >
        <button
          onClick={() => {
            setIsOpen(true);
            postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.SIDEBAR_OPENED });
          }}
        >
          {icons.LEFT_ARROW}
        </button>
      </div>

      {/* Main sidebar - always rendered, controlled by CSS classes */}
      <div
        ref={sidebarRef}
        className={`cq-collapsible-sidebar ${isOpen ? 'open' : 'closed'}`}
      >
        <div>
          <div style={{ padding: '8px', display: 'flex', justifyContent: 'center' }}>
            <button
              onClick={() => {
                setIsOpen(false);
                closeSidePanel();
                postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.SIDEBAR_CLOSED });
              }}
              style={{
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                padding: '6px',
                backgroundColor: 'transparent',
              }}
              className="cq-sidebar-arrow-button"
            >
              {icons.RIGHT_ARROW}
            </button>
          </div>

          <Icon
            tooltip="About The Chat Quotient"
            icon={icons.THE_CQ_LOGO}
            label="The CQ"
            style={{
              fontWeight: 'bold',
            }}
            onClick={() => {
              postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.ABOUT_PANEL_OPENED });
              window.open('https://www.thechatquotient.com', '_blank');
            }}
          />

          <Icon
            tooltip="Settings"
            icon={icons.SETTINGS}
            label="Settings"
            onClick={() => {
              postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.PROFILE_PANEL_OPENED });
              const isUserOnboarded = localStorage.getItem('IS_USER_ONBOARDED');
              if (!isUserOnboarded || isUserOnboarded !== 'true') {
                onBoarding(null, false, true);
                return;
              } else {
                renderSidePanel(
                  SettingsPanel,
                  {},
                  {
                    title: 'Settings',
                    containerId: 'settings-panel'
                  }
                );
              }
            }}
          />

          {systemConfig?.config?.support?.is_enabled && systemConfig?.config?.support?.number && (
            <Icon
              tooltip="Chat With Us"
              icon={icons.SUPPORT}
              label="TheCQ Support"
              onClick={() => {
                postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.SUPPORT_PANEL_OPENED });
                setShowSupportModal(true);
              }}
            />
          )}

          <Icon
            tooltip="TheCQ Updates"
            icon={icons.ANNOUNCEMENT}
            label="TheCQ Updates"
            onClick={() => {
              postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.ANNOUNCEMENTS_CLICKED });
              const link = document.createElement("a");
              link.href = "https://whatsapp.com/channel/0029VbAxBX77dmegcdwpFw1G";
              link.rel = "noopener noreferrer";
              document.body.appendChild(link);
              link.click();
              link.remove();
            }}
          />
        </div>

        <div style={{ marginBottom: '16px' }}>
          <Icon
            tooltip="Open Dashboard"
            icon={icons.DASHBOARD}
            label="Dashboard"
            onClick={() => {
              // Close any open side panels
              closeSidePanel();

              // Dispatch escape key event to close open panels/chats
              const escEvent = new KeyboardEvent('keydown', {
                key: 'Escape',
                keyCode: 27,
                code: 'Escape',
                which: 27,
                bubbles: true,
                cancelable: true
              });
              document.dispatchEvent(escEvent);
            }}
          />



          <Icon
            tooltip="Leads"
            icon={icons.LEAD_SOURCE}
            onClick={() => checkOnboardingAndExecute(() => {
              // postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.LEADS_PANEL_OPENED }); // Ensure this event exists or add it
              renderSidePanel(
                LeadsPanel,
                { isOpen: true },
                {
                  title: 'Leads',
                  containerId: 'leads-panel',
                  monitorChat: true
                }
              );
            })}
            label={true ? "Lead" : "Create Lead"} // Dummy logic: hasLeads is false
          />
          <Icon
            tooltip="Quick Replies"
            icon={icons.QUICK_REPLY}
            onClick={() => checkOnboardingAndExecute(() => {
              postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.QUICK_REPLIES_PANEL_OPENED });
              renderSidePanel(
                QuickReplyManager,
                { isOpen: true, isSidebarMode: true },
                {
                  title: 'Quick Replies',
                  containerId: 'quick-reply-panel',
                  monitorChat: true
                }
              );
            })}
            label="Quick Replies"
          />
          <Icon
            tooltip="Chat Summary"
            icon={icons.SUMMARY}
            onClick={() => checkOnboardingAndExecute(() => {
              postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.CHAT_SUMMARY_PANEL_OPENED });
              renderSidePanel(
                ChatSummarizer,
                { shouldGenerateSummary: true },
                {
                  title: 'Chat Summary',
                  containerId: 'chat-summary-panel',
                  monitorChat: true
                }
              );
            })}
            label="Summarize This Chat"
          />
          <Icon
            tooltip="Schedule Messages"
            icon={icons.SCHEDULE_MESSAGE}
            onClick={() => checkOnboardingAndExecute(() => renderSidePanel(
              ScheduledMessages,
              { isOpen: true },
              {
                title: 'Scheduled Messages',
                containerId: 'scheduled-messages-panel',
                monitorChat: true
              }
            ))}
            badge={currentChatId ? scheduledMessageCount : 0}
            badgeType="info"
            label="Schedule Messages"
          />
          <TasksFolder
            noteCount={noteCount}
            todoCount={todoCount}
            reminderCount={reminderCount}
            currentChatId={currentChatId}
            checkOnboardingAndExecute={checkOnboardingAndExecute}
          />
        </div>
      </div>

      <ConfirmationModal
        isOpen={showSupportModal}
        onClose={() => setShowSupportModal(false)}
        onConfirm={() => {
          const message = systemConfig?.config?.support?.message || 'Hi';
          sendTextMessage(message, systemConfig.config.support.number);
        }}
        title="Need Support?"
        message="Your message will be sent on WhatsApp to the creator of The Chat Quotient. We're a small team, so while replies may not be immediate, you'll hear back during our working hours (IST). Thanks for your patience!"
        confirmText="Send Message"
        cancelText="Cancel"
      />
    </>
  );
};

export const mountSidebar = () => {
  const header = document.querySelector('#app header');
  if (!header) return;

  const target = header.parentElement;
  if (!target || target.querySelector('.cq-collapsible-sidebar')) return;

  const container = document.createElement('div');
  container.className = 'cq-collapsible-sidebar';
  container.style.position = 'relative';
  target.appendChild(container);

  const root = createRoot(container);
  root.render(<CollapsibleSidebar />);
};
