export function epochToDate(epochSec) {
  const sec = typeof epochSec === 'number' ? epochSec : Number(epochSec);
  if (isNaN(sec)) throw new Error('Invalid epoch value');
  return new Date(sec * 1000).toISOString();
}

export function epochToIST(epochSec) {
  const date = new Date(epochSec * 1000); // Epoch is in seconds
  // Convert to IST
  const istOffset = 5.5 * 60; // IST is UTC+5:30 in minutes
  const istDate = new Date(date.getTime() + istOffset * 60 * 1000);

  // Format manually to ISO string
  const year = istDate.getUTCFullYear();
  const month = String(istDate.getUTCMonth() + 1).padStart(2, '0');
  const day = String(istDate.getUTCDate()).padStart(2, '0');
  const hours = String(istDate.getUTCHours()).padStart(2, '0');
  const minutes = String(istDate.getUTCMinutes()).padStart(2, '0');
  const seconds = String(istDate.getUTCSeconds()).padStart(2, '0');

  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}+05:30`;
}

export function getNextOccurrence(currentDue, interval, now = new Date()) {
  const diff = now.getTime() - currentDue.getTime();
  if (diff >= 0) {
    const steps = Math.floor(diff / interval) + 1;
    return new Date(currentDue.getTime() + steps * interval);
  }
  return new Date(currentDue.getTime() + interval);
}
/**
 * Internal helper to format a Date object into MMM DD, YYYY hh:mm AM/PM
 * @param {Date} dateObj - The Date object to format
 * @returns {string} Formatted date time string
 */
function _formatDateObject(dateObj) {
  const options = {
    month: 'short',
    day: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true,
  };

  const formatted = dateObj.toLocaleString('en-US', options);

  return formatted.replace(', ', ' ');
}

/**
 * Format date and time as MMM DD, YYYY hh:mm AM/PM
 * @param {string} date - Date string in YYYY-MM-DD format
 * @param {string} time - Time string in HH:mm format
 * @returns {string} Formatted date time string or 'N/A' if invalid
 */
export function formatDateTime(date, time) {
  if (!date || !time) return 'N/A';

  const dateObj = new Date(`${date}T${time}`);

  if (isNaN(dateObj.getTime())) return 'N/A';

  return _formatDateObject(dateObj);
}

/**
 * Format ISO date string as dd/mm/yy hh:mm AM/PM
 * @param {string} isoString - ISO date string
 * @returns {string} Formatted date time string or 'N/A' if invalid
 */
export function formatISODateTime(isoString) {
  if (!isoString) return 'N/A';

  const dateObj = new Date(isoString);

  if (isNaN(dateObj.getTime())) return 'N/A';

  return _formatDateObject(dateObj);
}
