import { userRepository, contactRepository } from './database/index.js';


export const getMyProfileName = async () => {
    return await window.WPP?.profile?.getMyProfileName();
};

export const getUserTimezone = async () => {
    return Intl.DateTimeFormat().resolvedOptions().timeZone;
};

export const getActiveChatId = async () => {
    try {
        const activeChat = await window.WPP?.chat?.getActiveChat();

        if (!activeChat || !activeChat.id) {
            return false;
        }

        return activeChat.id._serialized;
    } catch (e) {
        console.warn('WPP getActiveChat failed:', e);
        return false;
    }
};

export const getMyUserId = async () => {
    try {
        const activeUser = await window.WPP?.conn?.getMyUserId();
        if (!activeUser || !activeUser.user) {
            throw new Error('No active user found.');
        }

        return activeUser.user;
    } catch (wppError) {
        console.warn('WPP failed, falling back to WAWC:', wppError?.message || wppError);

        try {
            return await userRepository.getUserId();
        } catch (dbError) {
            throw new Error(
                `Failed to retrieve user ID. WPP: ${wppError?.message || wppError}; WAWC: ${dbError?.message || dbError}`
            );
        }
    }
};

export const getContactName = async (contactId, required_for_customer_info = false) => {
    try {
        const contactUser = await window.WPP.contact.get(contactId);
        if (!contactUser) {
            throw new Error('No active user found.');
        }
        if (required_for_customer_info) {
            return contactUser.name || contactUser.pushname || '';
        }
        return contactUser.name || contactUser.pushname || contactId;
    } catch (wppError) {
        console.warn('WPP failed, falling back to Contact:', wppError?.message || wppError);
        try {
            return await contactRepository.getContactName(contactId);
        } catch (dbError) {
            throw new Error(
                `Failed to retrieve user ID. WPP: ${wppError?.message || wppError}; Contact: ${dbError?.message || dbError}`
            );
        }
    }
};

export const isAddressBookContact = async (contactId) => {
    try {
        const contactUser = await window.WPP.contact.get(contactId);
        if (!contactUser) {
            throw new Error('No active user found.');
        }
        return !!contactUser.isAddressBookContact;
    } catch (wppError) {
        console.warn('WPP failed, falling back to Contact:', wppError?.message || wppError);
        try {
            return await contactRepository.isAddressBookContact(contactId);
        } catch (dbError) {
            throw new Error(
                `Failed to retrieve user ID. WPP: ${wppError?.message || wppError}; Contact: ${dbError?.message || dbError}`
            );
        }
    }
}

export const getPhoneNumberFromChatId = async (chatId) => {
    if (chatId != "") {
        try {
            if (window.WPP.contact && typeof window.WPP.contact.getPnLidEntry === 'function') {
                const entry = await window.WPP.contact.getPnLidEntry(chatId);
                if (entry && entry.phoneNumber) {
                    return entry.phoneNumber.id;
                }
            }
        } catch (error) {
            console.warn('Could not resolve PN from LID:', error);
        }
    }
    return false;
};

export const getActiveChatNumber = async () => {
    const activeChat = await window.WPP?.chat?.getActiveChat();
    return await getPhoneNumberFromChatId(activeChat.id._serialized);
};

export const getActiveChatMessages = async (msgCount = 20) => {
    const activeChat = await window.WPP.chat.getActiveChat();

    if (!activeChat || !activeChat.id) {
        throw new Error('No active chat found.');
    }

    const chatMessages = await window.WPP.chat.getMessages(activeChat.id._serialized, { count: msgCount });
    const isGroup = activeChat.isGroup;

    const userName = 'you';

    const result = [];
    let customer_name = '';
    if (!isGroup) {
        customer_name = await getContactName(activeChat.id._serialized);
    }

    for (const msg of chatMessages) {
        if (msg.type !== 'chat') {
            continue;
        }

        const is_customer = !msg.id?.fromMe;
        const msg_body = msg.body;
        const msg_author = msg.author?._serialized;
        const msg_author_name = isGroup && is_customer ? await getContactName(msg_author) : is_customer ? customer_name : userName;
        const msg_timestamp = msg.t;


        result.push({
            message: msg_body,
            is_customer,
            name: msg_author_name,
            timestamp: msg_timestamp
        });
    }

    const chatInfo = {
        chat: result,
    };

    return chatInfo;
};

export const sendTextMessage = async (message, chatId = null, isGroup = false) => {
    if (!message || String(message).trim().length === 0) {
        throw new Error('Message is required.');
    }

    if (!chatId) {
        chatId = await getActiveChatId();
    }

    if (!chatId) {
        throw new Error('No phone number found for chat ID.');
    }

    await WPP.chat.openChatBottom(chatId);

    try {
        return await window.WPP.chat.sendTextMessage(chatId, message, { linkPreview: false });
    } catch (e) {
        console.warn('WPP sendTextMessage failed, falling back to DOM:', e);
    }

    // DOM fallback
    await setInputText(message);

    const btn = await findSendButtonWithRetry(2, 150);
    if (!btn) {
        throw new Error('Message not sent.');
    }

    btn.click();
    return true;
};

async function findSendButtonWithRetry(retries = 2, delayMs = 150) {
    for (let attempt = 1; attempt <= retries; attempt++) {
        const btn = document.querySelector('#main button[aria-label="Send"]');
        if (btn) return btn;
        if (attempt < retries) {
            await new Promise(r => setTimeout(r, delayMs));
        }
    }
    return null;
}

export const setInputText = async (message) => {
    return await window.WPP.chat.setInputText(message)
}

export const saveContactToPhone = async (chatId, firstName = '', lastName = '', syncToPhone = false) => {
    try {
        if (!chatId) {
            chatId = await getActiveChatId();
        }
        const givenName = firstName || '';
        const surname = lastName || '';
        await window.WPP.contact.save(chatId, givenName, {
            surname: surname,
            syncAddressBook: !!syncToPhone,
        });
    } catch (e) {
        console.warn('saveContactToPhone failed:', e);
    }
};

export const removeContactFromPhone = async (chatId = null) => {
    try {
        if (!chatId) {
            chatId = await getActiveChatId();
        }
        if (!chatId) return;
        await window.WPP?.contact?.remove?.(chatId);
    } catch (e) {
        console.warn('removeContactFromPhone failed:', e);
    }
};

export const openChat = async (chatId) => {
    if (!chatId) return false;
    try {
        if (window.WPP && window.WPP.chat && window.WPP.chat.openChatBottom) {
            await window.WPP.chat.openChatBottom(chatId);
            return true;
        }
    } catch (e) {
        console.error('Error opening chat:', e);
    }
    return false;
};

export const isAuthenticated = async () => {
    try {
        const result = await window.WPP?.conn?.isAuthenticated?.();
        return !!result;
    } catch (_) {
        return false;
    }
};

export const getChatType = async (chatId = null) => {
    try {
        let chat = null;
        if (chatId) {
            chat = await window.WPP.chat.get(chatId);
        } else {
            chat = await window.WPP.chat.getActiveChat();
        }

        if (!chat || !chat.id) return 'unknown';

        const id = chat.id;

        // 1. Check for Group first
        if (id.server === 'g.us' || id._serialized.endsWith('@g.us')) {
            return 'group';
        }
        // 2. Check for Individual
        else if (id.server === 'c.us' || id.server === 'lid' || id.isUser) {
            return 'individual';
        }
        // 3. Check for Channels (Newsletters)
        else if (id.server === 'newsletter') {
            return 'channel';
        }

        return 'unknown';
    } catch (e) {
        console.error('Error getting chat type:', e);
        return 'unknown';
    }
};


export const isGroupChat = async (chatId = null) => {
    const type = await getChatType(chatId);
    return type === 'group';
};

export const isIndividualChat = async (chatId = null) => {
    const type = await getChatType(chatId);
    return type === 'individual';
};

export const isChannel = async (chatId = null) => {
    const type = await getChatType(chatId);
    return type === 'channel';
};

export const searchWPPContacts = async (query) => {
    if (!query) return [];

    try {
        if (!window.WPP || !window.WPP.contact || !window.WPP.chat) {
            return [];
        }

        const lowerQuery = query.toLowerCase();

        const getMatchScore = (text) => {
            if (!text) return 0;
            const t = text.toLowerCase();
            if (t === lowerQuery) return 100;
            if (t.startsWith(lowerQuery)) return 80;
            if (t.includes(lowerQuery)) return 50;
            return 0;
        };

        const [allChats, allContacts] = await Promise.all([
            window.WPP.chat.list(),
            window.WPP.contact.list({ onlyMyContacts: true })
        ]);

        const groupCandidates = allChats
            .filter(chat => chat.isGroup)
            .map(c => {
                const name = c.name || c.formattedTitle || c.pushname || '';
                return {
                    original: c,
                    type: 'group',
                    name: name,
                    score: getMatchScore(name),
                    id: c.id._serialized
                };
            });

        const contactCandidates = allContacts
            .filter(c => c.type === 'in')
            .map(c => {
                const name = c.name || c.pushname || c.formattedName || c.id?.user || '';
                const score = getMatchScore(name);

                return {
                    original: c,
                    type: 'individual',
                    name: name,
                    score: score,
                    id: c.id._serialized
                };
            });

        const sortedCandidates = [...groupCandidates, ...contactCandidates]
            .filter(item => item.score > 0)
            .sort((a, b) => b.score - a.score)
            .slice(0, 20);

        const finalResults = [];
        const seenNumbers = new Set();

        for (const candidate of sortedCandidates) {
            if (finalResults.length >= 10) break;

            let resolvedNumber = candidate.original.id.user;
            let resolvedLid = null;
            let finalChatId = candidate.id;

            if (candidate.type === 'individual') {
                try {
                    const entry = await window.WPP.contact.getPnLidEntry(candidate.id);
                    if (entry) {
                        if (entry.phoneNumber) resolvedNumber = entry.phoneNumber.id;
                        if (entry.lid) resolvedLid = entry.lid._serialized || entry.lid;
                    }

                    // Use queryExists to fetch chat ID as requested
                    const result = await window.WPP.contact.queryExists(resolvedNumber);
                    if (result && result.wid) {
                        finalChatId = result.wid._serialized || result.wid;
                    }
                } catch (err) {
                    // Ignore resolution errors
                }
            }

            if (seenNumbers.has(resolvedNumber)) {
                continue;
            }

            seenNumbers.add(resolvedNumber);

            finalResults.push({
                id: finalChatId,
                name: candidate.name,
                number: '+' + resolvedNumber,
                lid: resolvedLid,
                isGroup: candidate.type === 'group',
                isIndividual: candidate.type === 'individual',
                type: candidate.original.type,
                matchScore: candidate.score
            });
        }

        return finalResults;

    } catch (e) {
        console.error("WPP Search Error:", e);
        return [];
    }
};
