import React, { useState, useEffect, useRef } from 'react';
import InputBox from '../UIComponents/InputBox';
import ArtifactIconCard from '../UIComponents/ArtifactIconCard';
import CompanyField from '../CustomerInfo/CompanyField';
import { icons } from '../../Constants/svg';
import { isDarkMode } from '../../utils/utils';
import { postWindowMessage } from '../../utils/messageSender';

const ContactCard = ({
    contact,
    chatId,
    customerId,
    onContactUpdate,
    forceExpanded,
    isLoadingContact
}) => {
    const isDark = isDarkMode();
    const [isEditMode, setIsEditMode] = useState(false);
    const [saveLoading, setSaveLoading] = useState(false);

    // Internal form state initialized from props
    const [form, setForm] = useState({
        firstName: '',
        lastName: '',
        phone: '',
        email: '',
        company: null,
        designation: '',
        address: '',
        city: '',
        state: '',
        zip: '',
        country: ''
    });

    const formRef = useRef(form);

    useEffect(() => {
        formRef.current = form;
    }, [form]);

    // Force expanded state if requested (e.g. new contact), but obey if it gets disabled
    useEffect(() => {
        if (forceExpanded) {
            setIsEditMode(true);
        } else if (!forceExpanded && !isLoadingContact) {
            // If parent says "don't force expand" and "done loading", we can collapse
            // This happens when checkingContact becomes false and customerId EXISTS
            setIsEditMode(false);
        }
    }, [forceExpanded, isLoadingContact]);

    // Update form when parent contact data changes
    useEffect(() => {
        if (contact) {
            setForm(prev => ({
                ...prev,
                firstName: contact.firstName || '',
                lastName: contact.lastName || '',
                phone: contact.phone || '',
                email: contact.email || '',
                company: contact.company || null,
                designation: contact.designation || '',
                address: contact.address || '',
                city: contact.city || '',
                state: contact.state || '',
                zip: contact.zip || '',
                country: contact.country || ''
            }));
        }
    }, [contact]);

    // Cleanup listener on unmount
    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'CUSTOMER_UPDATE') {
                const { actionType, data } = payload || {};

                if ((actionType === 'CUSTOMER_CREATED' || actionType === 'CUSTOMER_UPDATED') && data) {
                    setSaveLoading(false);
                    if (!forceExpanded) {
                        setIsEditMode(false);
                    }
                    // Push local state to parent to keep it in sync
                    if (onContactUpdate) {
                        onContactUpdate(formRef.current);
                    }
                }
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [onContactUpdate, forceExpanded]);

    const handleChange = (key) => (e) => {
        setForm(prev => ({ ...prev, [key]: e.target.value }));
    };

    const handleCompanyChange = (company) => {
        setForm(prev => ({ ...prev, company }));
    };

    const toggleEdit = () => {
        if (forceExpanded) return; // Cannot collapse if forced expanded

        // Reset form to current props when canceling
        if (isEditMode && contact) {
            setForm(prev => ({
                ...prev,
                firstName: contact.firstName || '',
                lastName: contact.lastName || '',
                phone: contact.phone || '',
                email: contact.email || '',
                company: contact.company || null,
                designation: contact.designation || '',
                address: contact.address || '',
                city: contact.city || '',
                state: contact.state || '',
                zip: contact.zip || '',
                country: contact.country || ''
            }));
        }
        setIsEditMode(!isEditMode);
    };

    const handleSave = async () => {
        if (!chatId) return;

        // Validation - Check firstName instead of leadName
        if (!form.firstName || !form.firstName.trim()) {
            console.error("First name is required");
            return;
        }

        setSaveLoading(true);

        const companyId = form.company?.id;
        const designation = form.designation || '';

        // Helper to ensure leading +
        const withPlus = (val) => {
            if (!val) return val;
            return String(val).startsWith('+') ? String(val) : `+${val}`;
        };

        const payload = {
            chat_id: chatId,
            first_name: form.firstName,
            last_name: form.lastName,
            email: form.email,
            phone: withPlus(form.phone),
            source: contact?.source || '', // Preserve source if not editable
            address: form.address,
            city: form.city,
            state: form.state,
            zip_code: form.zip,
            country: form.country,
            ...(companyId ? { company_id: companyId, relationship_type: designation } : {})
        };

        if (customerId) {
            postWindowMessage('CUSTOMER_UPDATE', {
                customer_id: customerId,
                ...payload
            });
        } else {
            postWindowMessage('CUSTOMER_CREATE', payload);
        }
    };

    const companyName = form.company ? form.company.name : '';
    const description = [form.designation?.trim(), companyName?.trim()]
        .filter(Boolean)
        .join(' at ');

    const fullName = [form.firstName, form.lastName].filter(Boolean).join(' ');

    const footerItems = [];
    if (form.phone) {
        footerItems.push({ icon: icons.PHONE, text: form.phone });
    }
    if (form.email) {
        footerItems.push({ icon: icons.EMAIL, text: form.email });
    }

    if (isLoadingContact) {
        return (
            <div style={{ marginBottom: '8px', padding: '12px', textAlign: 'center' }} className="cq-contact-card">
                <span style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>Checking contact details...</span>
            </div>
        );
    }

    return (
        <div style={{ marginBottom: '8px' }}>
            <div className={`cq-contact-card-header ${isEditMode ? 'editing' : ''}`}>
                <span className="cq-card-title">Contact Details</span>
                {isEditMode && !forceExpanded && (
                    <button type="button" className="cq-btn-icon" onClick={toggleEdit}>
                        {icons.MINUS_IN_SQUARE}
                    </button>
                )}
            </div>

            {isEditMode ? (
                <div className="cq-contact-edit-form cq-contact-card">
                    <div className="cq-lead-row">
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">First Name</span>
                            <InputBox
                                value={form.firstName}
                                onChange={handleChange('firstName')}
                                placeholder="First Name"
                            />
                        </label>
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Last Name</span>
                            <InputBox
                                value={form.lastName}
                                onChange={handleChange('lastName')}
                                placeholder="Last Name"
                            />
                        </label>
                    </div>

                    <div className="cq-lead-row">
                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Phone</span>
                            <InputBox
                                value={form.phone}
                                onChange={handleChange('phone')}
                                placeholder="+1234567890"
                                disabled={true}
                                style={{ opacity: 0.7, cursor: 'not-allowed' }}
                            />
                        </label>

                        <label className="cq-lead-field">
                            <span className="cq-lead-label">Email</span>
                            <InputBox
                                value={form.email}
                                onChange={handleChange('email')}
                                placeholder="email@example.com"
                            />
                        </label>
                    </div>

                    <label className="cq-lead-field">
                        <span className="cq-lead-label">Company</span>
                        <CompanyField
                            value={form.company}
                            onChange={handleCompanyChange}
                        />
                    </label>

                    <label className="cq-lead-field">
                        <span className="cq-lead-label">Designation</span>
                        <InputBox
                            value={form.designation}
                            onChange={handleChange('designation')}
                            placeholder="Job title"
                        />
                    </label>

                    <div className="cq-lead-actions" style={{ marginTop: '16px', display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
                        {!forceExpanded && (
                            <button
                                type="button"
                                className="cq-btn-secondary"
                                onClick={toggleEdit}
                                disabled={saveLoading}
                                style={{ padding: '6px 12px', fontSize: '13px' }}
                            >
                                Cancel
                            </button>
                        )}
                        {!forceExpanded && (
                            <button
                                type="button"
                                className="cq-btn-primary"
                                onClick={handleSave}
                                disabled={saveLoading}
                                style={{ padding: '6px 12px', fontSize: '13px' }}
                            >
                                {saveLoading ? 'Saving...' : 'Save Details'}
                            </button>
                        )}
                    </div>
                </div>
            ) : (
                <ArtifactIconCard
                    isDark={isDark}
                    title={fullName || 'No Name'}
                    description={description || null}
                    footerItems={footerItems}
                    actions={[
                        {
                            icon: icons.EDIT,
                            tooltip: "Edit Contact",
                            label: "Edit",
                            onClick: toggleEdit
                        }
                    ]}
                />
            )}
        </div>
    );
};

export default ContactCard;
