import React, { useState, useEffect } from 'react';
import { icons } from '../../Constants/svg';
import OnBoardingForm from '../OnBoardingForm/OnBoardingForm';
import PipelineManager from '../PipelineManager/PipelineManager';
import ErrorBoundary from '../ErrorBoundary/ErrorBoundary';
import { postWindowMessage } from '../../utils/messageSender';
import './SettingsPanel.css';

const SettingsPanel = () => {
    const [openSection, setOpenSection] = useState(null); // 'profile' or 'pipeline'
    const [onboardingData, setOnboardingData] = useState(null);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data || {};

            if (type === 'USER_CONFIG') {
                // Directly update state so OnBoardingForm shows it immediately
                setOnboardingData(payload || null);
            }

            if (type === 'USER_CONFIG_UPDATE') {
                // Refresh config after update (so UI reflects saved state)
                postWindowMessage('GET_USER_CONFIG', {});
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, []);

    const toggleSection = (section) => {
        const newSection = openSection === section ? null : section;
        setOpenSection(newSection);

        // Fetch latest config whenever profile opens
        if (newSection === 'profile') {
            postWindowMessage('GET_USER_CONFIG', {});
        }
    };

    return (
        <div className="cq-settings-panel">
            {/* Profile Section */}
            <div className="cq-accordion-item">
                <button
                    className="cq-accordion-trigger"
                    aria-expanded={openSection === 'profile'}
                    onClick={() => toggleSection('profile')}
                >
                    <span>Profile Details</span>
                    <span className="cq-accordion-chevron">{icons.DROPDOWN_CHEVRON}</span>
                </button>

                <div className={`cq-accordion-content ${openSection === 'profile' ? 'open' : ''}`}>
                    {openSection === 'profile' && (
                        <OnBoardingForm
                            isUpdate={true}
                            OnboardingData={onboardingData}
                            onCancel={() => toggleSection('profile')}
                        />
                    )}
                </div>
            </div>

            {/* Pipeline Section */}
            <div className="cq-accordion-item">
                <button
                    className="cq-accordion-trigger"
                    aria-expanded={openSection === 'pipeline'}
                    onClick={() => toggleSection('pipeline')}
                >
                    <span>Pipeline Settings</span>
                    <span className="cq-accordion-chevron">{icons.DROPDOWN_CHEVRON}</span>
                </button>

                <div className={`cq-accordion-content ${openSection === 'pipeline' ? 'open' : ''}`}>
                    {openSection === 'pipeline' && (
                        <ErrorBoundary>
                            <PipelineManager />
                        </ErrorBoundary>
                    )}
                </div>
            </div>
        </div>
    );
};

export default SettingsPanel;
