import React, { useState, useEffect, useRef } from 'react';
import { icons } from '../../Constants/svg';
import { PIPELINE_STAGE_TYPES } from '../../Constants/constant';
import './PipelineManager.css';

const STAGE_COLOR_MAP = {
    'Green': '#22C55E',
    'Blue': '#3B82F6',
    'Red': '#EF4444',
    'Cyan': '#06B6D4',
    'Orange': '#F97316',
    'Gray': '#94a3b8',
    'Yellow': '#EAB308',
    'Purple': '#A855F7',
    'Pink': '#EC4899',
};

const getValidHex = (color) => {
    if (!color) return '#000000';
    if (color.startsWith('#')) return color;
    return STAGE_COLOR_MAP[color] || '#000000';
};

const StageStatusCell = ({ stage, onChange }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [isFocused, setIsFocused] = useState(false);
    const wrapperRef = useRef(null);

    const options = [
        { label: 'Won (100%)', value: 100, type: PIPELINE_STAGE_TYPES.WON },
        ...Array.from({ length: 9 }, (_, i) => ({ label: `${(9 - i) * 10}%`, value: (9 - i) * 10, type: PIPELINE_STAGE_TYPES.OPEN })),
        { label: 'Lost (0%)', value: 0, type: PIPELINE_STAGE_TYPES.LOST }
    ]

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
                if (isOpen || isFocused) {
                    setIsOpen(false);
                    setIsFocused(false);
                    onChange(stage.id, {}, true);
                }
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, isFocused, stage.id, onChange]);

    const getDisplayValue = () => {
        if (isFocused) return stage.probability;
        if (stage.probability === 100) return 'Won (100)';
        if (stage.probability === 0) return 'Lost (0)';
        return stage.probability;
    };

    const handleSelect = (option) => {
        onChange(stage.id, { probability: option.value, type: option.type }, true);
        setIsOpen(false);
        setIsFocused(false);
    };

    const handleInputChange = (e) => {
        const strVal = e.target.value;
        if (strVal === '') {
            onChange(stage.id, { probability: 0, type: PIPELINE_STAGE_TYPES.LOST }, false);
            return;
        }

        let val = parseInt(strVal);
        if (isNaN(val)) return;
        val = Math.min(100, Math.max(0, val));

        let newType = PIPELINE_STAGE_TYPES.OPEN;
        if (val === 100) newType = PIPELINE_STAGE_TYPES.WON;
        if (val === 0) newType = PIPELINE_STAGE_TYPES.LOST;

        onChange(stage.id, { probability: val, type: newType }, false);
    };

    const handleFocus = () => {
        setIsFocused(true);
        setIsOpen(true);
    };

    const handleBlur = () => {
        setIsFocused(false);
        setTimeout(() => setIsOpen(false), 200);
        onChange(stage.id, {}, true);
    };

    return (
        <div className="cq-stage-status-cell" ref={wrapperRef}>
            <div className="cq-status-input-wrapper">
                <input
                    className="cq-status-input"
                    type="text"
                    value={getDisplayValue()}
                    onChange={handleInputChange}
                    onFocus={handleFocus}
                    onBlur={handleBlur}
                />
                <div className="cq-status-toggle" onClick={() => setIsOpen(!isOpen)}>
                    {icons?.DROPDOWN_CHEVRON || '▼'}
                </div>
            </div>
            {isOpen && (
                <div className="cq-status-dropdown">
                    {options.map(opt => (
                        <div
                            key={opt.label}
                            className={`cq-status-option ${stage.probability === opt.value ? 'selected' : ''}`}
                            onClick={() => handleSelect(opt)}
                        >
                            {opt.label}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

const StageEditor = ({ pipeline, onUpdate, onAddStage, onDeleteStage, onAutoSave }) => {
    const [stages, setStages] = useState(pipeline.stages || []);
    const [errors, setErrors] = useState([]);

    useEffect(() => {
        setStages(pipeline.stages || []);
        validateStages(pipeline.stages || []);
    }, [pipeline]);

    const validateStages = (currentStages) => {
        if (!Array.isArray(currentStages)) return false;
        const errs = [];
        const hasOpen = currentStages.some(s => s.type === PIPELINE_STAGE_TYPES.OPEN);
        const hasWon = currentStages.some(s => s.type === PIPELINE_STAGE_TYPES.WON);
        const hasLost = currentStages.some(s => s.type === PIPELINE_STAGE_TYPES.LOST);

        // Safe access to name
        const uniqueNames = new Set(currentStages.map(s => (s.name || '').trim().toLowerCase())).size === currentStages.length;

        if (!hasOpen) errs.push('At least one Open stage is required.');
        if (!hasWon) errs.push('At least one Won stage is required.');
        if (!hasLost) errs.push('At least one Lost stage is required.');
        if (!uniqueNames) errs.push('Stage names must be unique.');

        setErrors(errs);
        return errs.length === 0;
    };

    const triggerAutoSave = (stagesToSave) => {
        if (onAutoSave) {
            onAutoSave(stagesToSave);
        }
    };

    const handleUpdateStages = (newStages) => {
        setStages(newStages);
        const isValid = validateStages(newStages);
        onUpdate({ ...pipeline, stages: newStages }, isValid);
    };

    const handleStageChange = (id, fieldOrUpdates, value, shouldAutoSave = false) => {
        const newStages = stages.map(s => {
            if (s.id === id) {
                let updated = { ...s };
                if (typeof fieldOrUpdates === 'object') {
                    // Batch update: fieldOrUpdates is the updates object, value is shouldAutoSave
                    updated = { ...updated, ...fieldOrUpdates };
                    shouldAutoSave = value;
                } else {
                    // Single field update
                    updated = { ...updated, [fieldOrUpdates]: value };
                    if (fieldOrUpdates === 'type') {
                        if (value === PIPELINE_STAGE_TYPES.WON) updated.probability = 100;
                        if (value === PIPELINE_STAGE_TYPES.LOST) updated.probability = 0;
                    }
                }
                return updated;
            }
            return s;
        });

        handleUpdateStages(newStages);

        if (shouldAutoSave) {
            triggerAutoSave(newStages);
        }
    };

    const handleAddStage = () => {
        if (onAddStage) {
            onAddStage();
        }
    };

    const handleDeleteStage = (id) => {
        const stageToDelete = stages.find(s => s.id === id);
        if (!stageToDelete) return;

        // Validation: At least one of each type
        const sameTypeCount = stages.filter(s => s.type === stageToDelete.type).length;
        if (sameTypeCount <= 1) {
            setErrors([`Cannot delete: You must have at least one ${stageToDelete.type} stage.`]);
            setTimeout(() => setErrors([]), 3000);
            return;
        }

        if (onDeleteStage) {
            onDeleteStage(id);
        } else {
            // Fallback if not provided (old behavior)
            handleUpdateStages(stages.filter(s => s.id !== id));
        }
    };

    const moveStage = (index, direction) => {
        if (direction === 'up' && index === 0) return;
        if (direction === 'down' && index === stages.length - 1) return;

        const newStages = [...stages];
        const targetIndex = direction === 'up' ? index - 1 : index + 1;

        // Swap
        [newStages[index], newStages[targetIndex]] = [newStages[targetIndex], newStages[index]];

        // Reassign order 0-based
        newStages.forEach((s, i) => s.order = i);
        handleUpdateStages(newStages);
        if (onAutoSave) {
            onAutoSave(newStages);
        }
    };

    return (
        <div className="cq-stage-editor">
            <div className="cq-stage-editor-header">
                <h4>Stages ({stages.length})</h4>
                {errors.length > 0 && (
                    <div className="cq-error-banner" title={errors.join('\n')}>
                        {icons?.WARNING || '!'} Invalid Configuration
                    </div>
                )}
            </div>

            <div className="cq-stage-list-header-row">
                <div className="cq-header-handle-spacer"></div>
                <div className="cq-stage-header-content">
                    <span className="cq-col-header">Name</span>
                    <span className="cq-col-header center-text">Color</span>
                    <span className="cq-col-header">Status</span>
                    <span className="cq-col-header"></span> {/* Action column */}
                </div>
            </div>
            <div className="cq-stage-list">
                {stages.map((stage, index) => (
                    <div key={stage.id} className="cq-stage-item">
                        <div className="cq-stage-handle">
                            <button
                                className="cq-pipeline-action-btn"
                                onClick={() => moveStage(index, 'up')}
                                disabled={index === 0}
                                style={{ padding: 0, height: 12 }}
                            >
                                ▲
                            </button>
                            <button
                                className="cq-pipeline-action-btn"
                                onClick={() => moveStage(index, 'down')}
                                disabled={index === stages.length - 1}
                                style={{ padding: 0, height: 12 }}
                            >
                                ▼
                            </button>
                        </div>

                        <div className="cq-stage-content">
                            <input
                                className="cq-stage-input"
                                value={stage.name}
                                onChange={(e) => handleStageChange(stage.id, 'name', e.target.value)}
                                onBlur={() => {
                                    console.log('Name Input Blur');
                                    triggerAutoSave(stages);
                                }}
                                placeholder="Stage Name"
                            />

                            <div className="cq-stage-field-group center-content">
                                <div className="cq-color-picker-wrapper">
                                    <input
                                        type="color"
                                        className="cq-stage-color-input"
                                        value={getValidHex(stage.color)}
                                        onChange={(e) => handleStageChange(stage.id, 'color', e.target.value, true)} // Auto-save
                                        title={stage.color || "Pick a color"}
                                    />
                                </div>
                            </div>

                            <StageStatusCell
                                stage={stage}
                                onChange={handleStageChange}
                            />

                            <button
                                className="cq-stage-delete-btn"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDeleteStage(stage.id);
                                }}
                                title="Delete Stage"
                            >
                                {icons?.DELETE || 'x'}
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <button className="cq-add-stage-btn" onClick={handleAddStage}>
                + Add Stage
            </button>

            {errors.length > 0 && (
                <div style={{ color: '#ef4444', fontSize: '0.8rem', padding: '0 4px' }}>
                    {errors.map(e => <div key={e}>• {e}</div>)}
                </div>
            )}
        </div>
    );
};

export default StageEditor;
