import React, { useState, useEffect, useRef } from 'react';
import { icons } from '../../Constants/svg';
import Icon from '../UIComponents/Icon';
import TextAreaBox from '../UIComponents/TextAreaBox';
import RelativeTime from '../UIComponents/RelativeTime';
import { getActiveChatId } from '../../utils/WppFunctions';
import { postWindowMessage } from '../../utils/messageSender';
import { TRACK_EVENTS } from '../../Constants/constant';
import { isDarkMode } from '../../utils/utils';
import ArtifactIconCard from '../UIComponents/ArtifactIconCard';
import ErrorBoundary from '../UIComponents/ErrorBoundary';
import './ChatTodo.css';

const ChatTodo = ({ isOpen, chatId: initialChatId }) => {
  const isDark = isDarkMode();
  const [pendingTodos, setPendingTodos] = useState([]);
  const [doneTodos, setDoneTodos] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [editingIndex, setEditingIndex] = useState(null);
  const [editingSection, setEditingSection] = useState(null);
  const [currentChatId, setCurrentChatId] = useState(initialChatId);
  const [isLoading, setIsLoading] = useState(false);

  // Pending section state
  const [pendingCurrentPage, setPendingCurrentPage] = useState(1);
  const [pendingHasNextPage, setPendingHasNextPage] = useState(false);
  const [pendingTotalCount, setPendingTotalCount] = useState(0);
  const [pendingNextPageNumber, setPendingNextPageNumber] = useState(null);
  const [pendingPreviousPageNumber, setPendingPreviousPageNumber] = useState(null);
  const [isPendingLoadingMore, setIsPendingLoadingMore] = useState(false);

  // Done section state
  const [doneCurrentPage, setDoneCurrentPage] = useState(1);
  const [doneHasNextPage, setDoneHasNextPage] = useState(false);
  const [doneTotalCount, setDoneTotalCount] = useState(0);
  const [doneNextPageNumber, setDoneNextPageNumber] = useState(null);
  const [donePreviousPageNumber, setDonePreviousPageNumber] = useState(null);
  const [isDoneLoadingMore, setIsDoneLoadingMore] = useState(false);

  // Collapsible sections state
  const [isPendingOpen, setIsPendingOpen] = useState(true);
  const [isDoneOpen, setIsDoneOpen] = useState(false);
  const [doneDataFetched, setDoneDataFetched] = useState(false);

  const popupRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const handleMessage = (event) => {
      if (event.source !== window) return;

      const { type, payload } = event.data;
      if ((type == 'CHAT_ARTIFACTS_UPDATED' || type == 'CHAT_ARTIFACT_UPDATE') && payload.chatId === currentChatId && payload.dataType === 'to_do') {
        handleTodosUpdate(payload);
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [currentChatId, isPendingLoadingMore, isDoneLoadingMore, pendingCurrentPage, doneCurrentPage]);

  const handleTodosUpdate = (response) => {
    const todosData = response.data;
    const nextUrl = response.paginationMeta.next;
    const requestStatus = response.paginationMeta?.status;

    // Only update UI state if the panel is open
    if (isOpen && Array.isArray(todosData)) {
      const transformedTodos = todosData.map(todo => ({
        id: todo.id,
        text: todo.main_content,
        timestamp: todo.created_at,
        status: todo.status || 'pending'
      }));

      // Determine status from pagination metadata first, then from data
      const dataStatus = transformedTodos.length > 0 ? transformedTodos[0].status : null;
      const effectiveStatus = requestStatus || dataStatus;

      if (effectiveStatus === 'pending' || (!effectiveStatus && (transformedTodos.length === 0 || transformedTodos.every(todo => todo.status === 'pending')))) {
        // Handle pending todos
        if (response.paginationMeta && response.paginationMeta.count !== undefined) {
          setPendingTotalCount(response.paginationMeta.count);
        }

        if (isPendingLoadingMore && pendingCurrentPage > 1) {
          setPendingTodos(prev => {
            const allTodos = [...prev, ...transformedTodos];
            const deduplicated = Array.from(new Map(allTodos.map(todo => [todo.id, todo])).values());
            return deduplicated;
          });
        } else {
          setPendingTodos(transformedTodos);
          setPendingCurrentPage(1);
        }

        if (nextUrl) {
          const url = new URL(nextUrl);
          const pageFromUrl = parseInt(url.searchParams.get('page'), 10);
          setPendingHasNextPage(true);
          setPendingNextPageNumber(pageFromUrl);
          setPendingPreviousPageNumber(pageFromUrl > 1 ? pageFromUrl - 1 : null);
        } else {
          setPendingHasNextPage(false);
          setPendingNextPageNumber(null);
        }
        setIsPendingLoadingMore(false);
      } else if (effectiveStatus === 'done' || (transformedTodos.length > 0 && transformedTodos.every(todo => todo.status === 'done'))) {
        // Handle done todos
        if (response.paginationMeta && response.paginationMeta.count !== undefined) {
          setDoneTotalCount(response.paginationMeta.count);
        }

        if (isDoneLoadingMore && doneCurrentPage > 1) {
          setDoneTodos(prev => {
            const allTodos = [...prev, ...transformedTodos];
            const deduplicated = Array.from(new Map(allTodos.map(todo => [todo.id, todo])).values());
            return deduplicated;
          });
        } else {
          setDoneTodos(transformedTodos);
          setDoneCurrentPage(1);
        }

        if (nextUrl) {
          const url = new URL(nextUrl);
          const pageFromUrl = parseInt(url.searchParams.get('page'), 10);
          setDoneHasNextPage(true);
          setDoneNextPageNumber(pageFromUrl);
          setDonePreviousPageNumber(pageFromUrl > 1 ? pageFromUrl - 1 : null);
        } else {
          setDoneHasNextPage(false);
          setDoneNextPageNumber(null);
        }
        setIsDoneLoadingMore(false);
        setDoneDataFetched(true);
      } else {
        // Handle mixed data or backwards compatibility
        const pending = transformedTodos.filter(todo => todo.status === 'pending');
        const done = transformedTodos.filter(todo => todo.status === 'done');
        setPendingTodos(pending);
        setDoneTodos(done);
        setPendingTotalCount(pending.length);
        setDoneTotalCount(done.length);
      }
    }
    setIsLoading(false);
  };

  const loadMorePendingTodos = () => {
    if (!pendingHasNextPage || isPendingLoadingMore || !pendingNextPageNumber) return;

    setIsPendingLoadingMore(true);
    setPendingCurrentPage(pendingNextPageNumber);

    postWindowMessage('CHAT_ARTIFACTS_FETCH', {
      chatId: currentChatId,
      data_type: "to_do",
      status: "pending",
      page: pendingNextPageNumber,
      page_size: 10
    });
  };

  const loadMoreDoneTodos = () => {
    if (!doneHasNextPage || isDoneLoadingMore || !doneNextPageNumber) return;

    setIsDoneLoadingMore(true);
    setDoneCurrentPage(doneNextPageNumber);

    postWindowMessage('CHAT_ARTIFACTS_FETCH', {
      chatId: currentChatId,
      data_type: "to_do",
      status: "done",
      page: doneNextPageNumber,
      page_size: 10
    });
  };

  const resetPagination = () => {
    // Reset pending pagination
    setPendingCurrentPage(1);
    setPendingHasNextPage(false);
    setPendingNextPageNumber(null);
    setPendingTotalCount(0);
    setPendingTodos([]);
    setIsPendingLoadingMore(false);

    // Reset done pagination
    setDoneCurrentPage(1);
    setDoneHasNextPage(false);
    setDoneNextPageNumber(null);
    setDoneTotalCount(0);
    setDoneTodos([]);
    setIsDoneLoadingMore(false);
    setDoneDataFetched(false);
  };

  useEffect(() => {
    getActiveChatId().then(id => {
      if (id) {
        setCurrentChatId(id);
        // API will be called by the second useEffect when currentChatId changes
      }
    });

    const handleChatChange = (chat) => {
      const chatId = chat?.id?._serialized;
      setCurrentChatId(chatId);
      setEditingIndex(null);
      resetPagination();
    };

    window.WPP.on('chat.active_chat', handleChatChange);

    return () => {
      window.WPP.off('chat.active_chat', handleChatChange);
    };
  }, []);

  useEffect(() => {
    if (currentChatId) {
      setIsLoading(true);
      resetPagination();
      // Fetch pending todos by default
      postWindowMessage('CHAT_ARTIFACTS_FETCH', {
        chatId: currentChatId,
        data_type: "to_do",
        status: "pending",
        page: 1,
        page_size: 10
      });
    } else {
      resetPagination();
    }
  }, [currentChatId]);

  // Fetch done todos when done section is expanded
  useEffect(() => {
    if (currentChatId && isDoneOpen && !doneDataFetched) {
      postWindowMessage('CHAT_ARTIFACTS_FETCH', {
        chatId: currentChatId,
        data_type: "to_do",
        status: "done",
        page: 1,
        page_size: 10
      });
    }
  }, [currentChatId, isDoneOpen, doneDataFetched]);

  const handleAddTodo = async () => {
    if (inputValue.trim() === '' || !currentChatId) return;

    setIsLoading(true);

    if (editingIndex !== null) {
      await handleUpdateTodo();
    } else {
      await handleCreateTodo();
    }
  };

  const handleCreateTodo = async () => {
    const todoText = inputValue.trim();

    try {
      postWindowMessage('CHAT_ARTIFACTS_CREATE', {
        chatId: currentChatId,
        main_content: todoText,
        data_type: 'to_do',
        status: 'pending'
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.TODO_CREATED,
        properties: { chatId: currentChatId, status: 'pending' }
      });
      setInputValue('');
    } catch (error) {
      console.error('Failed to create todo:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateTodo = async () => {
    const todoText = inputValue.trim();
    const todoToUpdate = editingSection === 'pending'
      ? pendingTodos.find(t => t.id === editingIndex)
      : doneTodos.find(t => t.id === editingIndex);

    if (!todoToUpdate) return;

    try {
      postWindowMessage('CHAT_ARTIFACTS_UPDATE', {
        chatId: currentChatId,
        artifact_id: todoToUpdate.id,
        main_content: todoText,
        data_type: 'to_do',
        status: todoToUpdate.status
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.TODO_UPDATED,
        properties: { chatId: currentChatId, todoId: todoToUpdate.id, status: todoToUpdate.status }
      });
      setEditingIndex(null);
      setEditingSection(null);
      setInputValue('');
    } catch (error) {
      console.error('Failed to update todo:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleToggleStatus = async (todo) => {
    if (!currentChatId) return;

    const newStatus = todo.status === 'pending' ? 'done' : 'pending';
    setIsLoading(true);

    try {
      postWindowMessage('CHAT_ARTIFACTS_UPDATE', {
        chatId: currentChatId,
        artifact_id: todo.id,
        main_content: todo.text,
        data_type: 'to_do',
        status: newStatus
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.TODO_STATUS_CHANGED,
        properties: {
          chatId: currentChatId,
          todoId: todo.id,
          oldStatus: todo.status,
          newStatus: newStatus
        }
      });
      // Refresh both sections after status change
      setTimeout(() => {
        postWindowMessage('CHAT_ARTIFACTS_FETCH', {
          chatId: currentChatId,
          data_type: "to_do",
          status: "pending",
          page: 1,
          page_size: 10
        });
        postWindowMessage('CHAT_ARTIFACTS_FETCH', {
          chatId: currentChatId,
          data_type: "to_do",
          status: "done",
          page: 1,
          page_size: 10
        });
      }, 100);
    } catch (error) {
      console.error('Failed to toggle todo status:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditTodo = (todo, section) => {
    setInputValue(todo.text);
    setEditingIndex(todo.id);
    setEditingSection(section);
  };

  const handleDeleteTodo = async (todo) => {
    if (!currentChatId) return;

    setIsLoading(true);

    try {
      postWindowMessage('CHAT_ARTIFACTS_DELETE', {
        chatId: currentChatId,
        artifact_id: todo.id,
        data_type: 'to_do'
      });
      postWindowMessage('TRACK_EVENT', {
        eventName: TRACK_EVENTS.TODO_DELETED,
        properties: { chatId: currentChatId, todoId: todo.id, status: todo.status }
      });
      if (todo.status === 'pending') {
        setPendingTotalCount(prev => Math.max(0, prev - 1));
      }
    } catch (error) {
      console.error('Failed to delete todo:', error);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  const renderTodoItem = (todo, section, index) => {
    // Custom title component with checkbox
    const TodoTitle = () => (
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', width: '100%' }}>
        <button
          className={`cq-chattodo-checkbox ${todo.status === 'done' ? 'cq-chattodo-checkbox-checked' : ''}`}
          onClick={(e) => {
            e.stopPropagation();
            handleToggleStatus(todo);
          }}
          disabled={isLoading}
          style={{
            flexShrink: 0
          }}
        >
          {todo.status === 'done' && icons.CHECK}
        </button>
        <span
          className={`selectable-text copyable-text ${todo.status === 'done' ? 'cq-chattodo-text-done' : ''}`}
          style={{
            flex: 1,
            textDecoration: todo.status === 'done' ? 'line-through' : 'none',
            opacity: todo.status === 'done' ? 0.6 : 1
          }}
        >
          {todo.text}
        </span>
      </div>
    );

    return (
      <ArtifactIconCard
        key={todo.id}
        index={index}
        isDark={isDark}
        title={<TodoTitle />}
        footerItems={[
          {
            text: todo.timestamp ? <RelativeTime timestamp={todo.timestamp} /> : 'Unknown',
          },
        ]}
        actions={[
          {
            icon: icons.EDIT,
            tooltip: 'Edit Todo',
            label: 'Edit',
            onClick: () => handleEditTodo(todo, section),
            disabled: isLoading,
          },
          {
            icon: icons.DELETE,
            tooltip: 'Delete Todo',
            label: 'Delete',
            onClick: () => {
              const confirmed = window.confirm('Are you sure you want to delete this todo?');
              if (confirmed) {
                handleDeleteTodo(todo);
              }
            },
            disabled: isLoading,
          },
        ]}
      />
    );
  };

  const renderCollapsibleSection = (title, isOpen, setIsOpen, todos, hasNextPage, isLoadingMore, loadMoreFunction) => (
    <div className="cq-chattodo-section">
      <div
        className="cq-chattodo-section-header"
        onClick={() => setIsOpen(!isOpen)}
        style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
      >
        <span>{title}</span>
        <span style={{ transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }}>
          {icons.DOWN_ARROW}
        </span>
      </div>
      {isOpen && (
        <>
          <div className="cq-chattodo-section-content">
            {todos.length > 0 ? (
              todos.map((todo, index) => renderTodoItem(todo, title.toLowerCase(), index))
            ) : (
              <div style={{ padding: '20px', textAlign: 'center', color: '#666' }}>
                {title === 'Pending' ? (
                  <>
                    <div className="cq-chattodo-empty-title">No todos yet</div>
                    <div className="cq-chattodo-empty-description">
                      Start adding todos to keep track of tasks for this chat.
                    </div>
                  </>
                ) : (
                  `No ${title.toLowerCase()} todos`
                )}
              </div>
            )}
          </div>
          {hasNextPage && todos.length > 0 && (
            <div style={{ textAlign: 'center', padding: '20px' }}>
              <button
                onClick={loadMoreFunction}
                disabled={isLoadingMore}
                style={{
                  padding: '10px 20px',
                  backgroundColor: '#25d366',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: isLoadingMore ? 'not-allowed' : 'pointer',
                  fontSize: '14px',
                  fontWeight: '500',
                  opacity: isLoadingMore ? 0.6 : 1
                }}
              >
                {isLoadingMore ? 'Loading...' : `Load More ${title}`}
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );

  return (
    <ErrorBoundary isDark={isDark}>
      <div className="cq-chattodo-popup" ref={popupRef} style={{ backgroundColor: isDark ? '#1f2c33' : '#f0f2f5' }}>
        {currentChatId ? (
          <>
            <div className="cq-chattodo-container" ref={containerRef}>
              {isLoading && pendingTodos.length === 0 && doneTodos.length === 0 ? (
                <div className="cq-chattodo-empty-state">
                  <div className="cq-chattodo-empty-icon">{icons.TODO}</div>
                  <div className="cq-chattodo-empty-title">Loading todos...</div>
                  <div className="cq-chattodo-empty-description">
                    Please wait while we load your todos.
                  </div>
                </div>
              ) : (
                <>
                  {renderCollapsibleSection(
                    'Pending',
                    isPendingOpen,
                    setIsPendingOpen,
                    pendingTodos,
                    pendingHasNextPage,
                    isPendingLoadingMore,
                    loadMorePendingTodos
                  )}

                  {renderCollapsibleSection(
                    'Done',
                    isDoneOpen,
                    setIsDoneOpen,
                    doneTodos,
                    doneHasNextPage,
                    isDoneLoadingMore,
                    loadMoreDoneTodos
                  )}
                </>
              )}
            </div>
            <div className="cq-chattodo-input-fixed">
              <div className="cq-chattodo-input">
                <div style={{ position: 'relative' }}>
                  <TextAreaBox
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Add a todo..."
                  />
                </div>
                <button
                  onClick={handleAddTodo}
                  className="cq-chattodo-button"
                  disabled={isLoading || inputValue.trim() === ''}
                >
                  {isLoading ? '...' : editingIndex !== null ? 'Update' : 'Add'}
                </button>
              </div>
            </div>
          </>
        ) : (
          <div className="cq-chattodo-container">
            <div className="cq-chattodo-empty-state">
              <div className="cq-chattodo-empty-icon">{icons.TODO}</div>
              <div className="cq-chattodo-empty-title">Select Chat</div>
              <div className="cq-chattodo-empty-description">
                Please select a chat to see the todos.
              </div>
            </div>
          </div>
        )}
      </div>
    </ErrorBoundary>
  );
};

export default ChatTodo;