import React, { useState } from 'react';
import ActivityDetails from './ActivityDetails';
import { icons } from '../../../../Constants/svg';


const ActivityTask = ({ activity, formatTime }) => {
    const [expanded, setExpanded] = useState(false);
    const isUpdate = activity.activity_type === 'task_updated';
    const showDesc = true; // Always show description as we handle "fields updated" display explicitly now

    return (
        <div className={`cq-feed-item ${activity.activity_type}`}>
            <div className="cq-feed-main">
                <div
                    className="cq-feed-header"
                    onClick={() => isUpdate && setExpanded(!expanded)}
                    style={{
                        cursor: isUpdate ? 'pointer' : 'default',
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center'
                    }}
                >
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-title">
                            {activity.title}
                        </span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-time">{formatTime(activity.timestamp)}</span>
                    </div>
                </div>

                {isUpdate && activity.description && (
                    <div
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '4px',
                            cursor: isUpdate ? 'pointer' : 'default',
                            marginTop: '0px',
                            marginBottom: '4px'
                        }}
                        onClick={(e) => {
                            if (isUpdate) {
                                e.stopPropagation();
                                setExpanded(!expanded);
                            }
                        }}
                    >
                        {isUpdate ? (
                            <div className="cq-feed-desc"
                                style={{ marginTop: '0', marginBottom: '0', color: '#667781', fontSize: '13px' }}
                                dangerouslySetInnerHTML={{ __html: activity.description }} />
                        ) : (
                            <div className="cq-feed-desc" style={{ marginTop: '0', marginBottom: '0', color: '#667781', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                                <span style={{ fontWeight: '500' }}>
                                    {(() => {
                                        const typeDetail = Array.isArray(activity.details)
                                            ? activity.details.find(d => d.label === 'Task Type')
                                            : null;
                                        return typeDetail ? (typeDetail.to_value || typeDetail.new_value) : 'Task';
                                    })()}
                                </span>

                                {(() => {
                                    const dueDetail = Array.isArray(activity.details)
                                        ? activity.details.find(d => d.label === 'Due At')
                                        : null;
                                    const dueVal = dueDetail ? (dueDetail.to_value || dueDetail.new_value) : null;

                                    if (dueVal) {
                                        return (
                                            <>
                                                <span style={{ color: '#ccc' }}>@</span>
                                                <span style={{ color: '#1f2a37' }}>{formatTime(dueVal)}</span>
                                            </>
                                        );
                                    }
                                    return null;
                                })()}
                            </div>
                        )}

                        {isUpdate && (
                            <span
                                style={{
                                    transition: 'transform 0.2s',
                                    transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    marginTop: '2px'
                                }}
                            >
                                {icons.DROPDOWN_CHEVRON}
                            </span>
                        )}
                    </div>
                )}

                {(expanded || !isUpdate) && (
                    <div className="cq-feed-content">

                        {!isUpdate && (
                            <div className="cq-feed-desc" style={{ marginTop: '0', marginBottom: '0', color: '#667781', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                                <span style={{ fontWeight: '500' }}>
                                    {(() => {
                                        const typeDetail = Array.isArray(activity.details)
                                            ? activity.details.find(d => d.label === 'Task Type')
                                            : null;
                                        return typeDetail ? (typeDetail.to_value || typeDetail.new_value) : 'Task';
                                    })()}
                                </span>

                                {(() => {
                                    const dueDetail = Array.isArray(activity.details)
                                        ? activity.details.find(d => d.label === 'Due At')
                                        : null;
                                    const dueVal = dueDetail ? (dueDetail.to_value || dueDetail.new_value) : null;

                                    if (dueVal) {
                                        return (
                                            <>
                                                <span style={{ color: '#ccc' }}>@</span>
                                                <span style={{ color: '#1f2a37' }}>{formatTime(dueVal)}</span>
                                            </>
                                        );
                                    }
                                    return null;
                                })()}
                            </div>
                        )}

                        {isUpdate && (
                            <ActivityDetails details={activity.details} hideOldValue={!isUpdate} />
                        )}

                        {activity.actor && (
                            <div className="cq-feed-actor">by {activity.actor.name}</div>
                        )}
                    </div>
                )}


            </div>
        </div >
    );
};

export default ActivityTask;
