import React from 'react';
import ActivityDetails from './ActivityDetails';

const ActivityNote = ({ activity, formatTime }) => {
    return (
        <div className="cq-feed-item note_created">
            <div className="cq-feed-main">
                <div className="cq-feed-header">
                    <span className="cq-feed-title">{activity.title}</span>
                    <span className="cq-feed-time">{formatTime(activity.timestamp)}</span>
                </div>
                <div className="cq-feed-desc" dangerouslySetInnerHTML={{ __html: activity.description }} />

                <ActivityDetails details={activity.details} hideOldValue={true} hideLabel={true} useExpandable={true} />

                {activity.actor && (
                    <div className="cq-feed-actor">by {activity.actor.name}</div>
                )}
            </div>
        </div>
    );
};

export default ActivityNote;
