import React, { useState, useRef, useEffect } from 'react';
import ArtifactIconCard from '../UIComponents/ArtifactIconCard';
import { icons } from '../../Constants/svg';
import InputBox from '../UIComponents/InputBox';
import NoteForm from '../UIComponents/Forms/NoteForm';
import TaskForm from '../UIComponents/Forms/TaskForm';
import { postWindowMessage } from '../../utils/messageSender';
import './LeadCard.css';



const getRelativeTime = (dateString) => {
    if (!dateString) return '';
    try {
        const date = new Date(dateString);
        const now = new Date();
        const diffInSeconds = Math.floor((now - date) / 1000);

        if (diffInSeconds < 60) return 'Just now';
        if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
        if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
        return `${Math.floor(diffInSeconds / 86400)}d ago`;
    } catch (e) {
        return '';
    }
};

const LeadCard = ({
    lead,
    allStages = [],
    onUpdate,
    onDelete,
    onClick,
    isDark,
    index,
    style
}) => {
    const [interactionMode, setInteractionMode] = useState(null); // null, 'note', 'task'
    const [isStageDropdownOpen, setIsStageDropdownOpen] = useState(false);
    const dropdownRef = useRef(null);

    // Form States

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
                setIsStageDropdownOpen(false);
            }
        };

        if (isStageDropdownOpen) {
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isStageDropdownOpen]);

    const handleStageSelect = (stageObj) => {
        onUpdate(lead.id, {
            pipeline: stageObj.name,
            stageId: stageObj.id,
            probability: stageObj.probability ? `${stageObj.probability}%` : undefined
        });
        setIsStageDropdownOpen(false);
    };

    const toggleMode = (mode) => {
        setInteractionMode(prev => prev === mode ? null : mode);
    };


    const handleCreateTask = (taskData) => {
        console.log('Creating task for lead', lead.id, taskData);
        // Call API/Parent
        setInteractionMode(null);
    };

    // Derived Display Values
    const currency = lead.currencyType ? `${lead.currencyType} ` : 'INR';
    const valueDisplay = `${currency}${lead.expectedValue || '0'}`;
    const nextTask = lead.nextTask ? `• ${lead.nextTask} (${lead.nextTaskDate})` : `• No tasks scheduled`;
    const descriptionText = `${valueDisplay} ${nextTask}`;

    // Mock probability for demonstration if not present
    const probability = lead.stageProbability || '';

    return (
        <div
            className="lead-card-container"
            onClick={onClick}
            style={{ cursor: 'pointer' }}
        >
            <ArtifactIconCard
                index={index}
                isDark={isDark}
                title={lead.title}
                descriptionNode={
                    <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
                        {descriptionText}
                    </div>
                }
                style={{
                    backgroundColor: lead.stageColor ? `${lead.stageColor}1A` : undefined,
                    borderLeft: lead.stageColor ? `3px solid ${lead.stageColor}` : undefined,
                    position: 'relative',
                    zIndex: isStageDropdownOpen ? 10 : 2, // Ensure card is above drawer (z-index 0)
                    marginBottom: 0, // Remove margin to connect with drawer
                    ...style
                }}
                actions={[
                    {
                        icon: icons.NOTE,
                        tooltip: "New Note",
                        // Label removed to save space
                        onClick: (e) => { e.stopPropagation(); toggleMode('note'); },
                        isActive: interactionMode === 'note'
                    },
                    {
                        icon: icons.TODO,
                        tooltip: "New Task",
                        // Label removed to save space
                        onClick: (e) => { e.stopPropagation(); toggleMode('task'); }
                    }
                ]}
                footer={
                    <div className="lead-card-footer">
                        {/* Left: Stage Switcher */}
                        <div
                            className="stage-switcher"
                            onClick={(e) => { e.stopPropagation(); setIsStageDropdownOpen(!isStageDropdownOpen); }}
                            ref={dropdownRef}
                        >
                            <span>{lead.stage} {probability ? `(${probability}%)` : ''}</span>
                            <span style={{ display: 'flex', alignItems: 'center' }}>{icons.DROPDOWN_CHEVRON}</span>

                            {isStageDropdownOpen && (
                                <div className="stage-dropdown">
                                    {allStages.map((stage, idx) => (
                                        <div
                                            key={idx}
                                            className={`stage-option ${lead.stage === stage.name ? 'selected' : ''}`}
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                handleStageSelect(stage);
                                            }}
                                        >
                                            {stage.name || stage.label}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        {/* Right: Last Touch */}
                        <div style={{ color: 'var(--text-tertiary)', fontStyle: 'italic' }}>
                            {lead.lastTouch ? "Last Touch: " + getRelativeTime(lead.lastTouch) : 'No activity'}
                        </div>
                    </div>
                }
            />

            {/* Form Drawer - Coming from behind */}
            <div
                className={`lead-form-drawer ${interactionMode ? 'open' : ''}`}
                style={{ backgroundColor: lead.stageColor ? `${lead.stageColor}0D` : undefined }}
                onClick={(e) => e.stopPropagation()}
            >
                {interactionMode === 'note' && (
                    <div style={{ paddingBottom: '12px' }}>
                        <div className="lead-form-header" style={{ marginBottom: '8px' }}>Add Note</div>
                        <NoteForm
                            onSave={(text) => {
                                postWindowMessage('LEAD_NOTE_CREATE', {
                                    lead_id: lead.id,
                                    content: text
                                });
                                // Optimistic or parent update if needed, currently just closing
                                setInteractionMode(null);
                            }}
                            onCancel={() => setInteractionMode(null)}
                            autoFocus
                        />
                    </div>
                )}

                {interactionMode === 'task' && (
                    <div style={{ paddingBottom: '12px' }}>
                        <div className="lead-form-header" style={{ marginBottom: '8px' }}>New Task</div>
                        <TaskForm
                            onSave={handleCreateTask}
                            onCancel={() => setInteractionMode(null)}
                        />
                    </div>
                )}
            </div>
        </div>
    );
};

export default LeadCard;
