import React, { useState, useEffect } from 'react';
import TaskForm from '../../UIComponents/Forms/TaskForm';
import { icons } from '../../../Constants/svg';
import './LeadTasks.css';
import { postWindowMessage } from '../../../utils/messageSender';
import { useToast } from '../../UIComponents/Toast/ToastManager';
import ExpandableText from '../../UIComponents/ExpandableText';
import ConfirmationModal from '../../UIComponents/ConfirmationModal';



const LeadTasks = ({ leadId }) => {
    const [tasks, setTasks] = useState([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);
    const [completedTasks, setCompletedTasks] = useState([]);
    const [completedPage, setCompletedPage] = useState(1);
    const [hasMoreCompleted, setHasMoreCompleted] = useState(true);
    const [showCompleted, setShowCompleted] = useState(false);
    const [loadingCompleted, setLoadingCompleted] = useState(false);
    const [deleteModalOpen, setDeleteModalOpen] = useState(false);
    const [taskToDelete, setTaskToDelete] = useState(null);
    const [editingTask, setEditingTask] = useState(null);
    const { addToast } = useToast();

    const tasksRef = React.useRef(tasks);
    const completedTasksRef = React.useRef(completedTasks);

    useEffect(() => {
        tasksRef.current = tasks;
        completedTasksRef.current = completedTasks;
    }, [tasks, completedTasks]);

    useEffect(() => {
        const handleMessage = (event) => {
            if (event.source !== window) return;
            const { type, payload } = event.data;

            if (type === 'LEAD_TASK_CREATE_SUCCESS') {
                const newLeadId = payload.lead_id || payload.leadId;
                if (String(newLeadId) !== String(leadId)) return;

                const newId = payload.id || payload.task?.id || Date.now();

                // Deduplicate
                if (tasksRef.current.some(t => String(t.id) === String(newId))) return;

                const newTask = {
                    id: newId,
                    type: payload.task_type || 'TODO',
                    description: payload.title || payload.description,
                    date: payload.due_at || payload.date,
                    reminder_at: payload.reminder_at,
                    meta: payload.meta || {},
                    is_completed: false
                };
                setTasks(prev => [newTask, ...prev]);
                addToast({ message: 'Task created successfully', type: 'success', duration: 3000 });
            } else if (type === 'LEAD_TASK_CREATE_ERROR') {
                console.error('Error creating task:', payload.error);
                addToast({ message: 'Failed to create task', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_TASK_LIST_SUCCESS') {
                const apiTasks = payload.results || [];
                const formattedTasks = apiTasks.map(task => ({
                    id: task.id,
                    type: task.task_type || 'TODO',
                    description: task.title,
                    original_description: task.description,
                    date: task.due_at,
                    reminder_at: task.reminder_at,
                    meta: task.meta || {},
                    is_completed: task.is_completed
                }));

                if (!payload.previous) {
                    setTasks(formattedTasks);
                } else {
                    setTasks(prev => {
                        const existingIds = new Set(prev.map(t => String(t.id)));
                        const uniqueNew = formattedTasks.filter(t => !existingIds.has(String(t.id)));
                        return [...prev, ...uniqueNew];
                    });
                }

                setHasMore(!!payload.next);
                setLoading(false);
            } else if (type === 'LEAD_TASK_LIST_ERROR') {
                setLoading(false);
                addToast({ message: 'Failed to fetch tasks', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_COMPLETED_TASK_LIST_SUCCESS') {
                const apiTasks = payload.results || [];
                const formattedTasks = apiTasks.map(task => ({
                    id: task.id,
                    type: task.task_type || 'TODO',
                    description: task.title,
                    original_description: task.description,
                    date: task.due_at,
                    reminder_at: task.reminder_at,
                    meta: task.meta || {},
                    is_completed: true
                }));

                if (!payload.previous) {
                    setCompletedTasks(formattedTasks);
                } else {
                    setCompletedTasks(prev => {
                        const existingIds = new Set(prev.map(t => String(t.id)));
                        const uniqueNew = formattedTasks.filter(t => !existingIds.has(String(t.id)));
                        return [...prev, ...uniqueNew];
                    });
                }

                setHasMoreCompleted(!!payload.next);
                setLoadingCompleted(false);
            } else if (type === 'LEAD_COMPLETED_TASK_LIST_ERROR') {
                setLoadingCompleted(false);
                addToast({ message: 'Failed to fetch completed tasks', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_TASK_UPDATE_SUCCESS') {
                const updatedTaskId = payload.id;

                const isCompleted = payload.is_completed !== undefined ? payload.is_completed : payload.data?.is_completed;

                const currentTasks = tasksRef.current;
                const currentCompletedTasks = completedTasksRef.current;

                let originalTask = currentTasks.find(t => String(t.id) === String(updatedTaskId)) || currentCompletedTasks.find(t => String(t.id) === String(updatedTaskId));

                if (!originalTask && (payload.title || payload.description)) {
                    originalTask = {
                        id: updatedTaskId,
                        description: payload.title,
                        date: payload.due_at,
                        reminder_at: payload.reminder_at,
                        meta: payload.meta || {},
                        type: payload.task_type || 'TODO'
                    };
                }

                if (!originalTask) {
                    console.error('Could not find original task to update in local state', updatedTaskId);
                    return;
                }

                const updatedTask = {
                    ...originalTask,
                    description: payload.title || originalTask.description,
                    date: payload.due_at || originalTask.date,
                    reminder_at: payload.reminder_at !== undefined ? payload.reminder_at : originalTask.reminder_at,
                    meta: payload.meta || originalTask.meta,
                    type: payload.task_type || originalTask.type
                };

                const newIsCompleted = isCompleted !== undefined ? isCompleted : originalTask.is_completed;
                const statusChanged = newIsCompleted !== originalTask.is_completed;

                if (statusChanged) {
                    if (newIsCompleted) {
                        setTasks(prev => prev.filter(t => String(t.id) !== String(updatedTaskId)));
                        setCompletedTasks(prev => {
                            if (prev.some(t => String(t.id) === String(updatedTaskId))) return prev;
                            return [{ ...updatedTask, is_completed: true, status: 'completed' }, ...prev];
                        });
                        if (payload.initiator === 'side-panel') {
                            addToast({ message: 'Task marked as completed', type: 'success', duration: 3000 });
                        }
                    } else {
                        setCompletedTasks(prev => prev.filter(t => String(t.id) !== String(updatedTaskId)));
                        setTasks(prev => {
                            if (prev.some(t => String(t.id) === String(updatedTaskId))) return prev;
                            return [{ ...updatedTask, is_completed: false, status: 'pending' }, ...prev];
                        });
                        if (payload.initiator === 'side-panel') {
                            addToast({ message: 'Task marked as pending', type: 'success', duration: 3000 });
                        }
                    }
                } else {
                    if (updatedTask.is_completed) {
                        setCompletedTasks(prev => prev.map(t => String(t.id) === String(updatedTaskId) ? { ...updatedTask, is_completed: true } : t));
                    } else {
                        setTasks(prev => prev.map(t => String(t.id) === String(updatedTaskId) ? { ...updatedTask, is_completed: false } : t));
                    }
                    if (!statusChanged && payload.initiator === 'side-panel') {
                        addToast({ message: 'Task updated successfully', type: 'success', duration: 3000 });
                    }
                }
            } else if (type === 'LEAD_TASK_UPDATE_ERROR') {
                addToast({ message: 'Failed to update task', type: 'error', duration: 3000 });
            } else if (type === 'LEAD_TASK_DELETE_SUCCESS') {
                const deletedTaskId = payload.taskId;

                setTasks(prev => prev.filter(t => String(t.id) !== String(deletedTaskId)));
                setCompletedTasks(prev => prev.filter(t => String(t.id) !== String(deletedTaskId)));

                addToast({ message: 'Task deleted successfully', type: 'success', duration: 3000 });
            } else if (type === 'LEAD_TASK_DELETE_ERROR') {
                addToast({ message: 'Failed to delete task', type: 'error', duration: 3000 });
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [addToast]);

    // Reset when lead changes
    useEffect(() => {
        if (leadId) {
            setPage(1);
            setTasks([]);
            setHasMore(true);
            setLoading(true);
            postWindowMessage('LEAD_TASK_LIST', { leadId, page: 1 });

            // Reset completed tasks
            setCompletedPage(1);
            setCompletedTasks([]);
            setHasMoreCompleted(true);
            setShowCompleted(false);
            // Don't fetch completed until expanded
        }
    }, [leadId]);

    useEffect(() => {
        if (leadId && page > 1) {
            setLoading(true);
            postWindowMessage('LEAD_TASK_LIST', { leadId, page });
        }
    }, [leadId, page]);

    useEffect(() => {
        if (leadId && showCompleted && (completedTasks.length === 0 || completedPage > 1)) {
            if (completedPage === 1 && completedTasks.length > 0) return;

            setLoadingCompleted(true);
            postWindowMessage('LEAD_COMPLETED_TASK_LIST', { leadId, page: completedPage });
        }
    }, [leadId, showCompleted, completedPage]);

    const handleScroll = (e) => {
        const { scrollTop, clientHeight, scrollHeight } = e.target;
        if (scrollHeight - scrollTop <= clientHeight + 50 && !loading && hasMore) {
            setPage(prev => prev + 1);
        }
    };

    const handleCompletedScroll = (e) => {
        const { scrollTop, clientHeight, scrollHeight } = e.target;
        if (scrollHeight - scrollTop <= clientHeight + 50 && !loadingCompleted && hasMoreCompleted) {
            setCompletedPage(prev => prev + 1);
        }
    };


    const prepareTaskPayload = (taskData) => {
        // Calculate reminder_at
        let reminderAt = null;
        if (taskData.reminderEnabled && taskData.reminderValue && taskData.date) {
            const dueDate = new Date(taskData.date);
            const value = parseInt(taskData.reminderValue, 10);
            let multiplier = 0;

            switch (taskData.reminderUnit) {
                case 'minutes': multiplier = 60 * 1000; break;
                case 'hours': multiplier = 60 * 60 * 1000; break;
                case 'days': multiplier = 24 * 60 * 60 * 1000; break;
                case 'weeks': multiplier = 7 * 24 * 60 * 60 * 1000; break;
                default: multiplier = 60 * 1000;
            }

            reminderAt = new Date(dueDate.getTime() - (value * multiplier)).toISOString();
        }

        let payload = {
            lead_id: leadId,
            task_type: taskData.type ? taskData.type.toUpperCase() : 'TODO',
            title: taskData.description,
            description: "",
            due_at: new Date(taskData.date).toISOString(),
            reminder_at: reminderAt,
            meta: taskData.reminderEnabled ? {
                interval_type: taskData.reminderUnit,
                interval_value: parseInt(taskData.reminderValue, 10)
            } : {}
        };

        // Remove keys with null or empty string values, BUT preserve explicit nulls for updates
        const cleanObj = (obj) => {
            Object.keys(obj).forEach(key => {
                if (obj[key] && typeof obj[key] === 'object') {
                    cleanObj(obj[key]);
                    if (Object.keys(obj[key]).length === 0) delete obj[key];
                } else if (obj[key] === "" || obj[key] === undefined) {
                    // Only delete empty strings or undefined. Keep nulls.
                    delete obj[key];
                }
            });
        };

        cleanObj(payload);
        return payload;
    };

    const handleCreateNew = async (taskData) => {
        try {
            const payload = prepareTaskPayload(taskData);
            postWindowMessage('LEAD_TASK_CREATE', payload);
        } catch (error) {
            console.error('Error initiating task creation:', error);
            addToast({ message: 'Failed to initiate task creation', type: 'error', duration: 3000 });
        }
    };

    const handleUpdateCurrent = async (taskData) => {
        try {
            if (!editingTask) return;
            const payload = prepareTaskPayload(taskData);
            const changedData = {};

            // Compare fields
            if (payload.title !== editingTask.description) changedData.title = payload.title;

            if (new Date(payload.due_at).getTime() !== new Date(editingTask.date).getTime()) {
                changedData.due_at = payload.due_at;
            }

            if (payload.task_type !== editingTask.type?.toUpperCase()) {
                changedData.task_type = payload.task_type;
            }

            if (payload.reminder_at !== editingTask.reminder_at) {
                changedData.reminder_at = payload.reminder_at;
            }

            // Deep compare meta
            const newMeta = payload.meta || {};
            const oldMeta = editingTask.meta || {};
            if (newMeta.interval_type !== oldMeta.interval_type ||
                newMeta.interval_value !== oldMeta.interval_value) {
                changedData.meta = newMeta;
            }

            if (Object.keys(changedData).length > 0) {
                postWindowMessage('LEAD_TASK_UPDATE', {
                    leadId,
                    taskId: editingTask.id,
                    payload: changedData,
                    initiator: 'side-panel'
                });
            }

            setEditingTask(null);

        } catch (error) {
            console.error('Error initiating task update:', error);
            addToast({ message: 'Failed to update task', type: 'error', duration: 3000 });
        }
    };

    const handleEdit = (task) => {
        console.log('Edit task:', task);

        let dateStr = '';
        if (task.date) {
            const dateObj = new Date(task.date);
            // Quick hack for local datetime string yyyy-MM-ddThh:mm
            const offset = dateObj.getTimezoneOffset() * 60000;
            dateStr = (new Date(dateObj - offset)).toISOString().slice(0, 16);
        }

        // Normalize type to match TaskForm options: ['Call', 'Email', 'Meeting', 'To-Do']
        let type = 'Call';
        if (task.type) {
            const lower = task.type.toLowerCase();
            if (lower === 'call') type = 'Call';
            else if (lower === 'email') type = 'Email';
            else if (lower === 'meeting') type = 'Meeting';
            else if (lower === 'todo' || lower === 'to-do') type = 'To-Do';
            else type = task.type.charAt(0).toUpperCase() + task.type.slice(1).toLowerCase();
        }

        const formInitialData = {
            type: type,
            date: dateStr,
            description: task.description,
            reminderEnabled: !!task.reminder_at,
            reminderValue: task.meta?.interval_value || (task.meta?.interval_type === 'minutes' ? '10' : '1'),
            reminderUnit: task.meta?.interval_type || 'minutes'
        };

        setEditingTask({ ...task, formInitialData });
    };

    const handleCancelEdit = () => {
        setEditingTask(null);
    };
    const handleToggleComplete = (taskId, e) => {
        if (e) e.stopPropagation();
        console.log('Toggling task:', taskId);
        // Find task in either pending or completed list
        const task = tasks.find(t => t.id === taskId) || completedTasks.find(t => t.id === taskId);
        if (!task) {
            console.warn('Task not found for toggle:', taskId);
            return;
        }

        const newStatus = !task.is_completed;


        const payload = {
            is_completed: newStatus
        };

        postWindowMessage('LEAD_TASK_UPDATE', {
            leadId,
            taskId: task.id,
            payload,
            initiator: 'side-panel'
        });
    };



    const handleDelete = (task) => {
        setTaskToDelete(task);
        setDeleteModalOpen(true);
    };

    const confirmDelete = () => {
        if (!taskToDelete) return;

        postWindowMessage('LEAD_TASK_DELETE', {
            leadId,
            taskId: taskToDelete.id
        });
        setTaskToDelete(null);
    };

    const formatTaskDate = (dateStr) => {
        const date = new Date(dateStr);
        return date.toLocaleString([], {
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    const getTaskIcon = (type) => {
        switch (type) {
            case 'Call': return icons.PHONE;
            case 'Email': return icons.EMAIL;
            case 'Meeting': return icons.VIDEO;
            default: return icons.TODO;
        }
    };

    return (
        <div className="cq-lead-tasks">
            <div className="cq-task-creation-section">
                <TaskForm
                    onSave={handleCreateNew}
                    saveLabel="Create Task"
                />
            </div>

            <div className="cq-tasks-list" onScroll={handleScroll}>
                <div className="cq-section-header">Pending Tasks</div>
                {tasks.length === 0 && !loading ? (
                    <div className="cq-tasks-empty">No pending tasks.</div>
                ) : (
                    <>
                        {tasks.map(task => (
                            editingTask && editingTask.id === task.id ? (
                                <div key={task.id} className="cq-task-item editing">
                                    <TaskForm
                                        initialData={editingTask.formInitialData}
                                        onSave={handleUpdateCurrent}
                                        onCancel={handleCancelEdit}
                                        saveLabel="Update"
                                        className="cq-inline-task-form"
                                    />
                                </div>
                            ) : (
                                <div key={task.id} className={`cq-task-item ${task.is_completed ? 'completed' : 'pending'}`}>
                                    <div className="cq-task-checkbox" onClick={(e) => handleToggleComplete(task.id, e)}>
                                        {task.is_completed ? icons.CHECK_CIRCLE : <div className="cq-checkbox-custom" />}
                                    </div>
                                    <div className="cq-task-details">
                                        <div className="cq-task-top">
                                            <span className="cq-task-icon">{getTaskIcon(task.type)}</span>
                                            <span className="cq-task-type">{task.type}</span>
                                            <span className="cq-task-at">at</span>
                                            <span className="cq-task-date">{formatTaskDate(task.date)}</span>
                                        </div>
                                        <div className="cq-task-desc-row">
                                            <ExpandableText text={task.description} className="cq-task-desc" />
                                            <div className="cq-task-actions">
                                                <button className="cq-task-action-btn edit" onClick={(e) => { e.stopPropagation(); handleEdit(task); }} title="Edit">
                                                    {icons.EDIT}
                                                </button>
                                                <button className="cq-task-action-btn delete" onClick={(e) => { e.stopPropagation(); handleDelete(task); }} title="Delete">
                                                    {icons.DELETE}
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )
                        ))}
                        {loading && <div className="cq-tasks-loading">Loading tasks...</div>}
                    </>
                )}
            </div>

            {/* Completed Tasks Section */}
            <div className="cq-section-header"
                style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', marginTop: '16px', gap: '8px' }}
                onClick={() => setShowCompleted(!showCompleted)}
            >
                <span>Completed Tasks</span>
                <span style={{ fontSize: '10px' }}>{showCompleted ? '▼' : '▶'}</span>
            </div>

            {showCompleted && (
                <div className="cq-tasks-list completed-list" onScroll={handleCompletedScroll} style={{ maxHeight: '200px', overflowY: 'auto' }}>
                    {completedTasks.length === 0 && !loadingCompleted ? (
                        <div className="cq-tasks-empty">No completed tasks.</div>
                    ) : (
                        <>
                            {completedTasks.map(task => (
                                <div key={task.id} className="cq-task-item completed">
                                    <div className="cq-task-checkbox" onClick={(e) => handleToggleComplete(task.id, e)}>
                                        {icons.CHECK_CIRCLE}
                                    </div>
                                    <div className="cq-task-details">
                                        <div className="cq-task-top">
                                            <span className="cq-task-icon">{getTaskIcon(task.type)}</span>
                                            <span className="cq-task-type">{task.type}</span>
                                            <span className="cq-task-at">at</span>
                                            <span className="cq-task-date">{formatTaskDate(task.date)}</span>
                                        </div>
                                        <div className="cq-task-desc-row">
                                            <ExpandableText text={task.description} className="cq-task-desc" />
                                            {/* Actions for completed tasks? typically readonly or can delete/reopen */}
                                            <div className="cq-task-actions">
                                                <button className="cq-task-action-btn delete" onClick={(e) => { e.stopPropagation(); handleDelete(task); }} title="Delete">
                                                    {icons.DELETE}
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))}
                            {loadingCompleted && <div className="cq-tasks-loading">Loading...</div>}
                        </>
                    )}
                </div>
            )}

            <ConfirmationModal
                isOpen={deleteModalOpen}
                onClose={() => {
                    setDeleteModalOpen(false);
                    setTaskToDelete(null);
                }}
                onConfirm={confirmDelete}
                title="Delete Task"
                message="Are you sure you want to delete this task? This action cannot be undone."
                confirmText="Delete"
                confirmButtonStyle="danger"
            />
        </div>
    );
};

export default LeadTasks;
