import React, { useState, useRef, useEffect } from 'react';

const Select = ({ options, value, onChange, placeholder = "Select an option...", autoFocus = false }) => {
  const [isOpen, setIsOpen] = useState(autoFocus);
  const dropdownRef = useRef(null);

  useEffect(() => {
    // Inject CSS styles for select dropdown
    const styleId = 'cq-select-styles';
    let styleElement = document.getElementById(styleId);

    if (!styleElement) {
      styleElement = document.createElement('style');
      styleElement.id = styleId;
      document.head.appendChild(styleElement);
    }

    styleElement.textContent = `
      .cq-select-box {
        padding: 8px;
        color: #111b21;
        border: 1px solid #ccc;
        border-radius: 6px;
        background: #fff;
        cursor: pointer;
        font-size: 14px;
        display: flex;
        align-items: center;
        box-sizing: border-box;
        transition: background-color 0.2s ease, border-color 0.2s ease, color 0.2s ease;
      }

      body.dark .cq-select-box {
        border: 1px solid #313d45;
        background: #2a3942;
        color: #e9edef;
      }

      .cq-select-placeholder {
        color: #667781;
      }

      body.dark .cq-select-placeholder {
        color: #8696a0;
      }

      .cq-select-dropdown {
        position: absolute;
        width: 100%;
        top: 110%;
        left: 0;
        background: #fff;
        color: #111b21;
        border: 1px solid #ccc;
        border-radius: 6px;
        max-height: 200px;
        overflow-y: auto;
        margin-top: 4px;
        z-index: 10;
        transition: background-color 0.2s ease, border-color 0.2s ease, color 0.2s ease;
      }

      body.dark .cq-select-dropdown {
        background: #2a3942;
        color: #e9edef;
        border: 1px solid #313d45;
      }

      .cq-select-option {
        padding: 8px 10px;
        cursor: pointer;
        font-size: 14px;
        background: white;
        font-weight: normal;
        transition: background-color 0.2s ease;
      }

      .cq-select-option.selected {
        background: #f0faff;
        font-weight: bold;
      }

      body.dark .cq-select-option {
        background: #2a3942;
      }

      body.dark .cq-select-option.selected {
        background: #313d45;
      }

      .cq-select-option:hover {
        background: #f5f5f5;
      }

      body.dark .cq-select-option:hover {
        background: #3c4a54;
      }
    `;
  }, []);

  const toggleDropdown = () => setIsOpen(!isOpen);

  const handleOptionClick = (option) => {
    const val = (typeof option === 'object' && option !== null) ? option.value : option;
    onChange(val);
    setIsOpen(false);
  };

  const handleClickOutside = (event) => {
    if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
      setIsOpen(false);
    }
  };

  useEffect(() => {
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const getDisplayValue = () => {
    if (!value) return null;
    const selectedOption = options.find(opt => {
      const optVal = (typeof opt === 'object' && opt !== null) ? opt.value : opt;
      return optVal === value;
    });
    return selectedOption ? ((typeof selectedOption === 'object' && selectedOption !== null) ? selectedOption.label : selectedOption) : value;
  };

  const displayValue = getDisplayValue();

  const [searchTerm, setSearchTerm] = useState('');
  const searchInputRef = useRef(null);

  useEffect(() => {
    if (isOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isOpen]);

  const filteredOptions = options.filter(option => {
    const label = (typeof option === 'object' && option !== null) ? option.label : option;
    return String(label).toLowerCase().includes(searchTerm.toLowerCase());
  });

  return (
    <div ref={dropdownRef} style={{ position: 'relative', width: '100%' }}>
      {/* Display box */}
      <div
        onClick={toggleDropdown}
        className="cq-select-box"
      >
        {displayValue ? (
          <span>{displayValue}</span>
        ) : (
          <span className="cq-select-placeholder">{placeholder}</span>
        )}
      </div>

      {/* Dropdown menu */}
      {isOpen && (
        <div className="cq-select-dropdown">
          <div style={{ padding: '8px', borderBottom: '1px solid #e5e7eb' }}>
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Search..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onClick={(e) => e.stopPropagation()}
              style={{
                width: '100%',
                padding: '6px',
                borderRadius: '4px',
                border: '1px solid #d1d5db',
                fontSize: '13px',
                outline: 'none',
                boxSizing: 'border-box'
              }}
            />
          </div>
          <div style={{ maxHeight: '200px', overflowY: 'auto' }}>
            {filteredOptions.length > 0 ? (
              filteredOptions.map((option) => {
                const isObject = typeof option === 'object' && option !== null;
                const label = isObject ? option.label : option;
                const val = isObject ? option.value : option;
                return (
                  <div
                    key={val}
                    onClick={() => handleOptionClick(option)}
                    className={`cq-select-option ${val === value ? 'selected' : ''}`}
                  >
                    {label}
                  </div>
                );
              })
            ) : (
              <div style={{ padding: '8px 10px', fontSize: '13px', color: '#6b7280', fontStyle: 'italic' }}>
                No results found
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Select;
