import React, { useState } from 'react';
import ActivityDetails from './ActivityDetails';
import { icons } from '../../../../Constants/svg';

const ActivityContact = ({ activity, formatTime }) => {
    const [expanded, setExpanded] = useState(false);
    const isCreation = activity.activity_type.includes('create') ||
        activity.activity_type.includes('add') ||
        activity.activity_type.includes('remove') ||
        activity.activity_type.includes('delete') ||
        activity.title.toLowerCase().includes('created') ||
        activity.title.toLowerCase().includes('removed');

    return (
        <div className={`cq-feed-item ${activity.activity_type}`}>
            <div className="cq-feed-main">
                <div
                    className="cq-feed-header"
                    onClick={() => !isCreation && setExpanded(!expanded)}
                    style={{
                        cursor: isCreation ? 'default' : 'pointer',
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center'
                    }}
                >
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-title">{activity.title}</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="cq-feed-time">{formatTime(activity.timestamp)}</span>
                        {!isCreation && (
                            null // Removed header chevron for updates to use inline toggle
                        )}
                    </div>
                </div>

                {!isCreation && activity.description && (
                    <div
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '4px',
                            cursor: 'pointer',
                            marginTop: '0px',
                            marginBottom: '4px'
                        }}
                        onClick={(e) => {
                            e.stopPropagation();
                            setExpanded(!expanded);
                        }}
                    >
                        <div className="cq-feed-desc"
                            style={{ marginTop: '0', marginBottom: '0', color: '#667781', fontSize: '13px' }}
                            dangerouslySetInnerHTML={{ __html: activity.description }} />
                        <span
                            style={{
                                transition: 'transform 0.2s',
                                transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
                                display: 'flex',
                                alignItems: 'center',
                                marginTop: '2px'
                            }}
                        >
                            {icons.DROPDOWN_CHEVRON}
                        </span>
                    </div>
                )}

                {(expanded || isCreation) && (
                    <div className="cq-feed-content">
                        {isCreation && (
                            <div className="cq-feed-desc" dangerouslySetInnerHTML={{ __html: activity.description }} />
                        )}

                        {!isCreation && (
                            <ActivityDetails details={activity.details} hideOldValue={isCreation} />
                        )}
                    </div>
                )}

                {activity.actor && (
                    <div className="cq-feed-actor">by {activity.actor.name}</div>
                )}
            </div>
        </div>
    );
};

export default ActivityContact;
