import { injectAiButton } from './utils/injectAiButton';
import { onBoarding } from './utils/onBoarding';
import { getMyUserId, sendTextMessage, getMyProfileName, getUserTimezone, saveContactToPhone, getActiveChatMessages, getActiveChatId } from './utils/WppFunctions';
import { postWindowMessage } from './utils/messageSender';
import { showSuggestionPreview } from './utils/showSuggestionPreview';
import { showToastMessage } from './utils/showToastMessage';
import { mountSidebar } from './Components/Sidebar/Sidebar';
import { TRACK_EVENTS, EVENT_MAPPING, FAILED_EVENT_MAPPING } from './Constants/constant';
import { saveSummaryToStorage } from './utils/renderChatSummaryPanel';
import { mountOnboardingPopovers } from './Components/Popover/OnboardingPopovers';
import { mountDashboard } from './Components/Leads/DashboardInjector';


const InjectorService = () => {
  localStorage.removeItem('USER_AUTH_TOKEN');
  localStorage.removeItem('USER_AUTH_ID');
  localStorage.removeItem('IS_USER_ONBOARDED');
  localStorage.removeItem('IS_AUTHENTICATED');
  localStorage.removeItem('CQ_USER_NUMBER');
  localStorage.removeItem('CQ_STATIC_MESSAGES');
  localStorage.removeItem('CQ_USER_TRIAL_EXPIRY');
  localStorage.removeItem('CQ_WELCOME_GUIDE');

  // Remove all chat summaries from localStorage
  Object.keys(localStorage).forEach(key => {
    if (key.startsWith('summary_')) {
      localStorage.removeItem(key);
    }
  });
  localStorage.removeItem('CQ_QUICK_REPLIES');
  let isAuthenticationHandled = false;

  async function handleAuthentication() {
    if (isAuthenticationHandled) return;
    isAuthenticationHandled = true;
    try {
      const phoneNumber = await getMyUserId();
      localStorage.setItem('CQ_USER_NUMBER', phoneNumber);
      postWindowMessage('USER_LOGIN', { phoneNumber: phoneNumber });
      postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.SESSION_START });
      // Kick off chat data counts initialization (only once per install)
      setTimeout(() => {
        postWindowMessage('CHAT_DATA_COUNTS_INIT', {});
      }, 1500);
    } catch (error) {
      console.error('Failed to get user id:', error);
      throw new Error('Failed to get user id' + error.message);
    }
  }


  // Since we inject after WhatsApp is loaded (wf-loading check in content.js),
  // we can proceed directly.
  handleAuthentication();
  setTimeout(() => {
    mountSidebar();
    mountOnboardingPopovers();
    mountDashboard();
  }, 2000);

  document.addEventListener('click', () => {
    injectAiButton();
  });

  window.WPP.on('chat.active_chat', () => {
    injectAiButton();
  });

  window.addEventListener('message', async (event) => {
    if (event.source !== window) return;
    const { type, payload } = event.data;

    if (type === 'USER_LOGIN_FAIL') {
      try {
        const [wppNumber, userTimezone, profileName] = await Promise.all([
          getMyUserId(),
          getUserTimezone(),
          getMyProfileName()
        ]);

        const autoRegisterData = {
          name: profileName || wppNumber, // Use WPP number if name is empty
          number: wppNumber,
          meta: {
            wpp_number: wppNumber,
            timezone: userTimezone
          }
        };

        // Save CQ contact
        saveContactToPhone('919211225523@c.us', 'The Chat', 'Quotient').catch(console.warn);

        postWindowMessage('ONBOARDING_FORM_SUBMIT', autoRegisterData);
        postWindowMessage('TRACK_EVENT', { eventName: 'AUTO_REGISTER_TRIGGERED' });

        // Show welcome guide
        localStorage.setItem('CQ_WELCOME_GUIDE', 'true');
        window.postMessage({
          type: 'SHOW_ONBOARDING_POPOVER',
          step: 'CHAT_SELECT'
        }, '*');

        // Show Welcome Page logic
        onBoarding(null, false, true);

      } catch (error) {
        console.error('Auto registration failed:', error);
        // Fallback to manual onboarding if auto-reg fails
        onBoarding(null, false, true);
      }
    }
    // if (type === 'USER_CONFIG') {
    //   onBoarding(payload, true);
    // }
    if (type === 'USER_CONFIG_UPDATE') {
      showToastMessage({ message: payload.message });
    }
    if (type === 'AI_REPLY') {
      showSuggestionPreview(false, payload.data.ai_prompt, payload.data.prompt_id, payload.data.loggedUserID, false, EVENT_MAPPING[payload.type]);
      postWindowMessage('TRACK_EVENT', { eventName: EVENT_MAPPING[payload.type] });
    }
    if (type === 'AI_REPLY_ERROR') {
      showSuggestionPreview(false, 'Something went wrong. Please try after sometime.', null, null, true);
      postWindowMessage('TRACK_EVENT', { eventName: FAILED_EVENT_MAPPING[payload.type] });
    }
    // if (type === 'CQ_ICON_URL' && payload.iconUrl) {
    //   chatQuotientIconUrl = payload.iconUrl;
    //   injectSidebarButton(payload.iconUrl);
    // }
    if (type === 'CHAT_SUMMARY') {
      // The new ChatSummarizer component handles this automatically
      // Just save to localStorage for the new system to pick up
      if (payload.summary) {
        saveSummaryToStorage(payload.summary);
      }
    }
    if (type === 'CHAT_SUMMARY_ERROR') {
      console.error('Chat summary generation failed:', payload);
      // The new ChatSummarizer component will handle error states
    }

    if (type === 'DELIVER_SCHEDULED_MESSAGE') {
      try {
        console.log(`Delivering scheduled message:`, payload);

        if (!payload.message || !payload.chatId) {
          throw new Error('Missing message or chatId in payload');
        }

        await sendTextMessage(payload.message, payload.chatId);
        postWindowMessage('SCHEDULED_MESSAGE_DELIVERED', payload);
        console.log(`Scheduled message delivered to chat: ${payload.chatId}`);
      } catch (error) {
        console.error('Failed to deliver scheduled message:', error);
        payload.status = 'failed';
        payload.failureReason = error.message || 'Unknown error';
        postWindowMessage('SCHEDULED_MESSAGE_FAILED', payload);
      }
    }

    if (type === 'TRIGGER_LEAD_SUGGESTION') {
      try {
        const messages = await getActiveChatMessages(50);
        const chatId = await getActiveChatId();

        const enrichedPayload = {
          ...payload,
          whatsapp_chat_id: messages.chatId || chatId,
          chat: messages.chat
        };

        postWindowMessage('LEAD_SUGGESTION_PAYLOAD_READY', enrichedPayload);
      } catch (error) {
        console.error('Error fetching chat messages for suggestion:', error);
        postWindowMessage('LEAD_SUGGESTION_ERROR', { error: error.message });
      }
    }
  });
};

const setupInjectorService = () => {
  try {
    if (window.WPP.conn.isMainReady()) {
      InjectorService();
      console.log('Service initialized successfully.');
    } else {
      setTimeout(setupInjectorService, 1000);
      console.log('Service is not ready. Retrying.');
    }// Retry after 5 seconds
  } catch (error) {
    console.error('Error initializing Service:', error);
    setTimeout(setupInjectorService, 1000); // Retry after 5 seconds
  }
};

setupInjectorService();

let hasRequestedDbDeletion = false;

// Periodically check WhatsApp auth status using WPP and request IndexedDB deletion on logout
const startAuthWatcher = () => {
  const check = async () => {
    try {
      const isAuth = await window.WPP?.conn?.isAuthenticated?.();
      if (!isAuth && !hasRequestedDbDeletion) {
        hasRequestedDbDeletion = true;
        const userId = localStorage.getItem('USER_AUTH_ID') || undefined;
        postWindowMessage('DELETE_INDEXED_DB', { loggedUserId: userId });
      }
    } catch (_) { }
  };
  // Check every 30 seconds
  setInterval(check, 30000);
  // Also run an immediate check
  check();
};

// Start auth watcher
startAuthWatcher();
