import React, { useState, useEffect } from 'react';
import { Skeleton, Box, Flex, Text, Button as RadixButton } from '@radix-ui/themes';
import { icons } from '../../Constants/svg.js';
import RephraseForm from '../../Components/RephraseForm/RephraseForm.js';
import { TRACK_EVENTS } from '../../Constants/constant.js';
import { postWindowMessage } from '../../utils/messageSender.js';
import { isDarkMode } from '../../utils/utils.js';

const PreviewBox = ({ text, onReload, onCancel, onInsert, loading, requestId, onSend }) => {
  const isDark = isDarkMode();
  const [showRephraseForm, setShowRephraseForm] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState(null);
  const [feedbackLoading, setFeedbackLoading] = useState(false);

  // Handle feedback API responses
  useEffect(() => {
    const handleFeedbackResponse = (event) => {
      if (event.origin !== window.location.origin) return;

      const { type, payload } = event.data;

      if (type === 'FEEDBACK_SUCCESS') {
        setFeedbackLoading(false);
      } else if (type === 'FEEDBACK_ERROR') {
        setFeedbackLoading(false);
        // Reset feedback state so user can retry
        setFeedbackGiven(null);
      }
    };

    window.addEventListener('message', handleFeedbackResponse);
    return () => window.removeEventListener('message', handleFeedbackResponse);
  }, []);

  const handleRehraseForm = (isOpened, isFormSubmitted = false) => {
    if (isOpened) {
      postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.ADVANCE_REPHRASE_FORM_OPENED });
      setShowRephraseForm(true);
    }
    else {
      if (isFormSubmitted) postWindowMessage('TRACK_EVENT', { eventName: TRACK_EVENTS.ADVANCE_REPHRASE_FORM_CANCELLED });
      setShowRephraseForm(false);
    }
  };

  const handleFeedback = async (isPositive) => {
    if (!requestId || feedbackLoading) return;

    const eventName = isPositive ? TRACK_EVENTS.AI_REPLY_FEEDBACK_POSITIVE : TRACK_EVENTS.AI_REPLY_FEEDBACK_NEGATIVE;
    const feedbackType = isPositive ? 'positive' : 'negative';

    // Track event for analytics
    postWindowMessage('TRACK_EVENT', { eventName });

    // Set loading state
    setFeedbackLoading(true);

    try {
      // Submit feedback to API
      postWindowMessage('SUBMIT_FEEDBACK', {
        messageId: requestId,
        feedback_type: feedbackType
      });

      // Update local state
      setFeedbackGiven(feedbackType);
    } catch (error) {
      console.error('Failed to submit feedback:', error);
      // Don't update feedbackGiven state on error so user can retry
    } finally {
      setFeedbackLoading(false);
    }
  };

  const baseBg = isDark ? '#103529' : '#e7f7f3';
  const hoverBg = isDark ? '#145c46' : '#d2f2ea';

  return (
    <Box
      id="ai-suggestion-preview"
      style={{
        position: 'relative',
        margin: '8px 70px',
        padding: '12px 16px 8px 16px',
        backgroundColor: baseBg,
        borderRadius: '10px',
        boxShadow: '0 2px 6px rgba(0,0,0,0.08)',
        maxWidth: 'calc(100% - 140px)',
        cursor: loading ? 'default' : 'pointer',
        transition: 'background 0.2s ease',
      }}
      onClick={!loading && !showRephraseForm ? onInsert : undefined}
      onMouseEnter={(e) => {
        if (!loading) e.currentTarget.style.backgroundColor = hoverBg;
      }}
      onMouseLeave={(e) => {
        if (!loading) e.currentTarget.style.backgroundColor = baseBg;
      }}
    >
      <Skeleton loading={loading}>
        <Flex justify="between" align="center" gap="12">
          <Box flex="1">
            <Text as="div" size="2">
              <span id="suggestion-text">{text}</span>
            </Text>
            <Text as="div" size="1" color="gray" style={{ fontStyle: 'italic', fontSize: '10px', marginTop: '4px' }}>
              Click to insert this message
            </Text>
          </Box>
          {/* Action buttons */}
          <Flex style={{ gap: '2px' }} justify="end" align="center">
            <RadixButton
              size="1"
              variant="ghost"
              color="indigo"
              title="Regenerate AI Response"
              onClick={(e) => {
                e.stopPropagation();
                onReload();
              }}
            >
              {icons.RELOAD}
            </RadixButton>
            <RadixButton
              size="1"
              variant="ghost"
              color="gray"
              title="Discard it"
              onClick={(e) => {
                e.stopPropagation();
                onCancel();
              }}
            >
              {icons.CROSS_CIRCLED}
            </RadixButton>
            <RadixButton
              size="1"
              variant="solid"
              title="Rephrase"
              style={{
                fontSize: '11px',
                padding: '5px 8px',
                borderRadius: '4px',
                fontWeight: 700,
                textTransform: 'uppercase',
                margin: '0 5px',

                backgroundColor: isDark ? '#6B6B6B' : '#E0E0E0',
                color: isDark ? '#FFFFFF' : '#444444',
                border: isDark ? '1px solid #7A7A7A' : '1px solid #DDD',
              }}
              onClick={(e) => {
                e.stopPropagation();
                handleRehraseForm(true);
              }}
            >
              REPHRASE
            </RadixButton>
            <RadixButton
              size="1"
              variant="ghost"
              style={{
                backgroundColor: '#10B981', // Emerald 500
                borderRadius: '50%',
                width: '30px',
                height: '30px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                padding: 0,
                color: isDark ? 'black' : 'white',
                cursor: 'pointer'
              }}
              title="Send"
              onClick={async (e) => {
                e.stopPropagation();
                await onSend();
              }}
            >
              {icons.SEND}
            </RadixButton>
          </Flex>
        </Flex>
      </Skeleton>

      {/* Render RephraseForm if opened */}
      {showRephraseForm && (
        <>
          <div
            style={{
              position: 'fixed',
              top: 0,
              left: 0,
              width: '100vw',
              height: '100vh',
              backgroundColor: 'transparent',
              zIndex: 9998,
            }}
            onClick={() => handleRehraseForm(false)}
          />
          <div
            id="cq-rephrase-form"
            style={{
              position: 'absolute',
              bottom: '100%',
              right: '0',
              marginBottom: '8px',
              zIndex: 9999,
            }}
          >
            <RephraseForm aiPrompt={text} onCancel={() => handleRehraseForm(false, false)} />
          </div>
        </>
      )}
    </Box>
  );
};

export default PreviewBox;
