import React from 'react';
import Tooltip from '../Tooltip';
import './Stepper.css';

// Helper for color opacity
const hexToRgba = (hex, alpha) => {
    if (!hex) return '';
    let r = 0, g = 0, b = 0;
    // 3 digits
    if (hex.length === 4) {
        r = parseInt(hex[1] + hex[1], 16);
        g = parseInt(hex[2] + hex[2], 16);
        b = parseInt(hex[3] + hex[3], 16);
    }
    // 6 digits
    else if (hex.length === 7) {
        r = parseInt(hex.substring(1, 3), 16);
        g = parseInt(hex.substring(3, 5), 16);
        b = parseInt(hex.substring(5, 7), 16);
    }
    return `rgba(${r},${g},${b},${alpha})`;
};

const Stepper = ({
    title,
    steps = [],
    activeStep,
    stepData = {}, // { stepId: { tooltip: '...', ... } }
    onStepChange,
    className = ''
}) => {

    // Helper to determine index of current step
    const activeStepIndex = steps.findIndex(s => s.id === activeStep);

    const handleStepClick = (stepId) => {
        if (onStepChange) {
            onStepChange(stepId);
        }
    };

    if (!steps || steps.length === 0) return null;

    return (
        <div className={`cq-stepper ${className}`}>
            {title && <div className="cq-stepper-title" style={{ fontSize: '11px', color: '#6b7280', marginBottom: '8px', fontWeight: 500 }}>{title}</div>}
            <div className="cq-stepper-steps">
                {steps.map((step, index) => {
                    const stepId = step.id;
                    const stepName = step.name;

                    const data = stepData[stepId] || {};
                    const hasCompletionData = !!(data.timeSpent || data.completionDate);

                    const isCompleted = activeStepIndex > index || hasCompletionData;
                    const isActive = activeStep === stepId;

                    // Color Logic
                    const baseColor = step.color || '#d1d5db';
                    let stepStyle = {};

                    if (isActive || isCompleted) {
                        stepStyle = {
                            backgroundColor: baseColor,
                            color: '#ffffff'
                        };
                    } else {
                        // Future/Pending - 15% Opacity
                        stepStyle = {
                            backgroundColor: hexToRgba(baseColor, 0.15),
                            color: baseColor
                        };
                    }

                    // Enrichment of tooltip from stepData
                    let tooltipParts = [`Step: ${stepName}`];

                    if (step.probability !== undefined) {
                        tooltipParts.push(`Probability: ${step.probability}%`);
                    }
                    if (data.timeSpent) {
                        tooltipParts.push(`Time in Stage: ${data.timeSpent}`);
                    }
                    if (data.completionDate) {
                        tooltipParts.push(`Completed on: ${data.completionDate}`);
                    }
                    if (data.tooltip) {
                        tooltipParts.push(data.tooltip);
                    }

                    const tooltipContent = tooltipParts.join('\n');

                    return (
                        <Tooltip key={stepId} text={tooltipContent} position="top">
                            <div
                                className={`cq-stepper-step ${isActive ? 'active' : ''} ${isCompleted ? 'completed' : ''}`}
                                onClick={() => handleStepClick(stepId)}
                                style={stepStyle}
                            >
                                <span className="cq-step-label-text">
                                    {stepName}
                                </span>
                            </div>
                        </Tooltip>
                    );
                })}
            </div>
        </div>
    );
};

export default Stepper;
