import React, { useState, useEffect, useRef } from 'react';
import { Button } from '@radix-ui/themes';
import InputBox from '../UIComponents/InputBox';
import TextAreaBox from '../UIComponents/TextAreaBox';
import Select from '../UIComponents/Select';
import Checkbox from '../UIComponents/Checkbox';
import MultiSelectDropdown from '../UIComponents/MultiSelectDropdown';
import { getMyProfileName, getMyUserId, getUserTimezone, saveContactToPhone } from '../../utils/WppFunctions';
import { postWindowMessage } from '../../utils/messageSender';
import { getTrialDaysLeft, renderHtml, stripHtml, getStaticMessage } from '../../utils/utils';
import { INDUSTRY_OPTIONS, PROFESSION_OPTIONS, TONE_OPTIONS, TRACK_EVENTS } from '../../Constants/constant';


import './OnBoardingForm.css';

const OnBoardingForm = ({ OnboardingData, isUpdate = false, onCancel }) => {
  const [formData, setFormData] = useState({
    name: '',
    number: '',
    industry: '',
    profession: [],
    tone: [],
    'custom_instruction': '',
  });

  const [error, setError] = useState('');
  const formRef = useRef(null);

  useEffect(() => {
    formRef.current?.focus();
    const fetchData = async () => {
      const [name, number] = await Promise.all([getMyProfileName(), getMyUserId()]);
      const { trialExpiry, ...data } = OnboardingData || {};
      setFormData((prev) => ({
        ...prev,
        name: data.name || name || '',
        number: data.number || number || '',
        ...(data || {}),
      }));
    };
    fetchData();
  }, [OnboardingData]);

  const showPopover = () => {
    if (isUpdate) return;
    localStorage.setItem('CQ_WELCOME_GUIDE', 'true');
    window.postMessage({
      type: 'SHOW_ONBOARDING_POPOVER',
      step: 'CHAT_SELECT'
    }, '*');
  }

  const showTrialMessage = () => {
    const systemConfig = localStorage.getItem('CQ_SYSTEM_CONFIG');
    if (systemConfig) {
      const parsedConfig = JSON.parse(systemConfig);
      if (!parsedConfig?.config?.trial_expiry?.is_enabled) {
        return '';
      }
    }

    let trialMessage = '';
    if (OnboardingData?.trialExpiry) {
      const daysLeft = getTrialDaysLeft(OnboardingData.trialExpiry);
      if (daysLeft > 0) {
        trialMessage = getStaticMessage('MESSAGE_TRIAL_DAYS_COUNT').replace('#', daysLeft.toString());
      } else {
        trialMessage = getStaticMessage('MESSAGE_TRIAL_EXPIRED') || 'Your trial has expired.';
      }
      return stripHtml(trialMessage);
    }
  }

  const onboardingRegisterTop = () => {
    if (isUpdate) return '';
    return renderHtml(getStaticMessage('ONBOARDING_REGISTER_TOP') || '');
  }

  const onboardingRegisterBottom = () => {
    if (isUpdate) return '';
    return renderHtml(getStaticMessage('ONBOARDING_REGISTER_BOTTOM') || '');
  }

  const onboardingRegisterCTAText = () => {
    if (isUpdate) return 'Update';
    return stripHtml(getStaticMessage('ONBOARDING_REGISTER_CTA_TEXT') || 'Submit');
  }

  const closeOnBoardingForm = (isSubmitted = false) => {
    if (onCancel) {
      onCancel();
      return;
    }
    const onboarding = document.getElementById('cq-onboarding');
    if (onboarding) {
      onboarding.remove();
    }
    document.body.classList.remove('cq-body-class');

    const eventName = isUpdate ? TRACK_EVENTS.UPDATE_PROFILE_FORM_CANCELLED : TRACK_EVENTS.SIGN_UP_FORM_CANCELLED;
    showPopover();
    if (!isSubmitted) {
      postWindowMessage('TRACK_EVENT', { eventName: eventName });
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleToneToggle = (tone) => {
    setFormData((prev) => {
      const current = prev.tone || [];
      const updated = current.includes(tone)
        ? current.filter((t) => t !== tone)
        : [...current, tone];
      return { ...prev, tone: updated };
    });
  };

  const handleProfessionChange = (selected) => {
    setFormData((prev) => ({
      ...prev,
      profession: selected,
    }));
  };

  const handleIndustryChange = (selected) => {
    setFormData((prev) => ({
      ...prev,
      industry: selected,
    }));
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      setError('Please enter your name.');
      return;
    }

    // if (!formData.industry) {
    //   setError('Please select your industry.');
    //   return;
    // }

    // if (formData.profession.length === 0) {
    //   setError('Please select at least one profession.');
    //   return;
    // }

    // if (formData.tone.length === 0) {
    //   setError('Please select at least one tone.');
    //   return;
    // }

    // All required fields are filled correctly
    setError(''); // clear error

    if (!isUpdate) {
      const [wppNumber, UserTimezone] = await Promise.all([getMyUserId(), getUserTimezone()]);
      const meta = {
        wpp_number: wppNumber,
        timezone: UserTimezone
      }
      formData.meta = meta;
      // Save CQ contact to user's phone on first-time registration
      try {
        await saveContactToPhone('919211225523@c.us', 'The Chat', 'Quotient');
      } catch (e) {
        // Non-blocking: proceed even if saving contact fails
        console.warn('Failed to save CQ contact:', e);
      }
    }
    // const messageType = isUpdate ? 'UPDATE_USER_CONFIG' : 'ONBOARDING_FORM_SUBMIT';
    const messageType = 'UPDATE_USER_CONFIG';
    postWindowMessage(messageType, formData);
    showPopover();
    closeOnBoardingForm(true);
    const eventName = isUpdate ? TRACK_EVENTS.UPDATE_PROFILE_FORM_SUBMITTED : TRACK_EVENTS.SIGN_UP_FORM_SUBMITTED;
    postWindowMessage('TRACK_EVENT', { eventName: eventName });
  };

  return (
    <div className="cq-onboarding-container">
      <h2 className="cq-onboarding-title">
        {'Personalize Your AI Assistant'}
      </h2>

      {/* {ONBOARDING_REGISTER_TOP Message} */}
      {onboardingRegisterTop()}

      {showTrialMessage() && (
        <p className="cq-onboarding-trial-message">
          {showTrialMessage()}
        </p>
      )}

      <form ref={formRef} tabIndex={-1} onSubmit={handleSubmit} onKeyDown={handleKeyDown}>

        {/* Name */}
        <div className="cq-onboarding-field">
          <label htmlFor="name" className="cq-onboarding-label">
            Name (Required)
          </label>
          <InputBox
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder="Enter your name"
          />
        </div>

        {/* number */}
        <div className="cq-onboarding-field hide">
          <label htmlFor="number" className="cq-onboarding-label">
            Mobile Number
          </label>
          <InputBox
            name="number"
            value={formData.number}
            onChange={handleChange}
            placeholder="number"
            disabled
          />
        </div>

        {/* Industry */}
        <div className="cq-onboarding-field hide">
          <label htmlFor="industry" className="cq-onboarding-label">
            Industry
          </label>
          <Select
            options={INDUSTRY_OPTIONS}
            value={formData.industry}
            onChange={handleIndustryChange}
            placeholder="Select your industry"
          />
        </div>

        {/* Profession */}
        <div className="cq-onboarding-field hide">
          <label htmlFor="profession" className="cq-onboarding-label">
            Profession
          </label>
          <MultiSelectDropdown
            options={PROFESSION_OPTIONS}
            selectedOptions={formData.profession}
            onChange={handleProfessionChange}
            placeholder="Select your professions"
          />
        </div>

        {/* custom_instruction */}
        <div className="cq-onboarding-field">
          <label htmlFor="custom_instruction" className="cq-onboarding-label">
            Tell AI to behave like you (Optional, Recommended)
          </label>
          <TextAreaBox
            name="custom_instruction"
            value={formData['custom_instruction']}
            onChange={handleChange}
            placeholder="Be concise and structured. Assume I know the basics; avoid unnecessary explanations. Start with the recommendation, then brief reasoning..."
          />
        </div>

        {/* Tone */}
        <div className="cq-onboarding-field">
          <label className="cq-onboarding-label" style={{ marginBottom: '0.5rem' }}>
            AI Tone (Optional)
          </label>
          <div className="cq-onboarding-tone-container">
            {TONE_OPTIONS.map((tone) => (
              <Checkbox
                key={tone}
                id={`tone-${tone}`}
                label={tone}
                checked={formData.tone.includes(tone)}
                onChange={() => handleToneToggle(tone)}
              />
            ))}
          </div>
        </div>

        {/* Error */}
        {error && (
          <p className="cq-onboarding-error">
            {error}
          </p>
        )}

        {/* {ONBOARDING_REGISTER_BOTTOM Message} */}
        {onboardingRegisterBottom()}

        {/* Buttons */}
        <div className="cq-onboarding-buttons">
          <Button
            variant="solid"
            color="blue"
            size="3"
            type="submit"
            style={{ padding: '5px', borderRadius: '5px', cursor: 'pointer' }}
          >
            {onboardingRegisterCTAText()}
          </Button>
          <Button
            variant="solid"
            color="ghost"
            size="3"
            style={{ padding: '5px', borderRadius: '5px', cursor: 'pointer' }}
            onClick={() => closeOnBoardingForm()}
          >
            Later
          </Button>
        </div>

      </form>
    </div>
  );
};

export default OnBoardingForm;
