import React, { createContext, useState, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import Toast from './Toast';

// Context
const ToastContext = createContext(null);

// Global event target for non-React triggers
const toastEventTarget = new EventTarget();

export const showToast = (options) => {
    // Dispatch a custom event that the Manager listens to
    const event = new CustomEvent('show-toast', { detail: options });
    toastEventTarget.dispatchEvent(event);
};

export const ToastManager = ({ children }) => {
    const [toasts, setToasts] = useState([]);

    const addToast = useCallback((options) => {
        const id = Date.now().toString() + Math.random().toString(36).substr(2, 9);
        const newToast = { id, ...options };
        // Add to top of list (visual stack from bottom up? or top down? 
        // Request says "bottom right". Usually stack grows upwards or new ones appear at bottom.)
        // Let's have new ones appear at the bottom/top of the *stack* but since it's bottom-right, 
        // typically the newest is at the bottom or top depending on preference.
        // Let's prepend to array, and render regular order.
        setToasts(prev => [...prev, newToast]);
    }, []);

    const removeToast = useCallback((id) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    // Listen for global events
    useEffect(() => {
        const handler = (e) => {
            const options = e.detail;
            addToast(options);
        };
        toastEventTarget.addEventListener('show-toast', handler);
        return () => {
            toastEventTarget.removeEventListener('show-toast', handler);
        };
    }, [addToast]);

    return (
        <ToastContext.Provider value={{ addToast, removeToast }}>
            {children}
            {createPortal(
                <div
                    className="cq-toast-container"
                    style={{
                        position: 'fixed',
                        bottom: '24px',
                        right: '24px',
                        zIndex: 99999,
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '10px',
                        pointerEvents: 'none' // Allow clicks to pass through empty space
                    }}
                >
                    {toasts.map(toast => (
                        <Toast
                            key={toast.id}
                            {...toast}
                            onClose={removeToast}
                        />
                    ))}
                </div>,
                document.body
            )}
        </ToastContext.Provider>
    );
};

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error("useToast must be used within a ToastManager");
    }
    return context;
};
